import crypto from "node:crypto";
import type { NextRequest } from "next/server";
import { getServerSession } from "next-auth";

import { authOptions } from "../shared/infrastructure/auth";
import { prisma } from "../shared/infrastructure/db";
import { logger } from "../shared/infrastructure/logger";
import { redisClient } from "../shared/infrastructure/redis";
import { getIp, getUa } from "../shared/lib/request-context";

type Props = {
  req: NextRequest;
};

export async function createContext({ req }: Props) {
  const ip = getIp(req);
  const userAgent = getUa(req);
  const requestInfo = { ip, userAgent }; // NOTE: мб заменить на request-context.ts

  const authHeader = req.headers.get("authorization");
  if (typeof authHeader === "string" && authHeader.startsWith("Bearer ")) {
    const token = authHeader.split(" ")[1];
    if (token != null && token.startsWith("dxnx_")) {
      const hashedToken = crypto.createHash("sha256").update(token).digest("hex");

      const keyRecord = await prisma.apiKey.findUnique({
        include: { user: true },
        where: { hashedKey: hashedToken },
      });

      if (keyRecord?.revoked === false) {
        prisma.apiKey
          .update({
            data: { lastUsed: new Date() },
            where: { id: keyRecord.id },
          })
          .catch((error) =>
            logger.error({
              error:
                error instanceof Error ? { message: error.message, stack: error.stack } : error,
              keyId: keyRecord.id,
              msg: "Failed to update api key lastUsed",
            })
          );

        return {
          prisma,
          redis: redisClient,
          req,
          requestInfo,
          session: {
            expires: new Date(Date.now() + 1000 * 60 * 60 * 24).toISOString(),
            user: keyRecord.user,
          },
        };
      }
    }
  }

  const session = await getServerSession(authOptions);
  return {
    prisma,
    redis: redisClient,
    req,
    requestInfo,
    session,
  };
}

export type Context = Awaited<ReturnType<typeof createContext>>;

import { NotifyType, Status, Visibility } from "@prisma/client";
import { z } from "zod";

type ValidatePairType = { repoName?: string; repoOwner?: string };

const PaginationSchema = z.object({
  cursor: z.coerce.number().int().min(1).max(1_000_000).nullish(),
  limit: z.coerce.number().int().min(1).max(100).default(10),
  search: z.string().trim().max(1000).optional(),
});

export const RepoFilterSchema = PaginationSchema.extend({
  owner: z.string().trim().min(1).max(39).optional(),
  sortBy: z.enum(["name", "updatedAt", "createdAt"]).default("updatedAt"),
  sortOrder: z.enum(["asc", "desc"]).default("desc"),
  status: z.enum(Status).optional(),
  visibility: z.enum(Visibility).optional(),
});

export type RepoFiltersInput = z.infer<typeof RepoFilterSchema>;

const repoIdentityFields = {
  repoName: z.string().trim().min(1).max(255).optional(),
  repoOwner: z.string().trim().min(1).max(39).optional(),
};

const validateRepoPair = (data: ValidatePairType, ctx: z.RefinementCtx) => {
  if ((data.repoName == null) !== (data.repoOwner == null)) {
    const message = "repoName and repoOwner must be provided together";
    ctx.addIssue({ code: "custom", message, path: ["repoName"] });
    ctx.addIssue({ code: "custom", message, path: ["repoOwner"] });
  }
};

export const NotificationsFilterSchema = PaginationSchema.extend({
  ...repoIdentityFields,
  isRead: z.boolean().optional(),
  type: z.enum(NotifyType).optional(),
}).superRefine(validateRepoPair);

export type NotificationsFilterInput = z.infer<typeof NotificationsFilterSchema>;

export const NotificationsBulkFilterSchema = z
  .object({
    ...repoIdentityFields,
    search: z.string().trim().max(1000).optional(),
    type: z.enum(NotifyType).optional(),
  })
  .superRefine(validateRepoPair);

export type NotificationsBulkFilterInput = z.infer<typeof NotificationsBulkFilterSchema>;

export const OpenApiErrorResponses = {
  400: "Invalid request",
  401: "Authorization required",
  403: "Insufficient permissions",
  404: "Resource not found",
  409: "Resource conflict",
  422: "Data validation error",
  429: "Too many requests",
  500: "Internal server error",
  503: "Service temporarily unavailable",
} as const;

import "server-only";

import { cache } from "react";
import { headers } from "next/headers";
import { NextRequest } from "next/server";

import { TRPC_PREFIX } from "@/shared/constants/env.client";
import { IS_DEV } from "@/shared/constants/env.flags";

import { createContext } from "./context";
import { appRouter } from "./routers";
import { createCallerFactory } from "./trpc";

const caller = createCallerFactory(appRouter);

export const api = cache(async () => {
  const heads = new Headers(await headers());
  heads.set("x-trpc-source", "rsc");

  const protocol = IS_DEV ? "http" : "https";
  const host = heads.get("host") ?? "localhost:3000";

  const ctx = await createContext({
    req: new NextRequest(`${protocol}://${host}${TRPC_PREFIX}`, { headers: heads }),
  });

  return caller(ctx);
});

import type { UserRole } from "@prisma/client";
import { initTRPC, TRPCError } from "@trpc/server";
import { enhance } from "@zenstackhq/runtime";
import superjson from "superjson";
import type { OpenApiMeta } from "trpc-to-openapi";

import { IS_PROD } from "@/shared/constants/env.flags";

import type { DbClient } from "../shared/infrastructure/db";
import { logger } from "../shared/infrastructure/logger";
import { buildRequestStore, requestContext, resolveRequestId } from "../shared/lib/request-context";
import type { Context } from "./context";

const t = initTRPC
  .context<Context>()
  .meta<OpenApiMeta>()
  .create({
    errorFormatter({ ctx, error, shape }) {
      const publicErrors = [
        "BAD_REQUEST",
        "CONFLICT",
        "UNAUTHORIZED",
        "FORBIDDEN",
        "TOO_MANY_REQUESTS",
        "NOT_FOUND",
      ];

      const isPublicError = publicErrors.includes(error.code);

      return {
        ...shape,
        data: {
          ...shape.data,
          requestId: resolveRequestId(ctx?.req, requestContext.getStore()?.requestId),
          stack: IS_PROD ? undefined : error.stack,
          zodError: error.code === "BAD_REQUEST" ? error.cause : null,
        },
        message:
          IS_PROD && !isPublicError
            ? "An unexpected error occurred, please try again later."
            : error.message,
      };
    },
    transformer: superjson,
  });

const withZenStack = t.middleware(async ({ ctx, next }) => {
  const sessionUser = ctx.session?.user;
  const userId = sessionUser == null ? undefined : Number(sessionUser.id);

  const userRole = sessionUser?.role == null ? undefined : (sessionUser.role as UserRole);

  const protectedDb = enhance(ctx.prisma, {
    user: userId == null ? undefined : { id: userId, role: userRole },
  }) as unknown as DbClient;

  return next({
    ctx: {
      ...ctx,
      db: protectedDb,
    },
  });
});

const contextMiddleware = t.middleware(async ({ ctx, next, path, type }) => {
  const sessionUser = ctx.session?.user;

  const store = buildRequestStore({
    method: type,
    path,
    req: ctx.req,
    userId: sessionUser?.id == null ? undefined : Number(sessionUser.id),
    userRole: sessionUser?.role,
  });

  return requestContext.run(store, () => next({ ctx }));
});

const loggerMiddleware = t.middleware(async ({ next, path, type }) => {
  const start = performance.now();
  const result = await next();
  const durationMs = Number((performance.now() - start).toFixed(2));

  const meta = { durationMs, path, type };

  if (result.ok) {
    logger.info({ ...meta, msg: `tRPC [${type}] ok: ${path}` });
  } else {
    logger.error({
      ...meta,
      code: result.error.code,
      message: result.error.message,
      msg: `tRPC [${type}] error: ${path}`,
      stack: result.error.code === "INTERNAL_SERVER_ERROR" ? result.error.stack : undefined,
    });
    if (IS_PROD) {
      await logger.flush();
    }
  }
  return result;
});

export const createTRPCRouter = t.router;
export const createCallerFactory = t.createCallerFactory;
export const publicProcedure = t.procedure
  .use(contextMiddleware)
  .use(loggerMiddleware)
  .use(withZenStack);

const isAuthed = t.middleware(({ ctx, next }) => {
  if (ctx.session?.user == null) {
    throw new TRPCError({ code: "UNAUTHORIZED", message: "You are not logged in" });
  }

  return next({
    ctx: {
      session: { ...ctx.session, user: ctx.session.user },
    },
  });
});

export const protectedProcedure = publicProcedure.use(isAuthed);

const isAdmin = t.middleware(({ ctx, next }) => {
  if (ctx.session?.user.role !== "ADMIN") {
    throw new TRPCError({ code: "FORBIDDEN", message: "Admin rights required" });
  }

  return next({ ctx });
});

export const adminProcedure = protectedProcedure.use(isAdmin);

import { z } from "zod";

import { analyticsService } from "@/server/entities/analyze/api/analytics.service";
import { StatusSchema } from "@/generated/zod";

import { OpenApiErrorResponses } from "../contracts";
import { createTRPCRouter, protectedProcedure } from "../trpc";

const DashboardStatsOutputSchema = z.object({
  analysisStats: z.object({
    failed: z.number(),
    new: z.number(),
    pending: z.number(),
    success: z.number(),
    total: z.number(),
  }),
  highlights: z.object({
    mostCritical: z.object({ name: z.string(), score: z.number() }).nullable(),
    topPerformer: z.object({ name: z.string(), score: z.number() }).nullable(),
  }),
  languages: z.array(
    z.object({
      color: z.string(),
      name: z.string(),
      value: z.number(),
    })
  ),
  overview: z.object({
    avgScores: z.object({
      complexity: z.number(),
      health: z.number(),
      onboarding: z.number(),
      security: z.number(),
      techDebt: z.number(),
    }),
    complexityDelta: z.number(),
    criticalRepoCount: z.number(),
    docsCount: z.number(),
    healthDelta: z.number(),
    onboardingDelta: z.number(),
    repoCount: z.number(),
    securityDelta: z.number(),
    techDebtDelta: z.number(),
    totalLoc: z.number(),
  }),
  recentActivity: z.array(
    z.object({
      createdAt: z.date(),
      id: z.uuid(),
      progress: z.number(),
      repoName: z.string(),
      repoOwner: z.string(),
      status: StatusSchema,
    })
  ),
  risks: z.object({
    busFactorRepos: z.number(),
    topCoupling: z.array(
      z.object({
        commits: z.number(),
        from_path: z.string(),
        repo_name: z.string(),
        to_path: z.string(),
      })
    ),
    topHotspots: z.array(
      z.object({
        path: z.string(),
        repo_name: z.string(),
        score: z.number(),
      })
    ),
  }),
});

const TrendsOutputSchema = z.array(
  z.object({
    complexity: z.number(),
    date: z.string(),
    fullDate: z.string(),
    health: z.number(),
    onboarding: z.number(),
    security: z.number(),
    techDebt: z.number(),
  })
);

const InputSchema = z.object({
  from: z.date().optional(),
  period: z.string().optional().default("30d"),
  repoId: z.string().optional(),
  to: z.date().optional(),
});

export const analyticsRouter = createTRPCRouter({
  getDashboardStats: protectedProcedure
    .meta({
      openapi: {
        description: "Returns aggregated metrics, global scores, and language distribution.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/analytics",
        protect: true,
        summary: "Get rich dashboard statistics",
        tags: ["analytics"],
      },
    })
    .input(InputSchema)
    .output(DashboardStatsOutputSchema)
    .query(async ({ ctx, input }) => {
      return analyticsService.getDashboardStats(ctx.db, input, Number(ctx.session.user.id));
    }),

  getTrends: protectedProcedure
    .meta({
      openapi: {
        description:
          "Returns daily averages for security, health, and complexity scores over the last 30 days.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/analytics/trends",
        protect: true,
        summary: "Get 30-day analysis trends",
        tags: ["analytics"],
      },
    })
    .input(InputSchema)
    .output(TrendsOutputSchema)
    .query(async ({ ctx, input }) => {
      return analyticsService.getTrends(ctx.db, input, Number(ctx.session.user.id));
    }),
});

import { z } from "zod";

import { CreateApiKeySchema } from "@/shared/api/schemas/api-key";

import { apiKeyService } from "@/server/entities/api-key/api/api-key.service";
import { ApiKeySchema } from "@/generated/zod";

import { OpenApiErrorResponses } from "../contracts";
import { createTRPCRouter, protectedProcedure } from "../trpc";

export const apiKeyRouter = createTRPCRouter({
  create: protectedProcedure
    .meta({
      openapi: {
        description: "Generates a new API Key. The full key is shown only once.",
        errorResponses: OpenApiErrorResponses,
        method: "POST",
        path: "/api-keys",
        protect: true,
        summary: "Create API Key",
        tags: ["api-keys"],
      },
    })
    .input(CreateApiKeySchema)
    .output(z.object({ key: z.string(), message: z.string() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.create(ctx.db, Number(ctx.session.user.id), input);
    }),

  list: protectedProcedure
    .meta({
      openapi: {
        description: "Returns all active and revoked API keys for the current user.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/api-keys",
        protect: true,
        summary: "List API Keys",
        tags: ["api-keys"],
      },
    })
    .input(z.object({}).optional())
    .output(
      z.object({
        active: z.array(ApiKeySchema),
        archived: z.array(ApiKeySchema),
      })
    )
    .query(async ({ ctx }) => {
      return apiKeyService.list(ctx.db);
    }),

  revoke: protectedProcedure
    .meta({
      openapi: {
        description: "Permanently revokes an API key. It can no longer be used for authentication.",
        errorResponses: OpenApiErrorResponses,
        method: "DELETE",
        path: "/api-keys/{id}",
        protect: true,
        summary: "Revoke API Key",
        tags: ["api-keys"],
      },
    })
    .input(z.object({ id: z.uuid() }))
    .output(z.object({ message: z.string(), success: z.boolean() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.revoke(ctx.db, input.id);
    }),

  touch: protectedProcedure
    .meta({
      openapi: {
        description: "Updates the lastUsed timestamp for the specified API key.",
        errorResponses: OpenApiErrorResponses,
        method: "PATCH",
        path: "/api-keys/{id}/touch",
        protect: true,
        summary: "Touch API Key",
        tags: ["api-keys"],
      },
    })
    .input(z.object({ id: z.uuid() }))
    .output(z.object({ success: z.boolean() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.touch(ctx.db, input.id);
    }),

  update: protectedProcedure
    .meta({
      openapi: {
        description: "Updates the name or description of an existing API key.",
        errorResponses: OpenApiErrorResponses,
        method: "PATCH",
        path: "/api-keys/{id}",
        protect: true,
        summary: "Update API Key",
        tags: ["api-keys"],
      },
    })
    .input(CreateApiKeySchema.extend({ id: z.uuid() }))
    .output(z.object({ message: z.string(), success: z.boolean() }))
    .mutation(async ({ ctx, input }) => {
      return apiKeyService.update(ctx.db, input.id, input);
    }),
});

import { TRPCError } from "@trpc/server";
import { z } from "zod";

import { highlightCode } from "@/shared/lib/shiki";

import { mapAuditLogToDTO, sanitizeObject } from "@/server/entities/audit/lib/audit-mapper";
import { AUDIT_BUSINESS_MODELS } from "@/server/shared/lib/constants";

import { createTRPCRouter, protectedProcedure } from "../trpc";

export const auditRouter = createTRPCRouter({
  getActivityLogs: protectedProcedure
    .input(
      z.object({
        cursor: z.string().nullish(),
        limit: z.number().min(1).max(100).default(20),
      })
    )
    .query(async ({ ctx, input }) => {
      const { cursor, limit } = input;
      const userId = Number(ctx.session.user.id);

      const items = await ctx.db.auditLog.findMany({
        cursor: cursor != null ? { id: cursor } : undefined,
        orderBy: { createdAt: "desc" },
        take: limit + 1,
        where: {
          model: {
            in: AUDIT_BUSINESS_MODELS,
          },
          userId,
        },
      });

      let nextCursor: typeof cursor | undefined;
      if (items.length > limit) {
        const nextItem = items.pop();
        nextCursor = nextItem?.id;
      }

      return {
        items: items.map((item) => mapAuditLogToDTO(item)),
        nextCursor,
      };
    }),

  getLogPayloadHtml: protectedProcedure
    .input(z.object({ logId: z.string() }))
    .query(async ({ ctx, input }) => {
      const log = await ctx.db.auditLog.findUnique({
        select: { payload: true },
        where: { id: input.logId, userId: Number(ctx.session.user.id) },
      });

      if (log == null) throw new TRPCError({ code: "NOT_FOUND" });

      const cleanPayload = sanitizeObject(log.payload);

      const jsonString = JSON.stringify(cleanPayload, null, 2);

      return highlightCode(jsonString, "json", "dark", input.logId);
    }),
});

import { TRPCError } from "@trpc/server";
import { z } from "zod";

import { createTRPCRouter, protectedProcedure } from "@/server/api/trpc";
import { generatedFixService } from "@/server/entities/pr-analysis/api/generated-fix.service";
import { generateFixTask } from "@/server/features/generate-docs/task/generate-fix.task";
import { FixService } from "@/server/features/pr-analysis/lib/fix-generator";
import type { FindingForFix } from "@/server/features/pr-analysis/model/pr-types";
import { getClientContext } from "@/server/shared/infrastructure/github/github-provider";
import { logger } from "@/server/shared/infrastructure/logger";
import { REDIS_CONFIG } from "@/server/shared/lib/redis";
import { GeneratedFixSchema } from "@/generated/zod";

// ============================================================================
// VALIDATION SCHEMAS
// ============================================================================

const GeneratedFixDTO = GeneratedFixSchema.extend({ id: z.uuid() });

const FixResultSchema = z.object({
  error: z.string().optional(),
  explanation: z.string().optional(),
  fixedFiles: z
    .array(
      z.object({
        diff: z.string().optional(),
        filePath: z.string(),
        newContent: z.string(),
      })
    )
    .optional(),
});

const FindingForFixSchema = z.object({
  file: z.string().min(1),
  line: z.number().int().positive(),
  suggestion: z.string().optional(),
  type: z.enum(["architecture", "bug", "complexity", "performance", "security", "style"]),
});

const FixedFileContentSchema = z.object({
  filePath: z.string().min(1),
  newContent: z.string().min(1),
});

const FixApplicationPayloadSchema = z.object({
  branch: z.string().min(1),
  estimatedImpact: z.number().int().min(0).max(100),
  fixedFiles: z.array(FixedFileContentSchema).min(1),
  fixId: z.uuid(),
  repoId: z.uuid(),
  title: z.string().min(1),
});

const GeneratedFixDetailedDTO = GeneratedFixSchema.extend({
  id: z.uuid(),
  resultJson: FixResultSchema.nullable(),
});

export const generatedFixRouter = createTRPCRouter({
  /**
   * Apply fix to repository (create PR with full-content strategy).
   * Frontend sends back the fixed file contents that were generated.
   * No DB lookups of diffs - stateless.
   */
  applyFix: protectedProcedure
    .input(FixApplicationPayloadSchema)
    .output(
      z.object({
        error: z.string().optional(),
        prNumber: z.number().optional(),
        prUrl: z.string().optional(),
        success: z.boolean(),
      })
    )
    .mutation(async ({ ctx, input }) => {
      logger.info({
        fixId: input.fixId,
        msg: "fix_applying",
        userId: ctx.session.user.id,
      });

      try {
        // Fetch repo metadata (owner, name, defaultBranch)
        const repo = await ctx.db.repo.findUnique({
          where: { publicId: input.repoId },
        });

        if (repo == null) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "Repository not found",
          });
        }

        // Resolve GitHub client context (installation or OAuth)
        const clientContext = await getClientContext(
          ctx.db,
          Number(ctx.session.user.id),
          repo.owner
        );

        const fix = await generatedFixService.getById(ctx.db, input.fixId);

        if (fix == null) {
          throw new TRPCError({ code: "NOT_FOUND", message: "Fix not found" });
        }

        // Apply fix using full-content strategy
        const fixService = new FixService();
        const result = await fixService.applyFix(clientContext.octokit, {
          branch: input.branch,
          defaultBranch: repo.defaultBranch,
          fixedFiles: input.fixedFiles,
          fixId: fix.publicId,
          owner: repo.owner,
          repoId: repo.publicId,
          repoName: repo.name,
          title: input.title,
        });

        // Update fix status with PR metadata (no diffs stored)
        await generatedFixService.updateStatus(ctx.db, fix.publicId, "PR_OPENED", {
          githubPrNumber: result.prNumber,
          githubPrUrl: result.prUrl,
        });

        const cacheKey = REDIS_CONFIG.keys.prStaging(ctx.session.user.id, input.repoId);
        await ctx.redis.del(cacheKey);

        return {
          prNumber: result.prNumber,
          prUrl: result.prUrl,
          success: true,
        };
      } catch (error) {
        logger.error({
          error: error instanceof Error ? error.message : String(error),
          fixId: input.fixId,
          msg: "fix_apply_failed",
        });

        if (error instanceof TRPCError) {
          throw error;
        }

        return {
          error: error instanceof Error ? error.message : "Unknown error",
          success: false,
        };
      }
    }),

  /**
   * "Fix it for me" - Generate fix from findings (stateless full-content strategy).
   * Returns fixId + diffs for preview. Frontend sends fixed files back to applyFix.
   */
  createFix: protectedProcedure
    .input(
      z.object({
        fileContents: z.record(z.string(), z.string()), // Map of filePath -> originalContent
        findings: z.array(FindingForFixSchema).min(1),
        prAnalysisId: z.uuid().optional(),
        repoId: z.uuid(),
      })
    )
    .output(
      z.object({
        error: z.string().optional(),
        fixId: z.uuid().optional(),
        status: z.string().optional(),
        success: z.boolean().optional(),
      })
    )
    .mutation(async ({ ctx, input }) => {
      logger.info({
        findingsCount: input.findings.length,
        msg: "fix_creation_triggered",
        repoId: input.repoId,
        userId: ctx.session.user.id,
      });

      try {
        let validPrAnalysisId: string | undefined;

        if (input.prAnalysisId != null) {
          const prAnalysisRecord = await ctx.db.pullRequestAnalysis.findUnique({
            select: { publicId: true },
            where: { publicId: input.prAnalysisId },
          });

          if (prAnalysisRecord != null) {
            validPrAnalysisId = prAnalysisRecord.publicId;
          }
        }

        // Fetch repo metadata (to detect language)
        const repo = await ctx.db.repo.findUnique({
          where: { publicId: input.repoId },
        });

        if (repo == null) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "Repository not found",
          });
        }

        const fix = await generatedFixService.create(ctx.prisma, {
          branch: `doxynix/fix-${crypto.randomUUID().slice(0, 8)}`,
          createdByUser: true,
          prAnalysisId: validPrAnalysisId,
          repoId: repo.publicId,
          title: "AI Suggested Improvements",
        });

        await generateFixTask.trigger(
          {
            fileContents: input.fileContents,
            findings: input.findings as FindingForFix[],
            fixId: fix.publicId,
            prAnalysisId: validPrAnalysisId,
            repoId: repo.publicId,
            userId: Number(ctx.session.user.id),
          },
          {
            concurrencyKey: `repo-${repo.id}`,
            idempotencyKey: `fix-${fix.id}`,
            ttl: "30m",
          }
        );

        return {
          fixId: fix.publicId,
          status: "PENDING",
          success: true,
        };
      } catch (error) {
        logger.error({
          error: error instanceof Error ? error.message : String(error),
          msg: "fix_creation_failed",
          repoId: input.repoId,
        });

        return {
          error: error instanceof Error ? error.message : "Unknown error",
          success: false,
        };
      }
    }),

  /**
   * Get fix metadata (no diffs in response)
   */
  getById: protectedProcedure
    .input(z.object({ fixId: z.uuid() }))
    .output(GeneratedFixDetailedDTO)
    .query(async ({ ctx, input }) => {
      const fix = await generatedFixService.getById(ctx.db, input.fixId);

      if (fix == null) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Fix not found",
        });
      }

      const cachedResult = await ctx.redis.get(REDIS_CONFIG.keys.fixResult(input.fixId));
      const parsedResult = FixResultSchema.safeParse(cachedResult);

      return {
        ...fix,
        id: fix.publicId,
        resultJson: parsedResult.success ? parsedResult.data : null,
      };
    }),

  /**
   * Get all fixes for a repo (metadata only)
   */
  getByRepository: protectedProcedure
    .input(z.object({ repoId: z.uuid() }))
    .output(z.array(GeneratedFixDTO))
    .query(async ({ ctx, input }) => {
      const fixes = await generatedFixService.getByRepoId(ctx.db, input.repoId);
      return fixes.map((fix) => ({ ...fix, id: fix.publicId }));
    }),
});

