import { TRPCError } from "@trpc/server";
import { z } from "zod";

import { UpdateProfileSchema } from "@/shared/api/schemas/user";

import { userService } from "@/server/entities/user/api/user.service";
import { UserSchema } from "@/generated/zod";

import { OpenApiErrorResponses } from "../contracts";
import { createTRPCRouter, protectedProcedure } from "../trpc";

const PublicUserSchema = UserSchema.extend({
  id: z.uuid(),
});

export const userRouter = createTRPCRouter({
  deleteAccount: protectedProcedure
    .meta({
      openapi: {
        description: "Permanently deletes the current user account and all associated data.",
        errorResponses: OpenApiErrorResponses,
        method: "DELETE",
        path: "/users/me",
        protect: true,
        summary: "Delete account",
        tags: ["users"],
      },
    })
    .input(z.object({}).optional())
    .output(z.object({ message: z.string(), success: z.boolean() }))
    .mutation(async ({ ctx }) => {
      return userService.deleteAccount(ctx.db, ctx.prisma, Number(ctx.session.user.id));
    }),

  disconnectAccount: protectedProcedure
    .input(z.object({ provider: z.enum(["github", "google", "yandex"]) }))
    .mutation(async ({ ctx, input }) => {
      const userId = Number(ctx.session.user.id);

      await ctx.prisma.$transaction(
        async (tx) => {
          // Check if the account exists
          const accountToDelete = await tx.account.findUnique({
            where: {
              userId_provider: {
                provider: input.provider,
                userId,
              },
            },
          });

          if (accountToDelete == null) {
            throw new TRPCError({
              code: "NOT_FOUND",
              message: "Account not found or already disconnected.",
            });
          }

          // Re-validate account count and email auth within transaction
          const accountCount = await tx.account.count({
            where: { userId },
          });

          const user = await tx.user.findUnique({
            select: { email: true, emailVerified: true },
            where: { id: userId },
          });

          const hasEmailAuth = user?.email != null && user.emailVerified != null;

          if (accountCount <= 1 && !hasEmailAuth) {
            throw new TRPCError({
              code: "BAD_REQUEST",
              message:
                "You cannot disconnect your only authentication method. Add another one first.",
            });
          }

          // Perform the delete
          await tx.account.delete({
            where: {
              userId_provider: {
                provider: input.provider,
                userId,
              },
            },
          });
        },
        {
          isolationLevel: "Serializable",
        }
      );

      return { success: true };
    }),

  getLinkedAccounts: protectedProcedure.query(async ({ ctx }) => {
    const userId = Number(ctx.session.user.id);

    const [accounts, user] = await Promise.all([
      ctx.db.account.findMany({
        orderBy: { provider: "asc" },
        select: {
          email: true,
          image: true,
          name: true,
          provider: true,
          providerAccountId: true,
        },
        where: { userId },
      }),
      ctx.db.user.findUnique({
        select: { email: true, emailVerified: true },
        where: { id: userId },
      }),
    ]);

    return { accounts, user };
  }),

  me: protectedProcedure
    .meta({
      openapi: {
        description: "Returns detailed profile information for the currently authenticated user.",
        errorResponses: OpenApiErrorResponses,
        method: "GET",
        path: "/users/me",
        protect: true,
        summary: "Get current profile",
        tags: ["users"],
      },
    })
    .input(z.object({}).optional())
    .output(z.object({ message: z.string(), user: PublicUserSchema }))
    .query(async ({ ctx }) => {
      return userService.getMe(ctx.db, Number(ctx.session.user.id));
    }),

  removeAvatar: protectedProcedure
    .meta({
      openapi: {
        description: "Deletes the avatar image and remove from UT.",
        errorResponses: OpenApiErrorResponses,
        method: "DELETE",
        path: "/users/me/avatar",
        protect: true,
        summary: "Remove avatar",
        tags: ["users"],
      },
    })
    .input(z.object({}).optional())
    .output(z.object({ message: z.string(), success: z.boolean() }))
    .mutation(async ({ ctx }) => {
      return userService.removeAvatar(ctx.db, ctx.prisma, Number(ctx.session.user.id));
    }),

  updateUser: protectedProcedure
    .meta({
      openapi: {
        errorResponses: OpenApiErrorResponses,
        method: "PATCH",
        path: "/users/me",
        protect: true,
        summary: "Update user profile",
        tags: ["users"],
      },
    })
    .input(UpdateProfileSchema)
    .output(z.object({ message: z.string(), user: PublicUserSchema }))
    .mutation(async ({ ctx, input }) => {
      return userService.updateUser(ctx.db, Number(ctx.session.user.id), input);
    }),
});

import type { Status } from "@prisma/client";
import { getDashboardStats, getTrends } from "@prisma/client/sql";
import { subDays, subHours, subMinutes } from "date-fns";

import type { DbClient } from "@/server/shared/infrastructure/db";

type LanguageDto = {
  color: string;
  name: string;
  value: number;
};

type ExtremeRepoDto = {
  name: string;
  score: number;
};

type RecentActivityDto = {
  createdAt: Date;
  id: string;
  progress: number;
  repoName: string;
  repoOwner: string;
  status: Status;
};

type StatsInput = {
  from?: Date | null;
  period?: null | string;
  repoId?: string;
  to?: Date | null;
};

type HotspotDto = {
  path: string;
  repo_name: string;
  score: number;
};

type CouplingDto = {
  commits: number;
  from_path: string;
  repo_name: string;
  to_path: string;
};

type RisksDto = {
  busFactorRepos: number;
  topCoupling: CouplingDto[];
  topHotspots: HotspotDto[];
};

export const analyticsService = {
  calculatePeriodStart(period: string, relativeTo: Date): Date {
    switch (period) {
      case "15m": {
        return subMinutes(relativeTo, 15);
      }
      case "1h": {
        return subHours(relativeTo, 1);
      }
      case "24h": {
        return subDays(relativeTo, 1);
      }
      case "7d": {
        return subDays(relativeTo, 7);
      }
      case "90d": {
        return subDays(relativeTo, 90);
      }
      case "30d":
      default: {
        return subDays(relativeTo, 30);
      }
    }
  },

  async getDashboardStats(db: DbClient, input: StatsInput, userId: number) {
    const now = new Date();

    let currentStart: Date;
    let currentEnd: Date = input.to ?? now;

    if (input.period != null && input.period !== "custom") {
      currentEnd = now;
      currentStart = this.calculatePeriodStart(input.period, currentEnd);
    } else {
      currentStart = input.from ?? subDays(currentEnd, 30);
    }

    const durationMs = currentEnd.getTime() - currentStart.getTime();
    const previousStart = new Date(currentStart.getTime() - durationMs);

    const [data] = await db.$queryRawTyped(
      getDashboardStats(userId, currentStart, previousStart, currentEnd)
    );

    if (data == null) {
      return this.getEmptyDashboardStats();
    }

    const recentActivity = (data.recentActivity as unknown as RecentActivityDto[]).map(
      (activity): RecentActivityDto => ({
        createdAt: new Date(activity.createdAt),
        id: activity.id,
        progress: activity.progress,
        repoName: activity.repoName,
        repoOwner: activity.repoOwner,
        status: activity.status as Status,
      })
    );
    return {
      analysisStats: {
        failed: data.failedCount ?? 0,
        new: data.newCount ?? 0,
        pending: data.pendingCount ?? 0,
        success: data.successCount ?? 0,
        total: data.totalCount ?? 0,
      },
      highlights: {
        mostCritical: data.worstRepo as unknown as ExtremeRepoDto | null,
        topPerformer: data.bestRepo as unknown as ExtremeRepoDto | null,
      },
      languages: data.languages as unknown as LanguageDto[],
      overview: {
        avgScores: {
          complexity: Math.round(data.avgComplexity ?? 0),
          health: Math.round(data.avgHealth ?? 0),
          onboarding: Math.round(data.avgOnboarding ?? 0),
          security: Math.round(data.avgSecurity ?? 0),
          techDebt: Math.round(data.avgTechDebt ?? 0),
        },
        complexityDelta: data.complexityDelta ?? 0,
        criticalRepoCount: data.criticalRepoCount ?? 0,
        docsCount: data.docCount ?? 0,
        healthDelta: data.healthDelta ?? 0,
        onboardingDelta: data.onboardingDelta ?? 0,
        repoCount: data.repoCount ?? 0,
        securityDelta: data.securityDelta ?? 0,
        techDebtDelta: data.techDebtDelta ?? 0,
        totalLoc: data.totalLoc ?? 0,
      },
      recentActivity,
      risks: {
        busFactorRepos: data.busFactorRepos ?? 0,
        topCoupling: data.topCoupling as unknown as CouplingDto[],
        topHotspots: data.topHotspots as unknown as HotspotDto[],
      } satisfies RisksDto,
    };
  },

  getEmptyDashboardStats() {
    return {
      analysisStats: { failed: 0, new: 0, pending: 0, success: 0, total: 0 },
      highlights: { mostCritical: null, topPerformer: null },
      languages: [],
      overview: {
        avgScores: {
          complexity: 0,
          health: 0,
          onboarding: 0,
          security: 0,
          techDebt: 0,
        },
        complexityDelta: 0,
        criticalRepoCount: 0,
        docsCount: 0,
        healthDelta: 0,
        onboardingDelta: 0,
        repoCount: 0,
        securityDelta: 0,
        techDebtDelta: 0,
        totalLoc: 0,
      },
      recentActivity: [],
      risks: { busFactorRepos: 0, topCoupling: [], topHotspots: [] },
    };
  },

  async getTrends(db: DbClient, input: StatsInput, userId: number) {
    let startDate: Date;
    let endDate = input.to ?? new Date();

    if (input.period != null && input.period !== "custom") {
      endDate = new Date();
      startDate = this.calculatePeriodStart(input.period, endDate);
    } else {
      startDate = input.from ?? subDays(endDate, 30);
    }

    const trends = await db.$queryRawTyped(
      getTrends(userId, startDate, endDate, input.repoId ?? null)
    );

    const dateFormatter = new Intl.DateTimeFormat("en-US", {
      day: "numeric",
      month: "short",
      timeZone: "UTC",
    });

    return trends.map((t) => {
      const dateKey = t.dateKey ?? new Date();

      return {
        complexity: t.complexity ?? 0,
        date: dateFormatter.format(dateKey),
        fullDate: dateKey.toISOString().slice(0, 10),
        health: t.health ?? 0,
        onboarding: t.onboarding ?? 0,
        security: t.security ?? 0,
        techDebt: t.techDebt ?? 0,
      };
    });
  },
};

import type {
  LatestCompletedAnalysis,
  RepoWithLatestAnalysisAndDocs,
} from "@/server/shared/infrastructure/repo-snapshots";
import { getLanguageColor } from "@/server/shared/lib/language-metadata";
import { hasText } from "@/server/shared/lib/string-utils";

import type { createAnalyzeContextBuilder } from "../lib/analyze-context-builder";
import { buildStructureMapPayload, buildStructureNodePayload } from "../lib/graph-navigator";
import { buildNodeExplainPayload } from "../lib/node-explainer";
import {
  coerceAnalysisPayload,
  dedupeLatestDocsByType,
  normalizeWriterStatuses,
  toDocSummary,
} from "../lib/payload";
import { mapExplainBase, mapStructureNodeBase } from "../lib/repo-details-helpers";

export type ExplainPayload = NonNullable<
  ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getNodeExplain"]>
>;

export type StructureNodePayload = NonNullable<
  ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getStructureNode"]>
>;

export const repoDetailsPresenter = {
  toAvailableDocs(repo: Pick<RepoWithLatestAnalysisAndDocs, "analyses" | "documents">) {
    const latestAnalysis = coerceAnalysisPayload(repo.analyses[0]);
    return dedupeLatestDocsByType(repo.documents).map((doc) =>
      toDocSummary(doc, latestAnalysis?.aiResult ?? null)
    );
  },

  toBriefPanelInput(params: {
    explain: NonNullable<
      ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getNodeExplain"]>
    >;
    structureNode: NonNullable<
      ReturnType<ReturnType<typeof createAnalyzeContextBuilder>["getStructureNode"]>
    >;
  }) {
    return {
      explain: mapExplainBase(params.explain),
      structureNode: mapStructureNodeBase(params.structureNode),
    };
  },

  toDetailedMetrics(analysis: LatestCompletedAnalysis | null) {
    const payload = coerceAnalysisPayload(analysis);
    if (payload == null) return null;

    const { aiResult, metrics } = payload;
    const findings = aiResult.findings ?? [];
    const facts = aiResult.repository_facts ?? [];

    return {
      architecture: {
        analysisCoverage: metrics.analysisCoverage,
        configInventory: metrics.configInventory,
        dependencyCycles: metrics.dependencyCycles,
        dependencyHotspots: metrics.dependencyHotspots,
        entrypoints: metrics.entrypoints,
        graphReliability: metrics.graphReliability ?? null,
        hotspotFiles: metrics.hotspotFiles,
        hotspotSignals: metrics.hotspotSignals ?? [],
        orphanModules: metrics.orphanModules,
        routeInventory: metrics.routeInventory ?? null,
      },
      domain: {
        analysis: aiResult.domain_analysis ?? null,
      },
      onboarding: {
        guide: aiResult.onboarding_guide,
        score: metrics.onboardingScore,
        teamRoles: metrics.teamRoles,
      },
      quality: {
        analysisCoverage: metrics.analysisCoverage,
        busFactor: metrics.busFactor,
        complexity: metrics.complexityScore,
        dependencyCycles: metrics.dependencyCycles.length,
        docDensity: metrics.docDensity,
        duplicationReport: metrics.duplicationReport,
        health: metrics.healthScore,
        modularity: metrics.modularityIndex,
        security: metrics.securityScore,
        techDebt: metrics.techDebtScore,
      },
      recommendations: {
        bottlenecks: aiResult.mainBottlenecks ?? [],
        infrastructure: aiResult.sections.infrastructure_and_scaling,
        performanceAudit: aiResult.sections.performance_audit,
        refactoringTargets: aiResult.refactoring_targets,
        techDebtInventory: aiResult.sections.tech_debt_inventory,
      },
      reference: {
        apiStructure: aiResult.sections.api_structure,
        dataFlow: aiResult.sections.data_flow,
        swagger: aiResult.swaggerYaml ?? null,
      },
      risks: {
        facts,
        findings,
        hotspotFiles: metrics.hotspotFiles,
        topRisks: findings,
      },
      security: {
        findings: metrics.securityFindings,
        risks: aiResult.sections.security_audit.risks,
        score: aiResult.sections.security_audit.score,
        securityScanStatus: metrics.securityScanStatus,
        vulnerabilities: aiResult.vulnerabilities ?? [],
      },
    };
  },

  toInteractiveBriefNodePayloadInput(params: {
    explain: ExplainPayload;
    structureNode: StructureNodePayload;
  }) {
    return {
      explain: {
        analysisRef: params.explain.analysisRef ?? null,
        ...mapExplainBase(params.explain),
      },
      structureNode: {
        analysisRef: params.structureNode.analysisRef ?? null,
        ...mapStructureNodeBase(params.structureNode),
      },
    };
  },

  toNodeExplain(repo: RepoWithLatestAnalysisAndDocs, nodeId: string) {
    return buildNodeExplainPayload(repo, nodeId);
  },

  toOverview(repo: RepoWithLatestAnalysisAndDocs) {
    const payload = coerceAnalysisPayload(repo.analyses[0]);
    if (payload == null) return null;

    const { aiResult, metrics } = payload;
    const docs = this.toAvailableDocs(repo);

    return {
      docs: {
        availableCount: docs.length,
        availableTypes: docs.map((doc) => doc.type),
        hasSwagger: hasText(aiResult.swaggerYaml),
        items: docs,
        writers: normalizeWriterStatuses(aiResult),
      },
      domain: aiResult.domain_analysis ?? null,
      languages: metrics.languages,
      maintenance: metrics.maintenanceStatus,
      mostComplexFiles: metrics.mostComplexFiles,
      repo: {
        defaultBranch: repo.defaultBranch,
        description: repo.description,
        forks: repo.forks,
        id: repo.publicId,
        language: repo.language,
        languageColor: getLanguageColor(repo.language),
        license: repo.license,
        name: repo.name,
        openIssues: repo.openIssues,
        owner: repo.owner,
        ownerAvatarUrl: repo.ownerAvatarUrl,
        pushedAt: repo.pushedAt,
        size: repo.size,
        stars: repo.stars,
        topics: repo.topics,
        url: repo.url,
        visibility: repo.visibility,
      },
      scores: {
        complexity: metrics.complexityScore,
        health: metrics.healthScore,
        onboarding: metrics.onboardingScore,
        security: metrics.securityScore,
        techDebt: metrics.techDebtScore,
      },
      signals: {
        analysisCoverage: metrics.analysisCoverage,
        apiSurface: metrics.apiSurface,
        busFactor: metrics.busFactor,
        dependencyCycles: metrics.dependencyCycles.length,
        docDensity: metrics.docDensity,
        duplicationPercentage: metrics.duplicationReport.duplicationPercentage,
      },
      stats: {
        configFiles: metrics.configFiles,
        fileCount: metrics.fileCount,
        linesOfCode: metrics.totalLoc,
        totalSizeKb: metrics.totalSizeKb,
        totalSizeLabel: `${metrics.totalSizeKb} KB`,
