export async function loadRepoOrThrow(db: DbClient, repoId: string, aid?: string) {
  const repo = await getRepoWithLatestAnalysisAndDocs(db, repoId, aid);
  if (repo == null)
    throw new TRPCError({ code: "NOT_FOUND", message: "Repository or Analysis version not found" });
  return repo;
}

export async function loadAnalyzeContextBuilderOrThrow(db: DbClient, repoId: string, aid?: string) {
  return createAnalyzeContextBuilder(await loadRepoOrThrow(db, repoId, aid));
}

export function mapExplainBase(explain: ExplainPayload) {
  return {
    confidence: explain.confidence,
    nextSuggestedPaths: explain.nextSuggestedPaths,
    relationships: explain.relationships,
    role: explain.role,
    sourcePaths: explain.sourcePaths,
    summary: explain.summary,
    whyImportant: explain.whyImportant,
  };
}

export function mapStructureNodeBase(structureNode: StructureNodePayload) {
  return {
    breadcrumbs: structureNode.breadcrumbs.map((item) => ({
      id: item.id,
      label: item.label,
      path: item.path,
    })),
    canDrillDeeper: structureNode.canDrillDeeper,
    children: structureNode.children,
    edges: structureNode.edges,
    inspect: structureNode.inspect,
    node: structureNode.node,
  };
}

export async function loadLatestDocumentsWithContent(db: DbClient, repoId: string, aid?: string) {
  const docs = await db.document.findMany({
    orderBy: { updatedAt: "desc" },
    select: {
      analysis: { select: { publicId: true } },
      content: true,
      publicId: true,
      type: true,
      updatedAt: true,
      version: true,
    },
    where: {
      repo: { publicId: repoId },
      ...(aid != null ? { analysis: { publicId: aid } } : {}),
    },
  });

  return pickLatestDocsByType(docs);
}

export async function loadRelatedDocSections(
  db: DbClient,
  repoId: string,
  nodeId: string,
  nodeLabel: string,
  relatedFiles: string[],
  analyzeContext: ReturnType<typeof createAnalyzeContextBuilder>
) {
  const docs = await loadLatestDocumentsWithContent(db, repoId);
  const graph = analyzeContext.getStructureMap()?.graph ?? null;
  const fileTerms = relatedFiles.flatMap((path) => {
    const fileName = basename(path);
    return [fileName.toLowerCase(), path.toLowerCase()];
  });

  return docs
    .flatMap((doc) => {
      const formatted = DocumentFormatter.withGraphLinks(doc.content, graph, doc.type, doc.version);

      return formatted.sections
        .filter((section) => {
          const lowerTitle = section.title.toLowerCase();
          const lowerContent = section.content.toLowerCase();

          return (
            section.graphNodeIds.includes(nodeId) ||
            lowerTitle.includes(nodeLabel.toLowerCase()) ||
            fileTerms.some((term) => lowerTitle.includes(term) || lowerContent.includes(term))
          );
        })
        .slice(0, 4)
        .map((section) => ({
          docId: doc.publicId,
          docType: doc.type,
          id: section.id,
          title: section.title,
        }));
    })
    .slice(0, 8);
}

export async function loadRelatedPrFindings(db: DbClient, repoId: string, relatedFiles: string[]) {
  if (relatedFiles.length === 0) return [];

  const comments = await db.pullRequestComment.findMany({
    orderBy: [{ analysis: { createdAt: "desc" } }, { riskLevel: "desc" }],
    select: {
      analysis: {
        select: {
          prNumber: true,
          publicId: true,
        },
      },
      body: true,
      filePath: true,
      findingType: true,
      line: true,
      publicId: true,
      riskLevel: true,
    },
    take: 12,
    where: {
      analysis: { repo: { publicId: repoId } },
      filePath: { in: relatedFiles },
    },
  });

  return comments.map((comment) => ({
    body: comment.body,
    filePath: comment.filePath,
    findingType: comment.findingType,
    id: comment.publicId,
    line: comment.line,
    prAnalysisId: comment.analysis.publicId,
    prNumber: comment.analysis.prNumber,
    riskLevel: comment.riskLevel,
  }));
}

export async function loadRelatedFixes(db: DbClient, analysisIds: string[]) {
  const uniqueIds = unique(analysisIds.filter((id) => id.length > 0));
  if (uniqueIds.length === 0) return [];

  const fixes = await db.generatedFix.findMany({
    orderBy: { createdAt: "desc" },
    select: {
      githubPrNumber: true,
      githubPrUrl: true,
      publicId: true,
      status: true,
      title: true,
    },
    take: 8,
    where: {
      prAnalysis: {
        publicId: { in: uniqueIds },
      },
    },
  });

  return fixes.map((fix) => ({
    githubPrNumber: fix.githubPrNumber,
    githubPrUrl: fix.githubPrUrl,
    id: fix.publicId,
    status: fix.status,
    title: fix.title,
  }));
}

export function scoreSearchMatch(terms: string[], values: Array<null | string | undefined>) {
  const haystack = values
    .filter((value): value is string => typeof value === "string" && value.length > 0)
    .map((value) => value.toLowerCase());

  if (haystack.length === 0) return 0;

  let score = 0;
  for (const term of terms) {
    const exact = haystack.includes(term);
    const prefix = haystack.some((value) => value.startsWith(term));
    const partial = haystack.some((value) => value.includes(term));

    if (exact) score += 12;
    else if (prefix) score += 8;
    else if (partial) score += 4;
    else return 0;
  }

  return score;
}

export function dedupeSearchResults(results: RepoSearchResult[]) {
  const sortedByBest = orderBy(results, [(r) => r.score], ["desc"]);

  const unique = uniqBy(sortedByBest, (r) => r.id);

  return orderBy(unique, [(r) => r.score, (r) => r.label], ["desc", "asc"]);
}

export function pickLatestDocsByType<TDoc extends { type: DocType; updatedAt: Date }>(
  docs: TDoc[]
) {
  const latest = uniqBy(orderBy(docs, [(d) => d.updatedAt], ["desc"]), (d) => d.type);
  return orderBy(latest, [(d) => d.type], ["asc"]);
}

export async function getAnalysisSnapshot(db: DbClient, repoId: string, aid?: string) {
  if (aid != null) {
    const analysis = await db.analysis.findFirst({
      where: {
        publicId: aid,
        repo: { publicId: repoId },
        status: "DONE",
      },
    });
    if (!analysis)
      throw new TRPCError({ code: "NOT_FOUND", message: "Specified analysis version not found" });
    return analysis;
  }

  return await getLatestCompletedAnalysis(db, repoId);
}

import { compact } from "es-toolkit";

import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import { unique } from "@/server/shared/lib/array-utils";

import type { StructureGroupEntry, StructureSemanticKind } from "./structure-shared";

type StructureNodeSummaryLike = {
  kind: string;
  label: string;
  markers: {
    api: boolean;
    config: boolean;
    entrypoint: boolean;
    risk: boolean;
    server: boolean;
    shared: boolean;
  };
  nodeType: "file" | "group";
  path: string;
  score: number;
  stats: {
    apiCount: number;
    changeCouplingCount: number;
    churnCount: number;
    configCount: number;
    dependencyHotspotCount: number;
    entrypointCount: number;
    frameworkCount: number;
    graphWarningCount: number;
    hotspotCount: number;
    orphanCount: number;
    pathCount: number;
    riskCount: number;
  };
};

export const SEMANTIC_META: Record<StructureSemanticKind, { description: string; label: string }> =
  {
    api: { description: "Public API and externally reachable interface paths.", label: "API" },
    backend: {
      description: "Backend runtime, orchestration, services or server-side logic.",
      label: "Backend",
    },
    config: {
      description: "Configuration, environment or runtime setup surface.",
      label: "Config",
    },
    core: {
      description: "Core domain or engine logic that anchors important behavior.",
      label: "Core",
    },
    data: {
      description: "Persistence, schema, migrations or data-access concerns.",
      label: "Data",
    },
    frontend: {
      description: "UI, app shell or client-facing flow composition.",
      label: "Frontend",
    },
    infrastructure: {
      description: "Adapters and infrastructure integrations around the main runtime.",
      label: "Infrastructure",
    },
    ml: {
      description: "Machine learning models, training pipelines, datasets or inference logic.",
      label: "Machine Learning",
    },
    mobile: {
      description: "Mobile-specific application code, platform assets or cross-platform flows.",
      label: "Mobile",
    },
    shared: {
      description: "Cross-cutting shared primitives reused across the codebase.",
      label: "Shared",
    },
    unknown: {
      description: "A structural area without a stronger semantic signal yet.",
      label: "Module",
    },
  };

export function collectSemanticKinds(path: string, apiPaths: Set<string>): StructureSemanticKind[] {
  return ProjectPolicy.getSemanticKinds(path, { apiPaths }) as StructureSemanticKind[];
}

export function describeGroup(groupId: string, primaryKind: StructureSemanticKind) {
  const label = ProjectPolicy.getGroupLabel(groupId);
  return `${label}: ${SEMANTIC_META[primaryKind].description}`;
}

export function getGenericGroupPenalty(node: StructureNodeSummaryLike) {
  if (node.nodeType !== "group") return 0;

  let penalty = ProjectPolicy.getGenericGroupPathPenalty(node.path);
  if (node.kind === "unknown") penalty += 6;

  const hasStrongSignal = node.markers.entrypoint || node.markers.api || node.markers.risk;
  if (!hasStrongSignal && !node.markers.shared && !node.markers.config) penalty += 4;
  if (!hasStrongSignal && node.stats.pathCount < 3) penalty += 6;

  if (hasStrongSignal) penalty -= 6;
  if (node.kind === "core" || node.kind === "backend" || node.kind === "api") penalty -= 2;

  return Math.max(0, penalty);
}

export function isLikelyBarrelPath(path: string) {
  const normalized = normalizeRepoPath(path).toLowerCase();
  return /(^|\/)index\.(ts|tsx|js|jsx|mts|cts)$/u.test(normalized);
}

export function buildGroupKeySet(paths: string[], _apiPaths: Set<string>) {
  return unique(paths.map((path) => ProjectPolicy.deriveGroupId(path)));
}

function getPrimaryKindForEntry(entry: StructureGroupEntry) {
  return ProjectPolicy.getPrimarySemanticKind(entry.semanticCounts);
}

export function filterMeaningfulEntrypoints(paths: string[]) {
  const normalized = unique(compact(Array.from(paths)).map((path) => normalizeRepoPath(path)));
  const nonBarrel = normalized.filter((path) => !isLikelyBarrelPath(path));
  return nonBarrel.length > 0 ? nonBarrel : normalized;
}

export function summarizeGroupImportance(params: {
  apiCount: number;
  changeCouplingCount: number;
  churnCount: number;
  configCount: number;
  dependencyHotspotCount: number;
  entrypointCount: number;
  frameworkCount: number;
  graphWarningCount: number;
  groupId: string;
  hotspotCount: number;
  orphanCount: number;
  primaryKind: StructureSemanticKind;
  riskCount: number;
  sampleCount: number;
}) {
  const reasons: string[] = [];

  if (params.entrypointCount > 0) reasons.push("contains likely entrypoints");
  if (params.apiCount > 0) reasons.push("surfaces public API or route files");
  if (params.riskCount > 0) reasons.push("appears in high-risk or hotspot evidence");
  if (params.churnCount > 0) reasons.push("shows recent git activity concentration");
  if (params.changeCouplingCount > 0)
    reasons.push("changes here tend to move with neighboring paths");
  if (params.configCount > 0) reasons.push("contains configuration or runtime setup");
  if (params.frameworkCount > 0) reasons.push("shows framework or runtime integration signals");
  if (params.dependencyHotspotCount > 0) reasons.push("contains dependency-central files");
  if (params.orphanCount > 0) reasons.push("includes isolated runtime paths worth reviewing");
  if (params.graphWarningCount > 0) reasons.push("has partial dependency-resolution evidence");
  if (params.hotspotCount > 0 && params.riskCount === 0)
    reasons.push("concentrates hotspot candidates");
  if (params.sampleCount >= 8 && reasons.length === 0)
    reasons.push("covers a large structural area");

  if (reasons.length === 0) return describeGroup(params.groupId, params.primaryKind);

  return `${describeGroup(params.groupId, params.primaryKind)} This area ${reasons.join(", ")}.`;
}

function getStructureSeedScore(params: {
  apiPaths: Set<string>;
  graphRelatedPaths: Set<string>;
  metrics: RepoMetrics;
  path: string;
  signalMap: Map<
    string,
    Set<"api" | "config" | "entrypoint" | "fact" | "finding" | "hotspot" | "onboarding">
  >;
}) {
  const normalizedPath = normalizeRepoPath(params.path);
  const signals = params.signalMap.get(normalizedPath) ?? new Set();
  let score = 0;

  if (signals.has("entrypoint")) score += 5;
  if (signals.has("api")) score += 4;
  if (signals.has("hotspot") || signals.has("finding")) score += 4;
  if (signals.has("fact") || signals.has("onboarding")) score += 3;
  if (signals.has("config") && !ProjectPolicy.isLowSignalConfig(normalizedPath)) score += 1;

  if (params.graphRelatedPaths.has(normalizedPath)) score += 3;
  if ((params.metrics.documentationInput?.api.publicSurfacePaths ?? []).includes(normalizedPath))
    score += 3;
  if ((params.metrics.routeInventory?.sourceFiles ?? []).includes(normalizedPath)) score += 2;

  if (ProjectPolicy.isApiPath(normalizedPath)) score += 2;
  if (ProjectPolicy.isArchitectureRelevant(normalizedPath)) score += 2;
  if (ProjectPolicy.isPrimaryEntrypoint(normalizedPath)) score += 2;
  if (
    ProjectPolicy.isConfigFile(normalizedPath) &&
    !ProjectPolicy.isLowSignalConfig(normalizedPath)
  )
    score += 1;

  const groupId = ProjectPolicy.deriveGroupId(normalizedPath);
  if (ProjectPolicy.isBroadGenericGroupPath(groupId)) score -= 2;
  if (normalizedPath.split("/").filter(Boolean).length <= 1) score -= 2;

  return score;
}

export function shouldKeepStructurePath(
  path: string,
  signalMap: Map<
    string,
    Set<"api" | "config" | "entrypoint" | "fact" | "finding" | "hotspot" | "onboarding">
  >,
  metrics: RepoMetrics,
  apiPaths: Set<string>,
  graphRelatedPaths: Set<string>
) {
  const normalizedPath = normalizeRepoPath(path);
  if (ProjectPolicy.isSensitive(normalizedPath)) return false;
  if (ProjectPolicy.isIgnored(normalizedPath)) return false;

  const signals = signalMap.get(normalizedPath) ?? new Set();
  const hasStrongSignal =
    signals.has("entrypoint") ||
    signals.has("api") ||
    signals.has("hotspot") ||
    signals.has("finding") ||
    signals.has("fact") ||
    signals.has("onboarding");

  if (hasStrongSignal) return true;
  if (signals.has("config")) return !ProjectPolicy.isLowSignalConfig(normalizedPath);
  if (ProjectPolicy.isLikelyBarrelFile(normalizedPath)) return false;
  if (ProjectPolicy.isDocsFile(normalizedPath)) return false;
  if (ProjectPolicy.isGeneratedFile(normalizedPath)) return false;
  if (ProjectPolicy.isTestFile(normalizedPath)) return false;
  if (ProjectPolicy.isAssetFile(normalizedPath)) return false;
  if (ProjectPolicy.isToolingFile(normalizedPath)) return false;

  return (
    getStructureSeedScore({
      apiPaths,
      graphRelatedPaths,
      metrics,
      path: normalizedPath,
      signalMap,
    }) >= 2
  );
}

export function rankStructureNode(node: StructureNodeSummaryLike) {
  let rank = node.score;
  if (node.nodeType === "group") rank += 6;
  if (node.markers.entrypoint) rank += 12;
  if (node.markers.api) rank += 10;
  if (node.markers.risk) rank += 8;
  if (node.markers.config) rank += 4;
  if (node.markers.shared) rank += 3;
  if (node.kind !== "unknown") rank += 2;
  if (node.nodeType === "file" && ProjectPolicy.isLikelyBarrelFile(node.path)) rank -= 8;
  rank -= getGenericGroupPenalty(node);
  return rank;
}

export function isMeaningfulTopLevelNode(node: StructureNodeSummaryLike) {
  if (
    ProjectPolicy.isBroadGenericGroupPath(node.path) &&
    !node.markers.entrypoint &&
    !node.markers.api &&
    !node.markers.risk &&
    node.stats.pathCount < 3
  ) {
    return false;
  }

  if (node.markers.entrypoint || node.markers.api || node.markers.risk) return true;
  if (node.markers.config || node.markers.shared) return true;
  if (node.stats.pathCount >= 2) return true;
  return node.kind !== "unknown";
}

export function isMeaningfulChildNode(node: StructureNodeSummaryLike) {
  if (node.nodeType === "group") {
    return (
      node.markers.entrypoint ||
      node.markers.api ||
      node.markers.risk ||
      node.markers.config ||
      node.markers.shared ||
      node.stats.pathCount >= 2 ||
      node.kind !== "unknown"
    );
  }

  if (node.markers.entrypoint || node.markers.api || node.markers.risk || node.markers.config) {
    return true;
  }

  if (ProjectPolicy.isLikelyBarrelFile(node.path)) return false;
  return ProjectPolicy.isArchitectureRelevant(node.path) || ProjectPolicy.isApiPath(node.path);
}

export function collectGroupsByKind(groupMap: Map<string, StructureGroupEntry>) {
  const byKind = new Map<StructureSemanticKind, string[]>();

  for (const [groupId, entry] of groupMap.entries()) {
    const kind = getPrimaryKindForEntry(entry);
    const current = byKind.get(kind) ?? [];
    current.push(groupId);
    byKind.set(kind, current);
  }

  return byKind;
}

export function getStrongGroups(
  groups: string[] | undefined,
  groupMap: Map<string, StructureGroupEntry>,
  limit: number
) {
  return (groups ?? [])
    .slice()
    .sort((left, right) => {
      const leftEntry = groupMap.get(left);
      const rightEntry = groupMap.get(right);
      const leftScore =
        (leftEntry?.entrypointDetails.length ?? 0) * 4 +
        (leftEntry?.apiPaths.length ?? 0) * 3 +
        (leftEntry?.riskTitles.length ?? 0) * 2 +
        (leftEntry?.paths.length ?? 0);
      const rightScore =
        (rightEntry?.entrypointDetails.length ?? 0) * 4 +
        (rightEntry?.apiPaths.length ?? 0) * 3 +
        (rightEntry?.riskTitles.length ?? 0) * 2 +
        (rightEntry?.paths.length ?? 0);

      return rightScore - leftScore || left.localeCompare(right);
    })
    .slice(0, limit);
}

import type { AIResult } from "@/server/shared/engine/core/analysis-result.schemas";
import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import { unique } from "@/server/shared/lib/array-utils";

export function collectScopedEntrySignals(
  paths: string[],
  context: {
    aiResult: AIResult;
    metrics: RepoMetrics;
  }
) {
  const normalizedPaths = unique(paths.map((path) => normalizeRepoPath(path)));
  const pathSet = new Set(normalizedPaths);

  const frameworkNames = unique(
    (context.metrics.frameworkFacts ?? [])
      .filter((fact) => fact.sources.some((source) => pathSet.has(normalizeRepoPath(source))))
      .map((fact) => fact.name)
  ).slice(0, 5);

  const hotspotSignals = [...(context.metrics.hotspotSignals ?? [])]
    .filter((signal) => pathSet.has(normalizeRepoPath(signal.path)))
    .sort((left, right) => right.score - left.score)
    .slice(0, 4);

  const dependencyHotspots = [...context.metrics.dependencyHotspots]
    .filter((hotspot) => pathSet.has(normalizeRepoPath(hotspot.path)))
    .sort(
      (left, right) =>
        right.inbound +
        right.outbound +
        right.exports -
        (left.inbound + left.outbound + left.exports)
    )
    .slice(0, 4);

  const orphanPaths = unique(
    context.metrics.orphanModules
      .map((path) => normalizeRepoPath(path))
      .filter((path) => pathSet.has(path))
  ).slice(0, 4);

  const graphUnresolvedSamples = (context.metrics.graphReliability?.unresolvedSamples ?? [])
    .filter((sample) => pathSet.has(normalizeRepoPath(sample.fromPath)))
    .slice(0, 4);

  const graphNeighborPaths = unique(
    (context.metrics.graphPreviewEdges ?? [])
      .flatMap((edge) => {
        const fromPath = normalizeRepoPath(edge.fromPath);
        const toPath = normalizeRepoPath(edge.toPath);

        if (pathSet.has(fromPath) && !pathSet.has(toPath)) return [toPath];
        if (pathSet.has(toPath) && !pathSet.has(fromPath)) return [fromPath];
        return [];
      })
      .filter((path) => !pathSet.has(path))
  ).slice(0, 8);

  const factTitles = unique(
    (context.aiResult.repository_facts ?? [])
      .filter((fact) => fact.evidence.some((item) => pathSet.has(normalizeRepoPath(item.path))))
      .map((fact) => fact.title)
  ).slice(0, 5);

  return {
    changeCoupling: [...(context.metrics.changeCoupling ?? [])]
      .filter(
        (pair) =>
          pathSet.has(normalizeRepoPath(pair.fromPath)) ||
          pathSet.has(normalizeRepoPath(pair.toPath))
      )
      .sort((left, right) => right.commits - left.commits)
      .slice(0, 4),
    churnHotspots: [...(context.metrics.churnHotspots ?? [])]
      .filter((hotspot) => pathSet.has(normalizeRepoPath(hotspot.path)))
      .sort((left, right) => right.commitsInWindow - left.commitsInWindow)
      .slice(0, 4),
    dependencyHotspots,
    factTitles,
    frameworkNames,
    graphNeighborPaths,
    graphUnresolvedSamples,
    hotspotSignals,
    orphanPaths,
  };
}

export function collectScopedSignals(
  paths: string[],
  context: {
    aiResult: AIResult;
  }
) {
  const pathSet = new Set(paths.map((path) => normalizeRepoPath(path)));

  const matchingFacts = (context.aiResult.repository_facts ?? []).filter((fact) =>
    fact.evidence.some((item) => pathSet.has(normalizeRepoPath(item.path)))
  );
  const matchingFindings = (context.aiResult.findings ?? []).filter((finding) =>
    finding.evidence.some((item) => pathSet.has(normalizeRepoPath(item.path)))
  );

  return {
    facts: matchingFacts,
    findings: matchingFindings,
  };
}

import type { AIResult } from "@/server/shared/engine/core/analysis-result.schemas";
import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import type { RepoWithLatestAnalysisAndDocs } from "@/server/shared/infrastructure/repo-snapshots";
import { unique } from "@/server/shared/lib/array-utils";
import { hasText } from "@/server/shared/lib/string-utils";

import { createStructuralContextEdges } from "./edge-builder";
import { coerceAnalysisPayload } from "./payload";
import {
  buildGroupKeySet,
  collectSemanticKinds,
  filterMeaningfulEntrypoints,
  isLikelyBarrelPath,
  shouldKeepStructurePath,
} from "./semantics";
import { collectScopedEntrySignals } from "./signals";
import {
  createEmptyGroupEntry,
  isPathInsideScope,
  makeStructureNodeId,
  type StructureContext,
  type StructureGroupEntry,
  type StructureNodeType,
} from "./structure-shared";

export function buildBreadcrumbs(nodeType: StructureNodeType, path: string) {
  const parts = normalizeRepoPath(path).split("/").filter(Boolean);
  if (parts.length === 0) return [];

  const breadcrumbs = parts.slice(0, -1).map((_, index) => {
    const crumbPath = parts.slice(0, index + 1).join("/");
    return {
      id: makeStructureNodeId("group", crumbPath),
      label: ProjectPolicy.getGroupLabel(crumbPath),
      nodeType: "group" as const,
      path: crumbPath,
    };
  });

  if (nodeType === "group") {
    return [
      ...breadcrumbs,
      {
        id: makeStructureNodeId("group", path),
        label: ProjectPolicy.getGroupLabel(path),
        nodeType: "group" as const,
        path,
      },
    ];
  }

  return [
    ...breadcrumbs,
    {
      id: makeStructureNodeId("file", path),
      label: path.split("/").findLast(Boolean) ?? path,
      nodeType: "file" as const,
      path,
    },
  ];
}

export function collectNodeScopePaths(
  context: StructureContext,
  nodeType: StructureNodeType,
  path: string
) {
  if (nodeType === "file") {
    const normalizedPath = normalizeRepoPath(path);
    return context.allInterestingPaths.includes(normalizedPath) ? [normalizedPath] : [];
  }

  return context.allInterestingPaths.filter((candidatePath) =>
    isPathInsideScope(candidatePath, path)
  );
}
export function aggregateEntryForPaths(paths: string[], context: StructureContext) {
  const normalizedPaths = unique(paths.map((path) => normalizeRepoPath(path)));
  const pathSet = new Set(normalizedPaths);
  const entry = createEmptyGroupEntry();

  for (const path of normalizedPaths) {
    entry.paths.push(path);
    if (context.apiPaths.has(path)) entry.apiPaths.push(path);
    if (context.normalizedConfigInventory.includes(path)) entry.configPaths.push(path);
    if ((context.docInput?.api.publicSurfacePaths ?? []).includes(path))
      entry.publicSurfacePaths.push(path);
    for (const semanticKind of collectSemanticKinds(path, context.apiPaths)) {
      entry.semanticCounts[semanticKind] += 1;
    }
  }

  for (const entrypoint of context.metrics.entrypointDetails ?? []) {
    const normalizedEntrypointPath = normalizeRepoPath(entrypoint.path);
    if (pathSet.has(normalizedEntrypointPath)) {
      entry.entrypointDetails.push(entrypoint);
    }
  }

  for (const finding of context.aiResult.findings ?? []) {
    if (finding.evidence.some((item) => pathSet.has(normalizeRepoPath(item.path)))) {
      entry.riskTitles.push(finding.title);
    }
  }

  const scopedSignals = collectScopedEntrySignals(normalizedPaths, context);
  entry.changeCoupling = scopedSignals.changeCoupling;
  entry.churnHotspots = scopedSignals.churnHotspots;
  entry.dependencyHotspots = scopedSignals.dependencyHotspots;
  entry.factTitles = scopedSignals.factTitles;
  entry.frameworkNames = scopedSignals.frameworkNames;
  entry.graphNeighborPaths = scopedSignals.graphNeighborPaths;
  entry.graphUnresolvedSamples = scopedSignals.graphUnresolvedSamples;
  entry.hotspotSignals = scopedSignals.hotspotSignals;
  entry.orphanPaths = scopedSignals.orphanPaths;

  return entry;
}
function collectInterestingPaths(
  aiResult: AIResult,
  metrics: RepoMetrics,
  meaningfulEntrypoints: string[]
) {
  const docInput = metrics.documentationInput ?? null;
  return unique(
    [
      ...(docInput?.architecture.modules.map((module) => module.path) ?? []),
      ...meaningfulEntrypoints,
      ...(docInput?.sections.overview.body.primaryModules ?? []),
      ...(docInput?.sections.onboarding.body.firstLookPaths ?? []),
      ...(docInput?.sections.onboarding.body.apiPaths ?? []),
      ...(docInput?.sections.onboarding.body.configPaths ?? []),
      ...(docInput?.sections.onboarding.body.riskPaths ?? []),
      ...(metrics.routeInventory?.sourceFiles ?? []),
      ...(docInput?.api.publicSurfacePaths ?? []),
      ...metrics.hotspotFiles,
      ...metrics.configInventory,
      ...(aiResult.findings ?? []).flatMap((finding) => finding.evidence.map((item) => item.path)),
      ...(aiResult.repository_facts ?? []).flatMap((fact) =>
        fact.evidence.map((item) => item.path)
      ),
    ]
      .filter(hasText)
      .map((path) => normalizeRepoPath(path))
  );
}
function collectStructureSignalMap(params: {
  aiResult: AIResult;
  meaningfulEntrypoints: string[];
  metrics: RepoMetrics;
}) {
  const map = new Map<
    string,
    Set<"api" | "config" | "entrypoint" | "fact" | "finding" | "hotspot" | "onboarding">
  >();

  function add(
    paths: string[],
    signal: "api" | "config" | "entrypoint" | "fact" | "finding" | "hotspot" | "onboarding"
  ) {
    for (const rawPath of paths) {
      if (!hasText(rawPath)) continue;
      const path = normalizeRepoPath(rawPath);
      const current = map.get(path) ?? new Set();
      current.add(signal);
      map.set(path, current);
    }
  }

  add(params.meaningfulEntrypoints, "entrypoint");
  add(params.metrics.routeInventory?.sourceFiles ?? [], "api");
  add(params.metrics.documentationInput?.api.publicSurfacePaths ?? [], "api");
  add(params.metrics.hotspotFiles, "hotspot");
  add(params.metrics.configInventory, "config");
  add(
    params.metrics.documentationInput?.sections.onboarding.body.firstLookPaths ?? [],
    "onboarding"
  );
  add(params.metrics.documentationInput?.sections.onboarding.body.apiPaths ?? [], "onboarding");
  add(params.metrics.documentationInput?.sections.onboarding.body.configPaths ?? [], "onboarding");
  add(params.metrics.documentationInput?.sections.onboarding.body.riskPaths ?? [], "onboarding");
  add(
    (params.aiResult.findings ?? []).flatMap((finding) =>
      finding.evidence.map((item) => item.path)
    ),
    "finding"
  );
  add(
    (params.aiResult.repository_facts ?? []).flatMap((fact) =>
      fact.evidence.map((item) => item.path)
    ),
    "fact"
  );

  return map;
}
function buildGraphRelatedPathSet(metrics: RepoMetrics) {
  return new Set(
    (metrics.graphPreviewEdges ?? []).flatMap((edge) => [
      normalizeRepoPath(edge.fromPath),
      normalizeRepoPath(edge.toPath),
    ])
  );
}
export function buildStructureContext(
  repo: RepoWithLatestAnalysisAndDocs
): null | StructureContext {
  const payload = coerceAnalysisPayload(repo.analyses[0]);
  if (payload == null) return null;

  const { aiResult, metrics } = payload;
  const docInput = metrics.documentationInput ?? null;
  const apiPaths = buildApiPathSet(metrics);
  const graphRelatedPaths = buildGraphRelatedPathSet(metrics);
  const meaningfulEntrypoints = filterMeaningfulEntrypoints(metrics.entrypoints);
  const normalizedConfigInventory = metrics.configInventory.map((path) => normalizeRepoPath(path));
  const signalMap = collectStructureSignalMap({ aiResult, meaningfulEntrypoints, metrics });
  const allInterestingPaths = collectInterestingPaths(
    aiResult,
    metrics,
    meaningfulEntrypoints
  ).filter((path) =>
    shouldKeepStructurePath(path, signalMap, metrics, apiPaths, graphRelatedPaths)
  );

  const groupMap = new Map<string, StructureGroupEntry>();

  for (const path of allInterestingPaths) {
    const groupId = ProjectPolicy.deriveGroupId(path);
    const current = groupMap.get(groupId) ?? createEmptyGroupEntry();
    current.paths.push(path);
    if (apiPaths.has(path)) current.apiPaths.push(path);
    if (normalizedConfigInventory.includes(path)) current.configPaths.push(path);
    if ((docInput?.api.publicSurfacePaths ?? []).includes(path))
      current.publicSurfacePaths.push(path);
    for (const semanticKind of collectSemanticKinds(path, apiPaths)) {
      current.semanticCounts[semanticKind] += 1;
    }
    groupMap.set(groupId, current);
  }

  for (const entrypoint of (metrics.entrypointDetails ?? []).filter(
    (item) =>
      !isLikelyBarrelPath(item.path) &&
      !ProjectPolicy.isIgnored(item.path) &&
      !ProjectPolicy.isSensitive(item.path) &&
      !ProjectPolicy.isLowSignalConfig(item.path)
  )) {
    const normalizedEntrypointPath = normalizeRepoPath(entrypoint.path);
    const groupId = ProjectPolicy.deriveGroupId(normalizedEntrypointPath);
    const current = groupMap.get(groupId) ?? createEmptyGroupEntry();
    current.entrypointDetails.push(entrypoint);
    current.paths.push(normalizedEntrypointPath);
    for (const semanticKind of collectSemanticKinds(normalizedEntrypointPath, apiPaths)) {
      current.semanticCounts[semanticKind] += 1;
    }
    groupMap.set(groupId, current);
  }

  for (const finding of aiResult.findings ?? []) {
    const findingGroups = buildGroupKeySet(
      finding.evidence.map((item) => normalizeRepoPath(item.path)),
      apiPaths
    );
    for (const groupId of findingGroups) {
      const current = groupMap.get(groupId) ?? createEmptyGroupEntry();
      current.riskTitles.push(finding.title);
      groupMap.set(groupId, current);
    }
  }

  for (const [groupId, current] of groupMap) {
    const scopedSignals = collectScopedEntrySignals(current.paths, {
      aiResult,
      metrics,
    });
    current.dependencyHotspots = scopedSignals.dependencyHotspots;
    current.factTitles = scopedSignals.factTitles;
    current.frameworkNames = scopedSignals.frameworkNames;
    current.graphNeighborPaths = scopedSignals.graphNeighborPaths;
    current.graphUnresolvedSamples = scopedSignals.graphUnresolvedSamples;
    current.hotspotSignals = scopedSignals.hotspotSignals;
    current.orphanPaths = scopedSignals.orphanPaths;
    groupMap.set(groupId, current);
  }

  return {
    aiResult,
    allInterestingPaths,
    apiPaths,
    docInput,
    groupMap,
    meaningfulEntrypoints,
    metrics,
    normalizedConfigInventory,
    rawTopLevelEdges: createStructuralContextEdges({ aiResult, apiPaths, groupMap, metrics }),
    signalMap,
  };
}

function buildApiPathSet(metrics: RepoMetrics) {
  return new Set(
    unique([
      ...(metrics.routeInventory?.sourceFiles ?? []),
      ...(metrics.documentationInput?.api.publicSurfacePaths ?? []),
    ]).map((path) => normalizeRepoPath(path))
  );
}

import type { AIResult } from "@/server/shared/engine/core/analysis-result.schemas";
import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import type { ProjectPolicySemanticKind } from "@/server/shared/engine/core/project-policy-rules";
import type { RepoWithLatestAnalysisAndDocs } from "@/server/shared/infrastructure/repo-snapshots";

export type WriterStatus = "failed" | "llm" | "missing";

export type StructureEdgeRelationType =
  | "api"
  | "config"
  | "cycle"
  | "entrypoint"
  | "focus"
  | "risk";

export type StructureNodeType = "file" | "group";

export type StructureSemanticKind = ProjectPolicySemanticKind;

export type StoredDocument = RepoWithLatestAnalysisAndDocs["documents"][number];

export type StructureGroupEntry = {
  apiPaths: string[];
  changeCoupling: NonNullable<RepoMetrics["changeCoupling"]>;
  churnHotspots: NonNullable<RepoMetrics["churnHotspots"]>;
  configPaths: string[];
  dependencyHotspots: NonNullable<RepoMetrics["dependencyHotspots"]>;
  entrypointDetails: NonNullable<RepoMetrics["entrypointDetails"]>;
  factTitles: string[];
  frameworkNames: string[];
  graphNeighborPaths: string[];
  graphUnresolvedSamples: NonNullable<
    NonNullable<RepoMetrics["graphReliability"]>["unresolvedSamples"]
  >;
  hotspotSignals: NonNullable<RepoMetrics["hotspotSignals"]>;
  orphanPaths: string[];
  paths: string[];
  publicSurfacePaths: string[];
  riskTitles: string[];
  semanticCounts: Record<StructureSemanticKind, number>;
};

export type StructureContext = {
  aiResult: AIResult;
  allInterestingPaths: string[];
  apiPaths: Set<string>;
  docInput: null | RepoMetrics["documentationInput"];
  groupMap: Map<string, StructureGroupEntry>;
  meaningfulEntrypoints: string[];
  metrics: RepoMetrics;
  normalizedConfigInventory: string[];
  rawTopLevelEdges: Array<{
    id: string;
    relation: StructureEdgeRelationType;
    source: string;
    target: string;
    weight: number;
  }>;
  signalMap: Map<
    string,
    Set<"api" | "config" | "entrypoint" | "fact" | "finding" | "hotspot" | "onboarding">
  >;
};

function createSemanticCounts(): Record<StructureSemanticKind, number> {
  return {
    api: 0,
    backend: 0,
    config: 0,
    core: 0,
    data: 0,
    frontend: 0,
    infrastructure: 0,
    ml: 0,
    mobile: 0,
    shared: 0,
    unknown: 0,
  };
}

export function createEmptyGroupEntry(): StructureGroupEntry {
  return {
    apiPaths: [],
    changeCoupling: [],
    churnHotspots: [],
    configPaths: [],
    dependencyHotspots: [],
    entrypointDetails: [],
    factTitles: [],
    frameworkNames: [],
    graphNeighborPaths: [],
    graphUnresolvedSamples: [],
    hotspotSignals: [],
    orphanPaths: [],
    paths: [],
    publicSurfacePaths: [],
    riskTitles: [],
    semanticCounts: createSemanticCounts(),
  };
}

export function makeStructureNodeId(nodeType: StructureNodeType, path: string) {
  return `${nodeType}:${normalizeRepoPath(path)}`;
}

export function parseStructureNodeId(nodeId: string): {
  nodeType: StructureNodeType;
  path: string;
} {
  if (nodeId.startsWith("group:")) {
    return { nodeType: "group", path: normalizeRepoPath(nodeId.slice("group:".length)) };
  }
  if (nodeId.startsWith("file:")) {
    return { nodeType: "file", path: normalizeRepoPath(nodeId.slice("file:".length)) };
  }
  return { nodeType: "group", path: normalizeRepoPath(nodeId) };
}

export function isPathInsideScope(path: string, scopePath: string) {
  const normalizedPath = normalizeRepoPath(path);
  const normalizedScope = normalizeRepoPath(scopePath);
  return normalizedPath === normalizedScope || normalizedPath.startsWith(`${normalizedScope}/`);
}

export function resolveImmediateChildScope(parentPath: string, candidatePath: string) {
  const normalizedParent = normalizeRepoPath(parentPath);
  const normalizedCandidate = normalizeRepoPath(candidatePath);

  if (!normalizedCandidate.startsWith(`${normalizedParent}/`)) return null;

  const relative = normalizedCandidate.slice(normalizedParent.length + 1);
  const parts = relative.split("/").filter(Boolean);
  const head = parts[0];

  const scopePath = `${normalizedParent}/${head}`;
  return {
    nodeType: parts.length > 1 ? ("group" as const) : ("file" as const),
    path: scopePath,
  };
}

import crypto from "node:crypto";
import { TRPCError } from "@trpc/server";

import type { DbClient } from "@/server/shared/infrastructure/db";
import { handlePrismaError } from "@/server/shared/lib/handle-error";

const BRAND_PREFIX = "dxnx_";

export const apiKeyService = {
  async create(db: DbClient, userId: number, input: { description?: null | string; name: string }) {
    const randomPart = crypto.randomBytes(32).toString("base64url");
    const fullKey = `${BRAND_PREFIX}${randomPart}`;
    const displayPrefix = `${BRAND_PREFIX}${randomPart.slice(0, 6)}`;
    const hashedKey = crypto.createHash("sha256").update(fullKey).digest("hex");

    try {
      await db.apiKey.create({
        data: {
          description: input.description,
          hashedKey,
          name: input.name,
          prefix: displayPrefix,
          userId,
        },
      });
    } catch (error) {
      handlePrismaError(error, {
        defaultConflict: "API Key with this name already exists",
        uniqueConstraint: {
          hashedKey: "Incredible, but a duplicate key was generated. Try again.",
          name: "API Key with this name already exists",
        },
      });
    }

    return { key: fullKey, message: "API Key created" };
  },

  async list(db: DbClient) {
    const allKeys = await db.apiKey.findMany({
      orderBy: { createdAt: "desc" },
      where: {
        OR: [{ revoked: true }, { revoked: false }],
      },
    });

    return {
      active: allKeys.filter((k) => k.revoked === false),
      archived: allKeys.filter((k) => k.revoked),
    };
  },

  async revoke(db: DbClient, id: string) {
    try {
      await db.apiKey.update({
        data: { revoked: true },
        where: { id },
      });

      return { message: "API Key revoked", success: true };
    } catch (error) {
      handlePrismaError(error, { notFound: "Key not found" });
    }
  },

  async touch(db: DbClient, id: string) {
    const result = await db.apiKey
      .updateMany({
        data: { lastUsed: new Date() },
        where: { id },
      })
      .catch((error) => {
        handlePrismaError(error);
      });

    if (result.count === 0) {
      throw new TRPCError({
        code: "NOT_FOUND",
        message: "API Key not found or access denied",
      });
    }

    return { success: true };
  },

  async update(db: DbClient, id: string, input: { description?: null | string; name: string }) {
    try {
      const data = await db.apiKey.updateMany({
        data: { description: input.description, name: input.name },
        where: { id },
      });

      if (data.count === 0) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Key not found or access denied",
        });
      }

      return { message: "API Key data updated", success: true };
    } catch (error) {
      handlePrismaError(error, {
        defaultConflict: "API Key with this name already exists",
        notFound: "Key not found or access denied",
        uniqueConstraint: { name: "Name already taken" },
      });
    }
  },
};

