type DocumentSection = {
  content: string;
  endLine?: number;
  graphNodeIds: string[];
  id: string;
  startLine?: number;
  title: string;
};

type DocumentWithSections = {
  sections: DocumentSection[];
  type: string;
  version: string;
};

type GraphNode = {
  id: string;
  label?: string;
  name?: string;
};

type DependencyGraph = {
  nodes: GraphNode[];
};

const HEADING_REGEX = /^#+\s+/;
const SPACES_REGEX = /\s+/g;
const WORD_SPLIT_REGEX = /[\s-_]+/;

const MENTION_PATTERNS = [
  /(?:component|module|service|class)\s+(?:named\s+)?["']?(\w+)["']?/gi,
  /(?:file|path)\s+["']?([^\s"'>]+)["']?/gi,
  /###\s+(?:component|module):\s+(\w+)/gi,
];

/**
 * Links documentation sections to dependency graph nodes
 * Enables UI synergy: click graph node -> highlight doc section
 */
class DocumentGraphLinker {
  /**
   * Extract anchors and link to graph nodes
   */
  public static linkSectionsToGraph(
    document: string,
    dependencyGraph: DependencyGraph | null | undefined,
    docType: string
  ): DocumentSection[] {
    const sections: DocumentSection[] = [];

    // Split document into sections (by headings)
    const lines = document.split("\n");
    let currentSection: null | Partial<DocumentSection> = null;
    let contentBuffer: string[] = [];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i]!;

      // Detect heading (markdown # style)
      if (HEADING_REGEX.test(line)) {
        // Save previous section
        if (currentSection) {
          currentSection.content = contentBuffer.join("\n").trim();
          currentSection.endLine = i - 1;
          sections.push(currentSection as DocumentSection);
        } else if (contentBuffer.join("").trim().length > 0) {
          sections.push({
            content: contentBuffer.join("\n").trim(),
            endLine: i - 1,
            graphNodeIds: [],
            id: this.generateSectionId(docType, "preamble"),
            startLine: 0,
            title: "Preamble",
          });
        }

        // Start new section
        const title = line.replace(HEADING_REGEX, "").trim();

        currentSection = {
          graphNodeIds: [],
          id: this.generateSectionId(docType, title),
          startLine: i,
          title,
        };

        contentBuffer = [];
      } else {
        contentBuffer.push(line);
      }
    }

    // Save last section
    if (currentSection) {
      currentSection.content = contentBuffer.join("\n").trim();
      currentSection.endLine = lines.length - 1;
      sections.push(currentSection as DocumentSection);
    } else if (document.trim().length > 0) {
      // Fallback: create single section if no headings found
      sections.push({
        content: document.trim(),
        endLine: lines.length - 1,
        graphNodeIds: [],
        id: this.generateSectionId(docType, "document"),
        startLine: 0,
        title: "Document",
      });
    }

    // Link sections to graph nodes
    return sections.map((section) => ({
      ...section,
      graphNodeIds: this.findRelatedGraphNodes(section as DocumentSection, dependencyGraph),
    }));
  }

  private static generateSectionId(docType: string, title: string): string {
    return `section-${docType.toLowerCase()}-${title.toLowerCase().replaceAll(SPACES_REGEX, "-")}`;
  }

  /**
   * Find graph nodes related to doc section
   * Uses heuristics: component name mentions, file references, etc.
   */
  private static findRelatedGraphNodes(
    section: DocumentSection,
    graph: DependencyGraph | null | undefined
  ): string[] {
    const nodeIds: string[] = [];
    const content = section.content.toLowerCase();
    const sectionTitleLower = section.title.toLowerCase();

    // Extract potential node names from content
    const mentionedNames = new Set<string>();

    for (const pattern of MENTION_PATTERNS) {
      pattern.lastIndex = 0;
      let match;
      while ((match = pattern.exec(content)) !== null) {
        if (match[1] != null) {
          mentionedNames.add(match[1].toLowerCase());
        }
      }
    }

    // Match against graph nodes
    if (graph?.nodes != null && Array.isArray(graph.nodes)) {
      for (const node of graph.nodes) {
        const nodeName = (node.label ?? node.name ?? "").toLowerCase();
        const nodeId = node.id;

        if (mentionedNames.has(nodeName) || this.isSimilar(nodeName, sectionTitleLower)) {
          nodeIds.push(nodeId);
        }
      }
    }

    return nodeIds;
  }

  private static isSimilar(str1: string, str2: string): boolean {
    // Simple similarity: contains or shared meaningful words
    const words1 = str1.split(WORD_SPLIT_REGEX).filter((w) => w.length > 1);
    const words2 = str2.split(WORD_SPLIT_REGEX).filter((w) => w.length > 1);

    if (words1.length === 0 || words2.length === 0) return false;

    const set2 = new Set(words2);
    for (const word1 of words1) {
      if (set2.has(word1)) return true;
      for (const word2 of words2) {
        if (word1.includes(word2) || word2.includes(word1)) {
          return true;
        }
      }
    }

    return false;
  }
}

/**
 * Formats document with graph links for API response
 */
export class DocumentFormatter {
  public static withGraphLinks(
    document: string,
    graph: DependencyGraph | null | undefined,
    docType: string,
    version: string
  ): DocumentWithSections {
    const sections = DocumentGraphLinker.linkSectionsToGraph(document, graph, docType);

    return {
      sections,
      type: docType,
      version,
    };
  }
}

import type { DocType, Repo } from "@prisma/client";

import type { AIResult } from "@/server/shared/engine/core/analysis-result.schemas";
import type { RepositoryEvidence } from "@/server/shared/engine/core/discovery.types";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import { buildDocumentationInputModel } from "@/server/shared/engine/pipeline/documentation-input";
import { taskLogger } from "@/server/shared/lib/task-logger";
import type { RepositoryFact, RepositoryFinding } from "@/server/shared/types";

import { buildArchitectDigest } from "./architect-digest";
import { executeArchitectPhase } from "./stages/architect-stage";
import { executeMapperPhase } from "./stages/mapper-stage";
import { executeSentinelPhase } from "./stages/sentinel-stage";
import { getDocumentationInputSnapshot } from "./utils/input-retrieval";
import { orchestrateWriterTasks } from "./writers/writer-orchestrator";

export type DeepDocsResult = {
  generatedApiMarkdown?: string;
  generatedArchitecture?: string;
  generatedChangelog?: string;
  generatedContributing?: string;
  generatedReadme?: string;
  swaggerYaml?: string;
};

/**
 * Main AI Pipeline Orchestrator
 * Coordinates Sentinel → Mapper → Architect → Writers stages
 */
export async function runAiPipeline(
  validFiles: { content: string; path: string }[],
  repositoryFacts: RepositoryFact[],
  repositoryFindings: RepositoryFinding[],
  evidence: RepositoryEvidence,
  hardMetrics: RepoMetrics,
  instructions: string | undefined,
  analysisId: string,
  language: string,
  userId: number,
  repoId: string,
  branch: string
): Promise<AIResult> {
  taskLogger.log("Initializing AI Multi-Agent Pipeline...");

  // Stage 1: Prompt injection detection (Цензор)
  const sentinelStatus = await executeSentinelPhase(instructions, analysisId);

  if (sentinelStatus === "UNSAFE") {
    taskLogger.log("Security Sentinel: Prompt injection detected! Terminating pipeline.");
    throw new Error("Pipeline terminated due to a security violation in user instructions.");
  }

  // Stage 2: Project mapping
  taskLogger.log("Executing Project Mapper Agent...");
  const projectMap = await executeMapperPhase(
    validFiles,
    hardMetrics,
    evidence,
    analysisId,
    userId,
    repoId,
    branch
  );

  // Stage 3: Deep analysis & Context Assembly
  taskLogger.log("Assembling Rich Metadata Context for Architect...");

  if (!hardMetrics.documentationInput) {
    hardMetrics.documentationInput = buildDocumentationInputModel(evidence, hardMetrics);
  }

  const documentationInput = getDocumentationInputSnapshot(evidence, hardMetrics);

  const architectDigest = buildArchitectDigest(
    documentationInput,
    hardMetrics,
    projectMap,
    repositoryFacts,
    repositoryFindings
  );

  taskLogger.log("Invoking Lead Architect Agent...");
  return await executeArchitectPhase(
    validFiles,
    architectDigest,
    analysisId,
    instructions,
    sentinelStatus,
    language,
    userId,
    repoId,
    branch
  );
}

/**
 * Document Generation Pipeline
 * Coordinates parallel writer tasks for all requested documentation
 */
export async function generateDeepDocs(
  files: { content: string; path: string }[],
  analysisResult: AIResult,
  evidence: RepositoryEvidence,
  hardMetrics: RepoMetrics,
  analysisId: string,
  requestedDocs: DocType[],
  repo: Repo,
  userId: number,
  language: string
): Promise<DeepDocsResult> {
  taskLogger.log(`Launching Parallel Documentation Writers for ${requestedDocs.length} assets...`);
  return orchestrateWriterTasks(
    files,
    analysisResult,
    evidence,
    hardMetrics,
    analysisId,
    requestedDocs,
    repo,
    userId,
    language
  );
}

import { zodSchema } from "ai";
import { z } from "zod";

import { prisma } from "@/server/shared/infrastructure/db";
import { githubBrowseService } from "@/server/shared/infrastructure/github/github-browse.service";
import { logger } from "@/server/shared/infrastructure/logger";
import { CodeOptimizer } from "@/server/shared/lib/optimizers";

export function buildRepositoryTools(userId: number, repoId: string, branch: string) {
  const tools: Record<string, any> = {
    listFiles: {
      description: "Get the directory tree of the repository to discover files.",
      execute: async ({ prefix }: { prefix?: string }) => {
        try {
          logger.info({ msg: "AI Tool: listFiles", prefix, repoId });
          const repo = await prisma.repo.findUnique({ where: { publicId: repoId } });
          if (!repo) return "Error: Repo not found";

          const tree = await githubBrowseService.getRepoFiles(
            prisma,
            userId,
            repo.owner,
            repo.name,
            branch
          );

          let paths = tree.map((t) => t[0] as string);
          if (prefix != null) paths = paths.filter((p) => p.startsWith(prefix));

          return paths.slice(0, 500).join("\n");
        } catch {
          return "Error listing files.";
        }
      },
      parameters: zodSchema(
        z.object({
          prefix: z.string().optional().describe("Optional folder path to filter by"),
        })
      ),
    },

    readFile: {
      description:
        "Read the full content of a specific file from the repository. Use this ONLY when you need implementation details that are missing from the snippets.",
      execute: async ({ path }: { path: string }) => {
        try {
          logger.info({ msg: "AI Tool: readFile", path, repoId, userId });
          const fileData = await githubBrowseService.getFileContent(
            prisma,
            prisma,
            userId,
            repoId,
            path,
            branch
          );
          const cleanedContent = await CodeOptimizer.cleanForTool(fileData.content);

          return {
            content: cleanedContent.slice(0, 50_000),
            path: path,
          };
        } catch (error) {
          logger.warn({ error, msg: "AI Tool Failed: readFile", path });
          return `Error: Could not read file ${path}. Proceed with available info.`;
        }
      },
      parameters: zodSchema(
        z.object({
          path: z.string().describe("The full path to the file (e.g., 'src/server/api.ts')"),
        })
      ),
    },
  };

  return tools;
}

