import { normalize } from "pathe";

import type { Module } from "@/server/shared/engine/core/discovery.types";
import { getFileScore } from "@/server/shared/engine/core/file-classifier";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import { PROJECT_POLICY_RULES } from "@/server/shared/engine/core/project-policy-rules";
import { FILE_CONTEXT_MODIFIERS } from "@/server/shared/engine/core/scoring-constants";
import { cleanCodeForAi, skeletonizeCode } from "@/server/shared/lib/optimizers";
import { escapePromptXmlAttr, escapePromptXmlText } from "@/server/shared/lib/string-utils";
import { countTokens } from "@/server/shared/lib/tokenizer";

export type AiContextStage = "architect" | "writer_api" | "writer_architecture" | "writer_readme";

export type ContextDropReason =
  | "budget"
  | "empty-after-clean"
  | "secondary-no-budget"
  | "sensitive"
  | "stage-filter";

export type StageContextDebugEntry = {
  path: string;
  reason: string;
  score: number;
  tokens: number;
  truncated: boolean;
};

export type StageContextDropEntry = {
  path: string;
  reason: ContextDropReason;
  score: number;
};

export type StageContextSelection = {
  budgetChars: any;
  budgetTokens: number;
  dropped: StageContextDropEntry[];
  overflowPrevented: boolean;
  selected: StageContextDebugEntry[];
  selectedChars: any;
  selectedEvidencePaths: string[];
  selectedTokens: number;
  stage: AiContextStage;
};

export type StageContextPack = {
  context: string;
  debug: StageContextSelection;
};

type StageContextParams = {
  files: Module[];
  maxTokens?: number;
  preferredPaths?: string[];
  stage: AiContextStage;
};

const STAGE_TOKEN_BUDGETS: Record<AiContextStage, number> = {
  architect: 210_000,
  writer_api: 180_000,
  writer_architecture: 180_000,
  writer_readme: 150_000,
};

const STAGE_FILE_TOKEN_LIMITS: Record<AiContextStage, number> = {
  architect: 4000,
  writer_api: 6000,
  writer_architecture: 5000,
  writer_readme: 3500,
};

function isExampleLike(path: string) {
  return /(^|\/)(example|examples|sample|samples)\//iu.test(path);
}

function isRootManifest(path: string) {
  const parts = normalize(path).split("/");

  return (
    parts[0] != null &&
    parts.length === 1 &&
    PROJECT_POLICY_RULES.manifests.rootFiles.includes(
      parts[0].toLowerCase() as (typeof PROJECT_POLICY_RULES.manifests.rootFiles)[number]
    )
  );
}

function stageAllowsFile(stage: AiContextStage, filePath: string, preferred: boolean) {
  if (ProjectPolicy.isSensitive(filePath)) return false;
  if (ProjectPolicy.isGeneratedFile(filePath) || ProjectPolicy.isAssetFile(filePath)) return false;
  if (preferred) return true;

  const docsLike = ProjectPolicy.isDocsFile(filePath) || isExampleLike(filePath);
  const testLike = ProjectPolicy.isTestFile(filePath);
  const benchmarkLike = ProjectPolicy.isBenchmarkFile(filePath);

  switch (stage) {
    case "architect":
    case "writer_architecture": {
      if (docsLike || testLike || benchmarkLike) return false;
      return (
        ProjectPolicy.isPrimaryArchitecturePath(filePath) ||
        ProjectPolicy.isConfigFile(filePath) ||
        isRootManifest(filePath)
      );
    }
    case "writer_api": {
      return (
        ProjectPolicy.isApiPath(filePath) ||
        ProjectPolicy.isPrimaryArchitecturePath(filePath) ||
        isRootManifest(filePath)
      );
    }
    case "writer_readme": {
      return (
        ProjectPolicy.isConfigFile(filePath) ||
        ProjectPolicy.isPrimaryArchitecturePath(filePath) ||
        isRootManifest(filePath)
      );
    }
  }
}

function scoreFile(stage: AiContextStage, filePath: string, preferred: boolean) {
  let score = getFileScore(filePath);

  if (preferred) score += FILE_CONTEXT_MODIFIERS.preferredFileBonus;
  if (isRootManifest(filePath)) score += FILE_CONTEXT_MODIFIERS.rootManifestBonus;
  if (ProjectPolicy.isPrimaryArchitecturePath(filePath))
    score += FILE_CONTEXT_MODIFIERS.primaryArchitectureBonus;
  if (ProjectPolicy.isConfigFile(filePath)) {
    score +=
      stage === "writer_readme"
        ? FILE_CONTEXT_MODIFIERS.configFileBonusForReadme
        : FILE_CONTEXT_MODIFIERS.configFileBonus;
  }
  if (stage === "writer_api" && ProjectPolicy.isApiPath(filePath))
    score += FILE_CONTEXT_MODIFIERS.apiFileBonus;
  if (stage === "architect" && ProjectPolicy.isApiPath(filePath))
    score += FILE_CONTEXT_MODIFIERS.apiFileSecondaryBonus;
  if ((ProjectPolicy.isDocsFile(filePath) || isExampleLike(filePath)) && !preferred)
    score += FILE_CONTEXT_MODIFIERS.docFilePenalty;
  if (ProjectPolicy.isTestFile(filePath) && !preferred)
    score += FILE_CONTEXT_MODIFIERS.testFilePenalty;

  return score;
}

function buildSelectionReason(stage: AiContextStage, filePath: string, preferred: boolean) {
  if (preferred) return "preferred-evidence";
  if (isRootManifest(filePath)) return "root-manifest";
  if (ProjectPolicy.isConfigFile(filePath))
    return stage === "writer_readme" ? "config-evidence" : "config-support";
  if (stage === "writer_api" && ProjectPolicy.isApiPath(filePath)) return "api-evidence";
  if (ProjectPolicy.isPrimaryArchitecturePath(filePath)) return "primary-architecture";
  return "secondary-support";
}

export async function buildStageContextPack({
  files,
  maxTokens,
  preferredPaths = [],
  stage,
}: StageContextParams): Promise<StageContextPack> {
  const preferredSet = new Set(preferredPaths);
  const budgetTokens = maxTokens ?? STAGE_TOKEN_BUDGETS[stage];
  const perFileTokenLimit = STAGE_FILE_TOKEN_LIMITS[stage];
  const dropped: StageContextDropEntry[] = [];

  const candidates = files
    .map((file) => {
      const lowerPath = file.path.toLowerCase();
      const preferred = preferredSet.has(file.path);

      if (ProjectPolicy.isSensitive(lowerPath)) {
        dropped.push({ path: file.path, reason: "sensitive", score: 0 });
        return null;
      }

      if (!stageAllowsFile(stage, lowerPath, preferred)) {
        dropped.push({ path: file.path, reason: "stage-filter", score: 0 });
        return null;
      }

      return {
        file,
        path: file.path,
        preferred,
        score: scoreFile(stage, lowerPath, preferred),
      };
    })
    .filter((c): c is NonNullable<typeof c> => c !== null)
    .sort((a, b) => b.score - a.score);

  const selected: StageContextDebugEntry[] = [];
  const selectedXml: string[] = [];
  let currentTotalTokens = 0;

  for (const item of candidates) {
    if (currentTotalTokens >= budgetTokens) {
      dropped.push({ path: item.path, reason: "budget", score: item.score });
      continue;
    }

    const cleanedContent = await cleanCodeForAi(item.file.content ?? "", item.path);
    let content = cleanedContent.trim();
    if (!content) {
      dropped.push({ path: item.path, reason: "empty-after-clean", score: item.score });
      continue;
    }

    let fileTokens = await countTokens(content);
    let isTruncated = false;

    if (fileTokens > perFileTokenLimit) {
      content = skeletonizeCode(content);
      fileTokens = await countTokens(content);
      isTruncated = true;
    }

    const xml = `<file path="${escapePromptXmlAttr(item.path)}">\n${escapePromptXmlText(content)}\n</file>`;
    const totalWithXmlTokens = fileTokens + 15;

    if (currentTotalTokens + totalWithXmlTokens > budgetTokens) {
      if (item.preferred) {
        const remainingSpace = budgetTokens - currentTotalTokens - 20;
        if (remainingSpace > 200) {
          content = content.slice(0, remainingSpace * 2) + "\n/* ...emergency truncated... */";
          const emergencyTokens = (await countTokens(content)) + 15;
          addFileToContext(item, buildXml(item.path, content), emergencyTokens, true);
          continue;
        }
      }

      dropped.push({ path: item.path, reason: "secondary-no-budget", score: item.score });
      continue;
    }

    addFileToContext(item, xml, totalWithXmlTokens, isTruncated);
  }

  function addFileToContext(item: any, xml: string, tokens: number, truncated: boolean) {
    selected.push({
      path: item.path,
      reason: buildSelectionReason(stage, item.path.toLowerCase(), item.preferred),
      score: item.score,
      tokens,
      truncated,
    });
    selectedXml.push(xml);
    currentTotalTokens += tokens;
  }

  return {
    context: selectedXml.join("\n\n"),
    debug: {
      budgetChars: undefined,
      budgetTokens,
      dropped,
      overflowPrevented: dropped.some((d) => d.reason === "budget"),
      selected,
      selectedChars: undefined,
      selectedEvidencePaths: selected.map((s) => s.path),
      selectedTokens: currentTotalTokens,
      stage,
    },
  };
}

function buildXml(path: string, content: string) {
  return `<file path="${escapePromptXmlAttr(path)}">\n${escapePromptXmlText(content)}\n</file>`;
}

export async function prepareSmartContext(files: Module[], maxTokens?: number): Promise<string> {
  const result = await buildStageContextPack({
    files,
    maxTokens,
    stage: "architect",
  });
  return result.context;
}

import { normalizeRepoPath } from "@/server/shared/engine/core/common";
import type {
  Module,
  ModuleRef,
  RepositoryEvidence,
} from "@/server/shared/engine/core/discovery.types";
import { REPORT_FOCUS_SECTIONS } from "@/server/shared/engine/core/documentation.types";
import { linguistStyleLabel } from "@/server/shared/engine/core/file-classifier";
import type { RepoMetrics } from "@/server/shared/engine/core/metrics.types";
import { ProjectPolicy } from "@/server/shared/engine/core/project-policy";
import { MAPPER_FILE_SCORING } from "@/server/shared/engine/core/scoring-constants";
import { dumpDebug } from "@/server/shared/lib/debug-logger";
import { getLanguageColor } from "@/server/shared/lib/language-metadata";
import { getFileExtension } from "@/server/shared/lib/path-operations";

const MAX_FILES_IN_TREE = 1000;
const MAX_FOLDER_ROWS = 100;

type MapperFolderAgg = {
  depth: number;
  fileCount: number;
  path: string;
};

function topFolderPrefixes(paths: string[]): MapperFolderAgg[] {
  const counts = new Map<string, number>();
  for (const p of paths) {
    const parts = p.split("/").filter(Boolean);
    if (parts.length <= 1) continue;
    const top = parts[0]!;
    counts.set(top, (counts.get(top) ?? 0) + 1);
  }
  return [...counts.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, MAX_FOLDER_ROWS)
    .map(([top, fileCount]) => ({
      depth: 1,
      fileCount,
      path: top,
    }));
}

function isArchitectureRelevantModule(fileModule: ModuleRef | undefined) {
  if (fileModule == null) return false;
  return ProjectPolicy.isArchitectureRelevantCategories(fileModule.categories);
}

// Local wrapper for linguistStyleLabel with sensible fallback
function fileLanguageLabel(filePath: string): string {
  const ext = getFileExtension(filePath);
  const fallback = ext ? ext.slice(1).toUpperCase() : "Unknown";
  return linguistStyleLabel(filePath, fallback);
}

function isPrimaryArchitectureModule(fileModule: ModuleRef | undefined) {
  if (fileModule == null) return false;
  if (!isArchitectureRelevantModule(fileModule)) return false;
  return ProjectPolicy.isPrimaryArchitectureCategories(fileModule.categories);
}

function buildEvidenceMaps(evidence: RepositoryEvidence, metrics: RepoMetrics) {
  const moduleByPath = new Map(evidence.modules.map((module) => [module.path, module] as const));
  const configPaths = new Set(evidence.configs.map((config) => config.path));
  const apiSourcePaths = new Set([
    ...evidence.routes.map((route) => route.sourcePath),
    ...evidence.routeInventory.sourceFiles,
    ...(metrics.openapiInventory?.sourceFiles ?? []),
  ]);
  const primaryEntrypointPaths = new Set(
    evidence.entrypoints
      .filter((entrypoint) => entrypoint.kind === "library" || entrypoint.kind === "runtime")
      .map((entrypoint) => entrypoint.path)
  );

  return {
    apiSourcePaths,
    configPaths,
    moduleByPath,
    primaryEntrypointPaths,
  };
}

function fileRoleHint(
  filePath: string,
  module: ModuleRef | undefined,
  isApiHeuristic: boolean,
  isConfig: boolean
): string {
  if (isConfig) return "config";
  if (isApiHeuristic) return "api";
  if (module?.categories.includes("test") ?? false) return "test";
  const lower = filePath.toLowerCase();
  if (lower.includes("/server/") || lower.includes("/api/")) return "server";
  if (lower.includes("/client/") || lower.includes("/ui/") || lower.includes("/components/")) {
    return "ui";
  }
  if (isPrimaryArchitectureModule(module)) return "source";
  return (module?.categories.includes("runtime-source") ?? false) ? "runtime-support" : "source";
}

function scoreFileCandidate(params: {
  fileModule: ModuleRef | undefined;
  isApiHeuristic: boolean;
  isConfig: boolean;
  lines: number;
  path: string;
  primaryEntrypointPaths: Set<string>;
}) {
  let score =
    Math.min(params.lines, MAPPER_FILE_SCORING.maxLinesForLineScore) *
    MAPPER_FILE_SCORING.lineMultiplier;

  if (params.primaryEntrypointPaths.has(params.path))
    score += MAPPER_FILE_SCORING.primaryEntrypointBonus;
  if (params.isConfig) score += MAPPER_FILE_SCORING.configFileBonus;
  if (params.isApiHeuristic) score += MAPPER_FILE_SCORING.apiHeuristicBonus;
  if (isPrimaryArchitectureModule(params.fileModule))
    score += MAPPER_FILE_SCORING.primaryArchitectureBonus;
  else if (isArchitectureRelevantModule(params.fileModule))
    score += MAPPER_FILE_SCORING.secondaryArchitectureBonus;

  return score;
}

export function buildMapperSkeleton(
  files: Module[],
  metrics: RepoMetrics,
  evidence: RepositoryEvidence
): string {
  const normalized = files.map((f) => ({
    content: f.content,
    path: normalizeRepoPath(f.path),
  }));

  const { apiSourcePaths, configPaths, moduleByPath, primaryEntrypointPaths } = buildEvidenceMaps(
    evidence,
    metrics
  );

  const scored = normalized.map((file) => {
    const lines = file.content?.split(/\r?\n/u).length;

    const fileModule = moduleByPath.get(file.path);
    const isConfig = configPaths.has(file.path);
    const isApiHeuristic = apiSourcePaths.has(file.path) || (fileModule?.routeCount ?? 0) > 0;

    return {
      approxLines: lines,
      entry: {
        approxLines: lines,
        isApiHeuristic,
        isConfig,
        linguistLabel: fileLanguageLabel(file.path),
        path: file.path,
        roleHint: fileRoleHint(file.path, fileModule, isApiHeuristic, isConfig),
      } satisfies Module,
      score: scoreFileCandidate({
        fileModule,
        isApiHeuristic,
        isConfig,
        lines: lines ?? 0,
        path: file.path,
        primaryEntrypointPaths,
      }),
    };
  });

  scored.sort((a, b) => b.score - a.score);
  const picked = scored.slice(0, MAX_FILES_IN_TREE).map((s) => s.entry);
  const allPaths = normalized.map((f) => f.path);

  const graphReliability = evidence.dependencyGraph;
  const openapiInventory = metrics.openapiInventory ?? {
    estimatedOperations: 0,
    pathPatterns: [],
    sourceFiles: [],
  };
  const routeInventory = metrics.routeInventory ?? evidence.routeInventory;
  const churnHotspots = metrics.churnHotspots ?? [];
  const tsStaticHints = metrics.tsStaticHints ?? [];

  const payload = {
    analysisCoverage: metrics.analysisCoverage,
    churnHotspots: churnHotspots.slice(0, 8),
    dependencyHotspots: metrics.dependencyHotspots.slice(0, 8),
    entrypointDetails: evidence.entrypoints,
    entrypoints: Array.from(primaryEntrypointPaths).sort((left, right) =>
      left.localeCompare(right)
    ),
    fileCategoryBreakdown: evidence.fileCategoryBreakdown,
    files: picked,
    folderSummary: topFolderPrefixes(allPaths),
    frameworkFacts: evidence.frameworkFacts,
    graphReliability,
    languages: metrics.languages.map((l) => ({
      color: l.color || getLanguageColor(l.name),
      lines: l.lines,
      name: l.name,
    })),
    modules: evidence.modules
      .filter((module) => isArchitectureRelevantModule(module))
      .sort(
        (left, right) =>
          right.apiSurface - left.apiSurface ||
          right.routeCount - left.routeCount ||
          right.exports - left.exports ||
          left.path.localeCompare(right.path)
      )
      .slice(0, 36)
      .map((module) => ({
        apiSurface: module.apiSurface,
        categories: module.categories,
        exports: module.exports,
        parseTier: module.parseTier,
        path: module.path,
        routeCount: module.routeCount,
      })),
    openapiInventory,
    reportFocus: [...REPORT_FOCUS_SECTIONS],
    routeInventory,
    techStack: metrics.techStack.slice(0, 24),
    tsStaticHints: tsStaticHints.slice(0, 12),
  };

  void dumpDebug("mapper-skeleton-payload", payload);

  return JSON.stringify(payload, null, 2);
}

