});

import { DocType } from "@prisma/client";

import type { ReportSectionKind } from "@/server/shared/engine/core/documentation.types";
import { DOC_PRIORITY_WEIGHTS } from "@/server/shared/engine/core/scoring-constants";
import { hasText } from "@/server/shared/lib/string-utils";

export const ALL_DOC_TYPES = [
  DocType.README,
  DocType.API,
  DocType.ARCHITECTURE,
  DocType.CONTRIBUTING,
  DocType.CHANGELOG,
] as const satisfies readonly DocType[];

export const DOC_SECTION_DEPENDENCIES: Record<DocType, readonly ReportSectionKind[]> = {
  [DocType.API]: ["api_reference"],
  [DocType.ARCHITECTURE]: ["architecture", "risks", "onboarding"],
  [DocType.CHANGELOG]: [],
  [DocType.CODE_DOC]: [],
  [DocType.CONTRIBUTING]: ["overview", "onboarding"],
  [DocType.README]: ["overview", "architecture"],
};

const DOC_WEIGHTS: Record<DocType, number> = {
  [DocType.API]: DOC_PRIORITY_WEIGHTS.api,
  [DocType.ARCHITECTURE]: DOC_PRIORITY_WEIGHTS.architecture,
  [DocType.CHANGELOG]: DOC_PRIORITY_WEIGHTS.changelog,
  [DocType.CODE_DOC]: 0,
  [DocType.CONTRIBUTING]: DOC_PRIORITY_WEIGHTS.contributing,
  [DocType.README]: DOC_PRIORITY_WEIGHTS.readme,
};

const SNAPSHOT_KEY_TO_DOC_TYPE: Record<string, DocType> = {
  api: DocType.API,
  architecture: DocType.ARCHITECTURE,
  changelog: DocType.CHANGELOG,
  contributing: DocType.CONTRIBUTING,
  readme: DocType.README,
};

type GeneratedDocsInput = {
  generatedApiMarkdown?: string;
  generatedArchitecture?: string;
  generatedChangelog?: string;
  generatedContributing?: string;
  generatedReadme?: string;
  swaggerYaml?: string;
};

/**
 * Расчет скоринга полноты документации.
 */
export function calculateDocumentationOutputScore(docs: GeneratedDocsInput) {
  let score = 0;
  let generatedCount = 0;

  const snapshot = {
    api: hasText(docs.generatedApiMarkdown),
    architecture: hasText(docs.generatedArchitecture),
    changelog: hasText(docs.generatedChangelog),
    contributing: hasText(docs.generatedContributing),
    readme: hasText(docs.generatedReadme),
  };

  Object.entries(snapshot).forEach(([key, isGenerated]) => {
    if (isGenerated) {
      const type = SNAPSHOT_KEY_TO_DOC_TYPE[key];
      if (type != null) {
        score += DOC_WEIGHTS[type];
        generatedCount++;
      }
    }
  });

  return {
    generatedCount,
    score,
    snapshot,
    totalCount: ALL_DOC_TYPES.length,
  };
}

import { task } from "@trigger.dev/sdk";
import { TRPCError } from "@trpc/server";

import { generatedFixService } from "@/server/entities/pr-analysis/api/generated-fix.service";
import { prisma } from "@/server/shared/infrastructure/db";
import { logger } from "@/server/shared/infrastructure/logger";
import { redisClient } from "@/server/shared/infrastructure/redis";
import { REDIS_CONFIG } from "@/server/shared/lib/redis";

import { FixService } from "../../pr-analysis/lib/fix-generator";
import type { FindingForFix } from "../../pr-analysis/model/pr-types";

export const generateFixTask = task({
  id: "generate-fix",
  run: async (payload: {
    fileContents: Record<string, string>;
    findings: FindingForFix[];
    fixId: string;
    prAnalysisId?: string;
    repoId: string;
    userId: number;
  }) => {
    const fixService = new FixService();

    try {
      const repo = await prisma.repo.findUnique({
        where: { publicId: payload.repoId },
      });

      if (repo == null) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Repository not found",
        });
      }

      await generatedFixService.updateStatus(prisma, payload.fixId, "GENERATING");

      // Create fix record (metadata only, no code/diffs stored)
      const fixResult = await fixService.createFixFromAnalysis({
        fileContents: payload.fileContents,
        findings: payload.findings,
        prAnalysisId: payload.prAnalysisId,
        repoContext: { language: repo.language ?? "typescript" },
        repoId: repo.id,
      });

      const cacheKey = REDIS_CONFIG.keys.fixResult(payload.fixId);
      await redisClient.set(cacheKey, fixResult, { ex: REDIS_CONFIG.ttl.fixResult });

      await generatedFixService.updateStatus(prisma, payload.fixId, "COMPLETED");

      logger.info({
        fixId: payload.fixId,
        msg: "fix_created",
        repoId: payload.repoId,
      });

      return { fixId: payload.fixId, success: true };
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      const cacheKey = REDIS_CONFIG.keys.fixResult(payload.fixId);
      await redisClient.set(cacheKey, { error: errorMsg }, { ex: REDIS_CONFIG.ttl.fixResult });

      await generatedFixService.updateStatus(prisma, payload.fixId, "FAILED");
      throw error;
    }
  },
});

import type { InstallationEvent } from "@octokit/webhooks-types";

import { prisma } from "@/server/shared/infrastructure/db";
import { logger } from "@/server/shared/infrastructure/logger";
import type { InstallationTargetTypeType, RepositorySelectionType } from "@/generated/zod";

export async function handleInstallationEvent(payload: InstallationEvent): Promise<void> {
  const action = payload.action;
  const installation = payload.installation;
  const instIdBigInt = BigInt(installation.id);

  const githubLogin = installation.account.login.slice(0, 39);
  const githubAvatar = installation.account.avatar_url;
  const githubRepoSelection =
    installation.repository_selection.toUpperCase() as RepositorySelectionType;
  const githubTargetType = installation.target_type.toUpperCase() as InstallationTargetTypeType;
  const githubHtmlUrl = installation.html_url;

  try {
    if (action === "created") {
      await prisma.githubInstallation.upsert({
        create: {
          accountAvatar: githubAvatar,
          accountLogin: githubLogin,
          appId: installation.app_id,
          htmlUrl: githubHtmlUrl,
          id: instIdBigInt,
          repositorySelection: githubRepoSelection,
          targetId: BigInt(installation.target_id),
          targetType: githubTargetType,
          userId: null,
        },
        update: {
          accountAvatar: githubAvatar,
          accountLogin: githubLogin,
          htmlUrl: githubHtmlUrl,
          isSuspended: false,
          repositorySelection: githubRepoSelection,
        },
        where: { id: instIdBigInt },
      });
      logger.info({
        installationId: instIdBigInt.toString(),
        msg: "GitHub installation created via webhook",
      });
    }

    if (action === "deleted") {
      const result = await prisma.githubInstallation.deleteMany({ where: { id: instIdBigInt } });
      logger.info({
        affectedRows: result.count,
        installationId: instIdBigInt.toString(),
        msg: "GitHub installation deleted via webhook",
      });
    }

    if (action === "suspend") {
      await prisma.githubInstallation.updateMany({
        data: { isSuspended: true },
        where: { id: instIdBigInt },
      });
      logger.info({
        installationId: instIdBigInt.toString(),
        msg: "GitHub installation suspended",
      });
    }

    if (action === "unsuspend") {
      await prisma.githubInstallation.updateMany({
        data: { isSuspended: false },
        where: { id: instIdBigInt },
      });
      logger.info({
        installationId: instIdBigInt.toString(),
        msg: "GitHub installation unsuspended",
      });
    }

    if (action === "new_permissions_accepted") {
      logger.info({
        installationId: instIdBigInt.toString(),
        msg: "GitHub App permissions updated by user",
      });
    }
  } catch (error) {
    logger.error({ error, msg: "Webhook DB Processing Error" });
    throw error;
  }
}

