import type { RepositoryEvent } from "@octokit/webhooks-types";

import { prisma } from "@/server/shared/infrastructure/db";
import { logger } from "@/server/shared/infrastructure/logger";

import { syncRepoMetadata } from "./sync-repo-metadata";

export async function handleRepositoryEvent(payload: RepositoryEvent): Promise<void> {
  const { action, repository } = payload;

  logger.info({
    action,
    githubId: repository.id,
    msg: "repository_webhook_received",
    repoName: repository.full_name,
  });

  try {
    if (action === "deleted") {
      const result = await prisma.repo.deleteMany({
        where: { githubId: repository.id },
      });

      logger.info({
        affectedRows: result.count,
        githubId: repository.id,
        msg: "repository_deleted_in_db",
      });
      return;
    }

    if (action === "archived") {
      logger.info({ githubId: repository.id, msg: "repository_archived" });
    }

    const syncActions = [
      "renamed",
      "edited",
      "privatized",
      "publicized",
      "archived",
      "transferred",
      "unarchived",
    ];
    if (syncActions.includes(action)) {
      await syncRepoMetadata(repository);

      logger.info({
        action,
        githubId: repository.id,
        msg: "repository_state_updated",
      });
    }
  } catch (error) {
    logger.error({ error, msg: "repository_webhook_error" });
    throw error;
  }
}

import type { Repository } from "@octokit/webhooks-types";
import { Visibility } from "@prisma/client";

import { prisma } from "@/server/shared/infrastructure/db";
import { logger } from "@/server/shared/infrastructure/logger";

/**
 * Оппортунистическое обновление данных репозитория из любого GitHub payload.
 * Вызывается без `await` в основных хендлерах, чтобы не блокировать ответ гитхабу.
 */
export async function syncRepoMetadata(repository: Repository): Promise<void> {
  try {
    let repoVisibility = Visibility.PRIVATE as Visibility;
    if (repository.visibility === "public" || repository.private === false) {
      repoVisibility = Visibility.PUBLIC;
    } else if (repository.visibility === "internal") {
      repoVisibility = Visibility.PRIVATE;
    }

    const licenseName = repository.license
      ? repository.license.spdx_id !== "NOASSERTION"
        ? repository.license.spdx_id
        : repository.license.name
      : null;

    let pushedAtDate: Date | undefined = undefined;
    if (repository.pushed_at != null) {
      if (typeof repository.pushed_at === "number") {
        pushedAtDate = new Date(repository.pushed_at * 1000);
      } else {
        pushedAtDate = new Date(repository.pushed_at);
      }
    }

    const result = await prisma.repo.updateMany({
      data: {
        defaultBranch: repository.default_branch,
        description: repository.description?.slice(0, 1000) ?? null,
        forks: repository.forks_count,
        language: repository.language,
        license: licenseName,
        name: repository.name,
        openIssues: repository.open_issues_count,
        owner: repository.owner.login,
        ownerAvatarUrl: repository.owner.avatar_url,
        pushedAt: pushedAtDate,
        size: repository.size,
        stars: repository.stargazers_count,
        topics: repository.topics,
        url: repository.html_url,
        visibility: repoVisibility,
      },
      where: { githubId: repository.id },
    });

    if (result.count > 0) {
      logger.debug({
        affectedRows: result.count,
        githubId: repository.id,
        msg: "repo_metadata_opportunistically_synced",
        repoName: repository.full_name,
      });
    }
  } catch (error) {
    logger.error({
      error: error instanceof Error ? error.message : String(error),
      githubId: repository.id,
      msg: "failed_to_sync_repo_metadata",
    });
  }
}

import type { Octokit } from "@octokit/rest";
import type { PRCommentStyle } from "@prisma/client";

import { logger } from "@/server/shared/infrastructure/logger";

import type { PRFinding } from "../model/pr-types";

/**
 * Formats PR findings into GitHub comment bodies
 */
export class CommentFormatter {
  static formatFinding(finding: PRFinding, style: PRCommentStyle): string {
    if (style === "CONCISE") {
      return `**${finding.type.toUpperCase()}** (${finding.severity}, score ${finding.score}/10)\n${finding.message}`;
    }

    let body = `## ${finding.title}\n\n`;
    body += `**Type:** ${finding.type} | **Severity:** ${finding.severity} | **Score:** ${finding.score}/10\n\n`;
    body += `${finding.message}\n\n`;

    if (finding.suggestion != null) {
      const cleanSuggestion = finding.suggestion.trim().startsWith("```")
        ? finding.suggestion.trim()
        : `\`\`\`\n\${finding.suggestion}\n\`\`\``;
      body += `**Suggestion:**\n${cleanSuggestion}\n\n`;
    }

    if (finding.codeSnippet != null) {
      const cleanSnippet = finding.codeSnippet.trim().startsWith("```")
        ? finding.codeSnippet.trim()
        : `\`\`\`\n${finding.codeSnippet}\n\`\`\``;
      body += `**Code:**\n${cleanSnippet}\n`;
    }

    return body;
  }
}

/**
 * Posts findings as GitHub comments via Octokit
 */
export class GitHubCommentPoster {
  constructor(private octokit: Octokit) {}

  /**
   * Post PR comments in batch (single review with all findings)
   */
  async postComments(
    owner: string,
    repo: string,
    prNumber: number,
    commitId: string,
    findings: PRFinding[],
    style: PRCommentStyle
  ): Promise<Array<{ commentId: number; finding: PRFinding }>> {
    if (findings.length === 0) return [];

    const reviewComments = findings.map((finding) => ({
      body: CommentFormatter.formatFinding(finding, style),
      line: finding.line,
      path: finding.file,
      side: "RIGHT" as const,
    }));

    try {
      const review = await this.octokit.rest.pulls.createReview({
        comments: reviewComments,
        commit_id: commitId,
        event: "COMMENT",
        owner,
        pull_number: prNumber,
        repo,
      });

      logger.debug({
        commentCount: reviewComments.length,
        msg: "pr_review_posted",
        prNumber,
        reviewId: review.data.id,
      });

      return findings.map((finding) => ({ commentId: review.data.id, finding }));
    } catch (error) {
      logger.error({
        error: error instanceof Error ? error.message : String(error),
        msg: "pr_review_post_failed",
        prNumber,
        reviewCommentsSummary: reviewComments.map((rc) => ({
          line: rc.line,
          path: rc.path,
          side: rc.side,
        })),
      });
      return [];
    }
  }

  /**
   * Update existing PR comment
   */
  async updateComment(
    owner: string,
    repo: string,
    commentId: number,
    body: string
  ): Promise<boolean> {
    try {
      await this.octokit.rest.pulls.updateReviewComment({
        body,
        comment_id: commentId,
        owner,
        repo,
      });
      return true;
    } catch (error) {
      logger.error({
        commentId,
        error: error instanceof Error ? error.message : String(error),
        msg: "pr_comment_update_failed",
      });
      return false;
    }
  }
}

import { compact, meanBy, sumBy, uniqBy } from "es-toolkit";
import parseGitDiff from "parse-git-diff";
import { normalize } from "pathe";
import pm from "picomatch";

import { PROJECT_POLICY_RULES } from "@/server/shared/engine/core/project-policy-rules";
import { AI_POLICY_CONSTANTS } from "@/server/shared/engine/core/scoring-constants";
import { logger } from "@/server/shared/infrastructure/logger";
import { prAnalysisLogger } from "@/server/shared/lib/pr-analysis-logger";

import type { DifferentialAnalysisResult, PRAnalysisConfig, PRFinding } from "../model/pr-types";

type PRDiffInfo = {
  baseSha: string;
  changedFiles: Array<{
    additions: number;
    changes_start?: number;
    deletions: number;
    filename: string;
    patch?: string;
  }>;
  headSha: string;
  owner: string;
  prNumber: number;
  repoName: string;
};

/**
 * Analyzes PR diff using reduced token budget (30-50K vs 210K for full analysis)
 * Runs Sentinel phase for security findings, Mapper for dependency impact
 */
export class DifferentialAnalyzer {
  private config: PRAnalysisConfig;
  private readonly isExcluded: (path: string) => boolean;

  private mapScoreToSeverity(score: number): PRFinding["severity"] {
    const thresholds = AI_POLICY_CONSTANTS.PR_ANALYSIS.SEVERITY_THRESHOLDS;

    if (score >= thresholds.CRITICAL) return "CRITICAL";
    if (score >= thresholds.HIGH) return "HIGH";
    if (score >= thresholds.MEDIUM) return "MEDIUM";
    return "LOW";
  }

  constructor(config: PRAnalysisConfig) {
    this.config = config;
    this.isExcluded = pm(config.excludePatterns);
  }

  /**
   * Main entry point for PR differential analysis
   */
  async analyzePRDiff(diffInfo: PRDiffInfo): Promise<DifferentialAnalysisResult> {
    const startTime = Date.now();
    logger.info({
      changedFiles: diffInfo.changedFiles.length,
      focusAreas: this.config.focusAreas,
      msg: "pr_differential_analysis_started",
      owner: diffInfo.owner,
      prNumber: diffInfo.prNumber,
      repoName: diffInfo.repoName,
      tokenBudget: this.config.tokenBudget,
    });

    try {
      const relevantFiles = diffInfo.changedFiles.filter((f) => {
        const normalizedPath = normalize(f.filename);
        if (this.isExcluded(normalizedPath)) return false;
        return f.additions + f.deletions <= 1000;
      });

      logger.debug({
        excluded: diffInfo.changedFiles.length - relevantFiles.length,
        msg: "pr_files_filtered",
        relevant: relevantFiles.length,
        total: diffInfo.changedFiles.length,
      });

      if (relevantFiles.length === 0) {
        logger.info({ msg: "pr_no_relevant_files", prNumber: diffInfo.prNumber });
        return {
          analyzedLines: 0,
          changedFiles: 0,
          findings: [],
          riskScore: 0,
          totalDuration: Date.now() - startTime,
        };
      }

      // Step 2: Run Sentinel phase on changed code (security, obvious bugs)
      const sentinelFindings = this.runSentinelPhase(relevantFiles, diffInfo.prNumber);

      // Step 3: Mapper
      const mapperFindings = this.runMapperPhase(relevantFiles, diffInfo.prNumber);

      // Step 5: Combine and score findings
      const allFindings = uniqBy(
        [...sentinelFindings, ...mapperFindings],
        (f) => `${f.file}:${f.line}:${f.type}`
      );
      const scoredFindings = this.applyFocusFilters(allFindings);
      const riskScore = this.calculateRiskScore(scoredFindings);

      const duration = Date.now() - startTime;
      logger.info({
        duration,
        findings: scoredFindings.length,
        msg: "pr_differential_analysis_completed",
        prNumber: diffInfo.prNumber,
        riskScore,
      });

      return {
        analyzedLines: sumBy(relevantFiles, (f) => f.additions + f.deletions),
        changedFiles: relevantFiles.length,
        findings: scoredFindings,
        riskScore,
        totalDuration: duration,
      };
    } catch (error) {
      logger.error({
        error: error instanceof Error ? error.message : String(error),
        msg: "pr_differential_analysis_failed",
        prNumber: diffInfo.prNumber,
      });
      throw error;
    }
  }

  private runSentinelPhase(files: PRDiffInfo["changedFiles"], prNumber: number): PRFinding[] {
    const findings: PRFinding[] = [];
    const { patterns, todoPatterns } = PROJECT_POLICY_RULES.security;

    for (const file of files) {
      if (file.patch == null) continue;

      const parsedDiff = parseGitDiff(file.patch);

      for (const parsedFile of parsedDiff.files) {
        for (const chunk of parsedFile.chunks) {
          if (!("changes" in chunk)) continue;

          for (const change of chunk.changes) {
            if (change.type !== "AddedLine") continue;

            const newLineNum = change.lineAfter;
            const lineContent = change.content;

            if (patterns.test(lineContent)) {
              findings.push({
                codeSnippet: lineContent.trim(),
                file: file.filename,
                line: newLineNum,
                message: "Code pattern may introduce security vulnerability",
                score: 8,
                severity: this.mapScoreToSeverity(8),
                suggestion: "Review and validate input handling",
                title: "Potential security issue detected",
                type: "security",
              });
            }

            if (todoPatterns.test(lineContent)) {
              findings.push({
                codeSnippet: lineContent.trim(),
                file: file.filename,
                line: newLineNum,
                message: "Incomplete implementation marker",
                score: 2,
                severity: this.mapScoreToSeverity(2),
                suggestion: "Complete or remove TODO",
                title: "TODO/FIXME comment found",
                type: "style",
              });
            }
          }
        }
      }
    }

    prAnalysisLogger.sentinelPhaseCompleted(prNumber, prNumber, findings.length, 0);
    return findings;
  }

  private runMapperPhase(files: PRDiffInfo["changedFiles"], prNumber: number): PRFinding[] {
    const findings: PRFinding[] = compact(
      files.map((file) => {
        if (file.patch == null) return null;

        const addedLines = file.patch.split("\n").filter((l) => l.startsWith("+")).length;
        const complexityRatio = addedLines / Math.max(file.additions, 1);

        if (complexityRatio > 2 || addedLines > 300) {
          return {
            file: file.filename,
            line: 1,
            message: `Файл содержит ${addedLines} новых строк. Высокая плотность изменений затрудняет ревью.`,
            score: 5,
            severity: this.mapScoreToSeverity(5),
            suggestion: "Разбейте изменения на несколько логических модулей или PR.",
            title: "Высокая сложность изменений",
            type: "performance",
          } satisfies PRFinding;
        }
        return null;
      })
    );

    prAnalysisLogger.mapperPhaseCompleted(prNumber, prNumber, findings.length, 0);
    return findings;
  }

  private applyFocusFilters(findings: PRFinding[]): PRFinding[] {
    if (this.config.focusAreas.length === 0) return findings;

    return findings.filter((f) => (this.config.focusAreas as string[]).includes(f.type));
  }

  private calculateRiskScore(findings: PRFinding[]): number {
    if (findings.length === 0) return 0;

    const avgSeverity = meanBy(findings, (f) => f.score);
    return Math.min(10, Math.ceil(avgSeverity));
  }
}

import diff_match_patch from "diff-match-patch";
