    fileContents: Record<string, string>
  ): FixRecommendation[] {
    const findingsByType = groupBy(findings, (f) => f.type);

    return Object.entries(findingsByType)
      .map(([type, typeFindings]) => {
        if (typeFindings.length === 0) return null;

        const config = this.getFixConfig(type, typeFindings.length);
        const affectedFiles = unique(typeFindings.map((f) => f.file));

        const fixedFiles: FixedFileContent[] = affectedFiles.map((filePath) => ({
          filePath,
          newContent: "",
        }));

        const diffs = this.generateDiffsFromContent(fileContents, fixedFiles);

        return {
          branch: `fix/${type}-${Date.now()}`,
          description: config.description,
          diffs,
          estimatedImpact: config.estimatedImpact,
          fixedFiles,
          title: config.title,
        };
      })
      .filter((fix): fix is FixRecommendation => fix !== null);
  }

  private static getFixConfig(type: string, count: number) {
    const map: Record<string, { description: string; estimatedImpact: number; title: string }> = {
      complexity: {
        description: `Refactors ${count} complex function(s)`,
        estimatedImpact: 40,
        title: "Reduce Complexity",
      },
      performance: {
        description: `Improves performance in ${count} location(s)`,
        estimatedImpact: 60,
        title: "Optimize Performance",
      },
      security: {
        description: `Addresses ${count} security vulnerability(ies) found during analysis`,
        estimatedImpact: 85,
        title: "Fix Security Issues",
      },
      style: {
        description: `Applies consistent code style to ${count} file(s)`,
        estimatedImpact: 20,
        title: "Code Style & Formatting",
      },
    };

    return (
      map[type] ?? {
        description: `Automated fixes for ${count} ${type} findings`,
        estimatedImpact: 30,
        title: `Fix ${type} issues`,
      }
    );
  }

  private static generateDiffsFromContent(
    originalContents: Record<string, string>,
    fixedFiles: FixedFileContent[]
  ): GeneratedDiff[] {
    return FixGenerator.generateDiffsFromContentPublic(originalContents, fixedFiles);
  }

  /**
   * Генерирует компактные патчи с помощью Google Diff-Match-Patch с полной поддержкой типов
   */
  static generateDiffsFromContentPublic(
    originalContents: Record<string, string>,
    fixedFiles: FixedFileContent[]
  ): GeneratedDiff[] {
    return fixedFiles.map((file) => {
      const original = originalContents[file.filePath] ?? "";
      const newContent = file.newContent;

      const diffs = dmp.diff_main(original, newContent);

      dmp.diff_cleanupSemantic(diffs);

      const patches = dmp.patch_make(original, diffs);
      const patchText = dmp.patch_toText(patches);

      let additions = 0;
      let deletions = 0;

      for (const patchItem of patches) {
        const typedPatch = patchItem as unknown as diff_match_patch.patch_obj;

        if (Array.isArray(typedPatch.diffs)) {
          for (const [operation, text] of typedPatch.diffs) {
            if (operation === 1) {
              additions += text.split("\n").length;
            }
            if (operation === -1) {
              deletions += text.split("\n").length;
            }
          }
        }
      }

      return {
        additions,
        deletions,
        filePath: file.filePath,
        patch: patchText,
      };
    });
  }
}

export class FixService {
  private static buildFixPrompt(
    findings: FindingInput[],
    fileContents: Record<string, string>
  ): string {
    const findingsByFile = groupBy(findings, (f) => f.file);
    const findingDetails = Object.entries(findingsByFile)
      .map(([filePath, fileFindings]) => {
        const content = fileContents[filePath] ?? "(file not provided)";
        const issues = fileFindings
          .map((f) => `  - Line ${f.line} (${f.type}): ${f.suggestion ?? "Issue detected"}`)
          .join("\n");
        return `\n## File: ${filePath}\n${issues}\n\nOriginal:\n\`\`\`\n${content}\n\`\`\``;
      })
      .join("\n");

    return `You are a professional code fixer. Analyze the detected issues in each file and provide the full fixed content.

${findingDetails}

For each file with issues, provide the COMPLETE fixed file content wrapped in:
<file path="filepath">
...full file content here...
</file>

Ensure:
1. Fixed content maintains the original file structure and imports
2. Only necessary changes to address the issues
3. All line numbers and syntax are correct
4. No partial content - always provide complete files`;
  }

  private static parseFixedCodeResponse(response: string): Record<string, string> {
    const fixedCode: Record<string, string> = {};

    FILE_TAG_REGEX.lastIndex = 0;
    let match;

    while ((match = FILE_TAG_REGEX.exec(response)) !== null) {
      const filePath = match[1]!.trim();
      let content = match[2]!.trim();

      content = content
        .replace(MARKDOWN_CODE_WRAP_PREFIX_REGEX, "")
        .replace(MARKDOWN_CODE_WRAP_SUFFIX_REGEX, "");

      if (filePath && content) {
        fixedCode[filePath] = content;
      }
    }

    return fixedCode;
  }

  async createFixFromAnalysis(input: {
    fileContents: Record<string, string>;
    findings: FindingForFix[];
    prAnalysisId?: string;
    repoContext: { framework?: string; language: string };
    repoId: number;
  }): Promise<{
    branch: string;
    diffs: GeneratedDiff[];
    estimatedImpact: number;
    fixedFiles: FixedFileContent[];
    title: string;
  }> {
    const recommendations = FixGenerator.generateFixRecommendations(
      input.findings,
      input.fileContents
    );

    if (recommendations.length === 0) {
      throw new Error("No fix recommendations generated");
    }

    const primary = recommendations[0]!;

    try {
      const fixPrompt = FixService.buildFixPrompt(input.findings, input.fileContents);

      const aiResponse = await callWithFallback<string>({
        attemptMetadata: {
          operation: "generate-fix",
          prAnalysisId: input.prAnalysisId,
          repoId: input.repoId,
        },
        maxOutputTokens: 65_536,
        models: AI_MODELS.POWERFUL,
        outputSchema: null,
        prompt: fixPrompt,
        providerOptions: {
          google: { safetySettings: SAFETY_SETTINGS },
        },
        system:
          'You are an expert code fixer. Provide complete, syntactically correct fixed file content. Return ONLY the fixed code wrapped in <file path="filepath"> tags.',
        taskType: "reasoning",
      });

      const fixedCodeMap = FixService.parseFixedCodeResponse(aiResponse);

      const fixedFiles = primary.fixedFiles.map((file) => ({
        filePath: file.filePath,
        newContent: fixedCodeMap[file.filePath] ?? file.newContent,
      }));

      const validFixedFiles = fixedFiles.filter((f) => f.newContent.length > 0);

      if (validFixedFiles.length === 0) {
        throw new Error("AI failed to generate any fixed file content");
      }

      const diffs = FixGenerator.generateDiffsFromContentPublic(
        input.fileContents,
        validFixedFiles
      );

      logger.info({
        branch: primary.branch,
        fixedFileCount: validFixedFiles.length,
        impact: primary.estimatedImpact,
        msg: "fix_generated_from_ai",
        repoId: input.repoId,
        title: primary.title,
      });

      return {
        branch: primary.branch,
        diffs,
        estimatedImpact: primary.estimatedImpact,
        fixedFiles: validFixedFiles,
        title: primary.title,
      };
    } catch (error) {
      logger.error({
        error: error instanceof Error ? error.message : String(error),
        msg: "fix_generation_failed",
        prAnalysisId: input.prAnalysisId,
        repoId: input.repoId,
      });
      throw error;
    }
  }

  async applyFix(
    octokit: OctokitInstance,
    input: {
      branch: string;
      defaultBranch: string;
      fixedFiles: FixedFileContent[];
      fixId: string;
      owner: string;
      repoId: string;
      repoName: string;
      title: string;
    }
  ): Promise<{ prNumber: number; prUrl: string }> {
    const { branch, defaultBranch, fixedFiles, owner, repoName, title } = input;

    logger.info({
      branch: input.branch,
      fixId: input.fixId,
      msg: "fix_applying",
      repoId: input.repoId,
    });

    const fileChanges: Record<string, string> = {};
    for (const file of fixedFiles) {
      fileChanges[file.filePath] = file.newContent;
    }

    try {
      const pr = await octokit.createPullRequest({
        base: defaultBranch,
        body: "This PR was automatically generated by Doxynix using Google Fuzzy Diff-Match-Patch to address detected issues.",
        changes: [
          {
            commit: title,
            files: fileChanges,
          },
        ],
        head: branch,
        owner,
        repo: repoName,
        title,
      });

      if (pr == null) {
        throw new Error("Failed to create pull request: received null response");
      }

      logger.info({
        branch: input.branch,
        fixId: input.fixId,
        msg: "fix_applied",
        prNumber: pr.data.number,
        repoId: input.repoId,
      });

      return {
        prNumber: pr.data.number,
        prUrl: pr.data.html_url,
      };
    } catch (error) {
      logger.error({
        branch: input.branch,
        error: error instanceof Error ? error.message : String(error),
        fixId: input.fixId,
        msg: "fix_apply_failed",
        repoId: input.repoId,
      });
      throw error;
    }
  }
}

import { PRCommentStyle, PRFocusArea } from "@prisma/client";

import { clamp } from "@/server/shared/engine/core/common";
import { PATH_PATTERNS } from "@/server/shared/engine/core/project-policy-rules";
import type { DbClient } from "@/server/shared/infrastructure/db";

import type { PRAnalysisConfig } from "../model/pr-types";

const SYSTEM_IGNORES = [
  ...PATH_PATTERNS.IGNORE,
  ...PATH_PATTERNS.GENERATED,
  ...PATH_PATTERNS.ASSET,
];

const DEFAULT_PR_CONFIG: PRAnalysisConfig = {
  ciSkip: false,
  commentStyle: PRCommentStyle.DETAILED,
  enabled: false,
  excludePatterns: SYSTEM_IGNORES,
  focusAreas: [PRFocusArea.SECURITY, PRFocusArea.PERFORMANCE],
  tokenBudget: 30_000,
};

export class PRConfigService {
  static async getConfig(repoId: string, db: DbClient): Promise<PRAnalysisConfig> {
    const config = await db.pullRequestAnalysisConfig.findFirst({
      where: { repo: { publicId: repoId } },
    });

    if (config == null) return DEFAULT_PR_CONFIG;

    return {
      ciSkip: config.ciSkip,
      commentStyle: config.commentStyle,
      enabled: config.enabled,
      excludePatterns: Array.from(new Set([...SYSTEM_IGNORES, ...config.excludePatterns])),
      focusAreas: config.focusAreas,
      tokenBudget: config.tokenBudget,
    };
  }

  static async updateConfig(
    repoId: string,
    config: Partial<PRAnalysisConfig>,
    db: DbClient
  ): Promise<PRAnalysisConfig> {
    const cleanUpdate = Object.fromEntries(Object.entries(config));

    await db.repo.update({
      data: {
        prAnalysisConfig: {
          upsert: {
            create: {
              ciSkip: config.ciSkip ?? DEFAULT_PR_CONFIG.ciSkip,
              commentStyle: config.commentStyle ?? DEFAULT_PR_CONFIG.commentStyle,
              enabled: config.enabled ?? DEFAULT_PR_CONFIG.enabled,
              excludePatterns: config.excludePatterns ?? [],
              focusAreas: config.focusAreas ?? DEFAULT_PR_CONFIG.focusAreas,
              tokenBudget: config.tokenBudget ?? DEFAULT_PR_CONFIG.tokenBudget,
            },
            update: cleanUpdate,
          },
        },
      },
      where: { publicId: repoId },
    });

    return this.getConfig(repoId, db);
  }

  static async enablePRAnalysis(repoId: string, db: DbClient): Promise<void> {
    await this.updateConfig(repoId, { enabled: true }, db);
  }

  static async disablePRAnalysis(repoId: string, db: DbClient): Promise<void> {
    await this.updateConfig(repoId, { enabled: false }, db);
  }

  static async setTokenBudget(repoId: string, budget: number, db: DbClient): Promise<void> {
    await this.updateConfig(repoId, { tokenBudget: clamp(budget, 10_000, 100_000) }, db);
  }

  static async setFocusAreas(
    repoId: string,
    areas: PRAnalysisConfig["focusAreas"],
    db: DbClient
  ): Promise<void> {
    await this.updateConfig(repoId, { focusAreas: areas }, db);
  }
}

import type { PullRequestEvent } from "@octokit/webhooks-types";

import { prAnalysisService } from "@/server/entities/pr-analysis/api/pr-analysis.service";
import { PRConfigService } from "@/server/features/pr-analysis/lib/pr-config";
import { prisma } from "@/server/shared/infrastructure/db";
import { logger } from "@/server/shared/infrastructure/logger";

import { analyzePrTask } from "../task/analyze-pr.task";

/**
 * Handle GitHub PR webhook events (opened, synchronize actions only)
 * Validates config, creates analysis record, and triggers Trigger.dev task for differential analysis
 */
export async function handlePullRequestEvent(payload: PullRequestEvent): Promise<void> {
  const { action, pull_request, repository } = payload;

  if (pull_request.user.type === "Bot") {
    logger.debug({
      bot: pull_request.user.login,
      msg: "pr_webhook_ignored_bot",
      prNumber: pull_request.number,
    });
    return;
  }

  if (pull_request.draft) {
    logger.debug({ msg: "pr_webhook_skipped_draft", prNumber: pull_request.number });
    return;
  }

  const allowedActions = ["opened", "reopened", "synchronize", "ready_for_review"];

  if (!allowedActions.includes(action)) {
    logger.debug({ action, msg: "pr_webhook_ignored", prNumber: pull_request.number });
    return;
  }

  logger.info({
    action,
    msg: "pr_webhook_received",
    owner: repository.owner.login,
    prNumber: pull_request.number,
    repo: repository.name,
  });

  try {
    // Find repo in DB by GitHub ID
    const repo = await prisma.repo.findFirst({
      where: { githubId: repository.id },
    });

    if (repo == null) {
      logger.warn({
        githubId: repository.id,
        msg: "pr_webhook_repo_not_found",
        owner: repository.owner.login,
        repo: repository.name,
      });
      return;
    }

    // Check if PR analysis is enabled
    const config = await PRConfigService.getConfig(repo.publicId, prisma);
    if (!config.enabled) {
      logger.debug({
        msg: "pr_webhook_analysis_disabled",
        prNumber: pull_request.number,
        repoId: repo.id,
      });
      return;
    }

    // Check for existing analysis
    const existingAnalysis = await prAnalysisService.getByRepoAndPRNumber(
      prisma,
      repo.publicId,
      pull_request.number
    );

    if (existingAnalysis != null && (action === "opened" || action === "ready_for_review")) {
      logger.warn({
        msg: "pr_webhook_analysis_already_exists",
        prNumber: pull_request.number,
        repoId: repo.id,
      });
      return;
    }

    let analysisId: number;

    if (existingAnalysis == null) {
      // Create new analysis
      const analysis = await prAnalysisService.create(prisma, {
        baseSha: pull_request.base.sha,
        headSha: pull_request.head.sha,
        owner: repository.owner.login,
        prNumber: pull_request.number,
        repoId: repo.publicId,
        repoName: repository.name,
      });

      analysisId = analysis.id;

      logger.info({
        analysisId: analysis.id,
        msg: "pr_webhook_analysis_created",
        prNumber: pull_request.number,
        repoId: repo.id,
      });
    } else {
      const updatedAnalysis = await prAnalysisService.update(prisma, existingAnalysis.id, {
        baseSha: pull_request.base.sha,
        headSha: pull_request.head.sha,
      });
      analysisId = updatedAnalysis.id;
    }

    // Trigger Trigger.dev task for differential analysis
    await analyzePrTask.trigger({
      analysisId,
      baseSha: pull_request.base.sha,
      headSha: pull_request.head.sha,
      owner: repository.owner.login,
      prNumber: pull_request.number,
      repoId: repo.id,
      repoName: repository.name,
    });
  } catch (error) {
    logger.error({
      error: error instanceof Error ? error.message : String(error),
      msg: "pr_webhook_error",
      owner: repository.owner.login,
      prNumber: pull_request.number,
      repo: repository.name,
    });
  }
}

