import { ADAPTER_PRIORITIES } from "../core/scoring-constants";
import { collectRegexSignals } from "../extractors/regex-signals";
import type { LanguageAdapter } from "./types";

export const regexAdapter: LanguageAdapter = {
  id: "regex-fallback",
  parse: (file) => collectRegexSignals(file),
  priority: ADAPTER_PRIORITIES.regex,
  supportedExtensions: [],
};

import type { RepositoryFile } from "../core/discovery.types";
import { regexAdapter } from "./regex.adapter";
import { treeSitterAdapter } from "./tree-sitter.adapter";
import { matchesExtension, type LanguageAdapter } from "./types";
import { typeScriptAdapter } from "./typescript.adapter";

const REGISTRY: LanguageAdapter[] = [typeScriptAdapter, treeSitterAdapter, regexAdapter].sort(
  (left, right) => right.priority - left.priority
);

export function getLanguageAdapters(file: RepositoryFile) {
  return REGISTRY.filter((adapter) => {
    if (!matchesExtension(adapter, file.path)) return false;
    return adapter.detect?.(file) ?? true;
  });
}

import { ADAPTER_PRIORITIES } from "../core/scoring-constants";
import {
  collectTreeSitterSignals,
  TREE_SITTER_SUPPORTED_EXTENSIONS,
} from "../extractors/tree-sitter-signals";
import type { LanguageAdapter } from "./types";

export const treeSitterAdapter: LanguageAdapter = {
  id: "tree-sitter",
  parse: (file) => collectTreeSitterSignals(file),
  priority: ADAPTER_PRIORITIES.treeSitter,
  supportedExtensions: TREE_SITTER_SUPPORTED_EXTENSIONS,
};

import { extname } from "pathe";

import type { FileSignals, RepositoryFile } from "../core/discovery.types";

export type LanguageAdapter = {
  detect?: (file: RepositoryFile) => boolean;
  id: string;
  parse: (file: RepositoryFile) => FileSignals | null | Promise<FileSignals | null>;
  priority: number;
  supportedExtensions: string[];
};

export function matchesExtension(adapter: LanguageAdapter, filePath: string) {
  if (adapter.supportedExtensions.length === 0) return true;
  const ext = extname(filePath).toLowerCase();
  return adapter.supportedExtensions.includes(ext);
}

import { ADAPTER_PRIORITIES } from "../core/scoring-constants";
import { collectTypeScriptSignals } from "../extractors/typescript-signals";
