export function buildRouteInventory(
  evidence: Pick<RepositoryEvidence, "frameworkFacts" | "routes">
): RouteInventory {
  const primaryRoutes = evidence.routes.filter((route) =>
    ProjectPolicy.isPrimaryApiSurface(route.sourcePath)
  );
  const rpcProcedures = primaryRoutes.filter((route) => route.kind === "rpc").length;
  const httpRoutes = primaryRoutes
    .filter((route) => route.kind === "http" && route.method != null)
    .map((route) => ({
      method: route.method ?? "GET",
      path: route.path,
      sourcePath: route.sourcePath,
    }));

  return {
    estimatedOperations: httpRoutes.length + rpcProcedures,
    frameworks: evidence.frameworkFacts.map((fact) => fact.name),
    httpRoutes,
    rpcProcedures,
    source: "extracted",
    sourceFiles: Array.from(new Set(primaryRoutes.map((route) => route.sourcePath))).sort(
      (left, right) => left.localeCompare(right)
    ),
  };
}

function normalizeFiles(files: RepositoryFile[]): NormalizedRepositoryFile[] {
  return files.map((file) => ({
    ...file,
    path: normalizeRepoPath(file.path),
  }));
}

function buildFilesByBaseName(files: NormalizedRepositoryFile[]) {
  const filesByBaseName = new Map<string, string[]>();

  for (const file of files) {
    const baseName = file.path.split("/").at(-1)?.toLowerCase();
    if (baseName == null) continue;
    const bucket = filesByBaseName.get(baseName);
    if (bucket == null) {
      filesByBaseName.set(baseName, [file.path]);
    } else {
      bucket.push(file.path);
    }
  }

  return filesByBaseName;
}

export function buildEvidenceLookups(
  files: RepositoryFile[],
  fileComplexities: FileComplexity[]
): EvidenceLookups {
  const normalizedFiles = normalizeFiles(files);

  return {
    aliasRules: collectAliasRules(normalizedFiles),
    complexityByFile: new Map(
      fileComplexities.map((item) => [normalizeRepoPath(item.path), item.score] as const)
    ),
    filesByBaseName: buildFilesByBaseName(normalizedFiles),
    fileSet: new Set(normalizedFiles.map((file) => file.path)),
    normalizedFiles,
  };
}

function createDependencyTracking(): DependencyTracking {
  return {
    edges: [],
    graph: new Map<string, Set<string>>(),
    inboundByFile: new Map<string, number>(),
    resolvedEdges: 0,
    unresolvedImportSpecifiers: 0,
    unresolvedSamples: [],
  };
}

export function createEvidenceAssembly(): EvidenceAssembly {
  return {
    apiSurfaceByFile: new Map<string, number>(),
    configs: [],
    dependencyTracking: createDependencyTracking(),
    exportsByFile: new Map<string, number>(),
    modules: [],
    routes: [],
    symbols: [],
  };
}

export function resolveImportEdges(
  filePath: string,
  imports: string[],
  lookups: Pick<EvidenceLookups, "aliasRules" | "filesByBaseName" | "fileSet">,
  tracking: DependencyTracking
) {
  const resolvedImports: string[] = [];

  for (const importPath of imports) {
    const resolved =
      resolveRelativeImport(filePath, importPath, lookups.fileSet) ??
      resolveModuleImport(importPath, lookups.fileSet, lookups.filesByBaseName, lookups.aliasRules);

    if (resolved === filePath) continue;

    if (resolved != null) {
      resolvedImports.push(resolved);
      tracking.resolvedEdges += 1;
      tracking.edges.push({
        fromPath: filePath,
        kind: "internal",
        resolved: true,
        specifier: importPath,
        toPath: resolved,
      });
      tracking.inboundByFile.set(resolved, (tracking.inboundByFile.get(resolved) ?? 0) + 1);
      continue;
    }

    const kind = isLikelyInternalImportSpecifier(importPath) ? "internal" : "external";
    tracking.edges.push({
      fromPath: filePath,
      kind,
      resolved: false,
      specifier: importPath,
    });

    if (kind === "internal") {
      tracking.unresolvedImportSpecifiers += 1;
      if (tracking.unresolvedSamples.length < SCHEMA_LIMITS.maxUnresolvedImportsSamples) {
        tracking.unresolvedSamples.push({ fromPath: filePath, specifier: importPath });
      }
    }
  }

  tracking.graph.set(filePath, new Set(resolvedImports));
  return resolvedImports;
}

import type {
  FileComplexity,
  FileSignals,
  RepositoryEvidence,
  RepositoryFile,
} from "./discovery.types";
import { buildModuleRef, collectFileEvidence } from "./evidence-collector";
import {
  buildDependencyHotspots,
  buildFileCategoryBreakdown,
  buildHotspotSignals,
  buildMainEntrypointPaths,
  buildOrphanModules,
  dedupeConfigs,
  inferEntrypoints,
} from "./evidence-derived";
import {
  buildEvidenceLookups,
  buildRouteInventory,
  createEvidenceAssembly,
  resolveImportEdges,
} from "./evidence-support";
import { selectRepositoryFrameworkFacts } from "./framework-catalog";
import { findDependencyCycles } from "./graph";
import { ProjectPolicy } from "./project-policy";

// Source-of-truth builder for repository structure: modules, graph, entrypoints, routes, configs, and hotspots.
export async function collectRepositoryEvidence(
  files: RepositoryFile[],
  fileComplexities: FileComplexity[],
  fileSignalsByPath: Map<string, FileSignals>
) {
  const lookups = buildEvidenceLookups(files, fileComplexities);
  const assembly = createEvidenceAssembly();

  const moduleByPath = new Map<string, ReturnType<typeof buildModuleRef>>();

  for (const file of lookups.normalizedFiles) {
    const collected = await collectFileEvidence(
      file,
      lookups,
      assembly.dependencyTracking,
      fileSignalsByPath,
      resolveImportEdges
    );

    assembly.apiSurfaceByFile.set(file.path, collected.apiSurface);
    assembly.exportsByFile.set(file.path, collected.exports);
    assembly.configs.push(...collected.configs);
    assembly.routes.push(...collected.routes);
    assembly.symbols.push(...collected.symbols);

    const moduleRef = buildModuleRef(file.path, collected.signals, collected.entrypointHints);
    assembly.modules.push(moduleRef);

    moduleByPath.set(file.path, moduleRef);
  }

  const entrypoints = inferEntrypoints({
    apiSurfaceByFile: assembly.apiSurfaceByFile,
    exportsByFile: assembly.exportsByFile,
    inboundByFile: assembly.dependencyTracking.inboundByFile,
    moduleByPath,
  });
  const mainEntrypointPaths = buildMainEntrypointPaths(entrypoints);

  const orphanModules = buildOrphanModules(
    assembly.modules,
    assembly.dependencyTracking.inboundByFile,
    mainEntrypointPaths
  );

  const dependencyCycles = findDependencyCycles(assembly.dependencyTracking.graph);

  const dependencyHotspots = buildDependencyHotspots(
    assembly.modules,
    assembly.exportsByFile,
    assembly.dependencyTracking.inboundByFile,
    assembly.dependencyTracking.graph
  );

  const hotspotSignals = buildHotspotSignals(
    assembly.modules,
    lookups.complexityByFile,
    assembly.dependencyTracking.inboundByFile,
    assembly.dependencyTracking.graph
  );

  const frameworkFacts = selectRepositoryFrameworkFacts(
    assembly.modules.flatMap((module) => module.frameworkHints)
  );

  const publicSurface = assembly.symbols
    .filter((symbol) => symbol.exported && ProjectPolicy.isArchitectureRelevant(symbol.path))
    .slice(0, 150);

  const fileCategoryBreakdown = buildFileCategoryBreakdown(assembly.modules);

  const evidence: RepositoryEvidence = {
    configs: dedupeConfigs(assembly.configs),
    dependencyCycles,
    dependencyGraph: {
      edges: assembly.dependencyTracking.edges,
      resolvedEdges: assembly.dependencyTracking.resolvedEdges,
      unresolvedImportSpecifiers: assembly.dependencyTracking.unresolvedImportSpecifiers,
      unresolvedSamples: assembly.dependencyTracking.unresolvedSamples,
    },
    entrypoints,
    fileCategoryBreakdown,
    frameworkFacts,
    hotspotSignals,
    modules: assembly.modules,
    orphanModules,
    publicSurface,
    routeInventory: buildRouteInventory({ frameworkFacts, routes: assembly.routes }),
    routes: assembly.routes,
    symbols: assembly.symbols,
  };

  return { dependencyHotspots, evidence };
}

import { XMLParser } from "fast-xml-parser";
import { basename } from "pathe";
import YAML from "yaml";

import { dumpDebug } from "../../lib/debug-logger";
import type {
  FileSignals,
  FrameworkFact,
  RepositoryEvidence,
  TechCategory,
  TechFact,
} from "./discovery.types";
import {
  collectFrameworkFactsFromTokens,
  selectRepositoryFrameworkFacts,
} from "./framework-catalog";
import { ProjectPolicy } from "./project-policy";
import { CONFIDENCE_LEVELS } from "./scoring-constants";

const xmlParser = new XMLParser({ ignoreAttributes: false });

type AnalyzedFile = { content: string; path: string };
type ManifestHandler = {
  matches: (fileName: string) => boolean;
  run: (collector: FactCollector, file: AnalyzedFile) => void;
};

function mapFrameworkCategory(category: FrameworkFact["category"]): TechCategory {
  switch (category) {
    case "api": {
      return "Framework";
    }
    case "cloud": {
      return "Cloud";
    }
    case "database": {
      return "Database";
    }
    case "framework": {
      return "Framework";
    }
    case "infrastructure": {
      return "Infrastructure";
    }
    case "orm": {
      return "ORM";
    }
    case "testing": {
      return "Testing";
    }
    case "tooling": {
      return "CI/CD";
    }
    case "ui": {
      return "UI/Styling";
    }
    case "runtime": {
      return "Framework";
    }
    default: {
      return "Library";
    }
  }
}

export class FactCollector {
  private facts = new Map<string, TechFact>();
  private frameworkFacts: FrameworkFact[] = [];

  static collect(
    files: { content: string; path: string }[],
    evidence?: Pick<RepositoryEvidence, "configs" | "frameworkFacts" | "routeInventory">,
    fileSignalsByPath?: Map<string, FileSignals>
  ) {
    const collector = new FactCollector();

    if (evidence?.frameworkFacts.length != null) {
      collector.frameworkFacts.push(...evidence.frameworkFacts);
    }
    if (
      (evidence?.routeInventory.source === "mixed" ||
        evidence?.routeInventory.source === "openapi") &&
      evidence.routeInventory.sourceFiles.length > 0
    ) {
      collector.addFact("OpenAPI", "Framework", CONFIDENCE_LEVELS.openapiSpec);
    }
    for (const config of evidence?.configs ?? []) {
      collector.collectFrameworkFactsFromTokens([config.kind, config.path], config.path, 68);
    }

    for (const file of files) {
      collector.analyzeFile(file, fileSignalsByPath?.get(file.path));
    }

    collector.promoteMergedFrameworkFacts();
    const result = Array.from(collector.facts.values()).sort((a, b) => b.confidence - a.confidence);
    void dumpDebug("tech-facts-detected", result);
    return result;
  }

  private static readonly manifestHandlers: ManifestHandler[] = [
    {
      matches: (fileName) => fileName === "package.json",
      run: (collector, file) => collector.parseManifestPackageJson(file.content, file.path),
    },
    {
      matches: (fileName) =>
        fileName === "package-lock.json" ||
        fileName === "pnpm-lock.yaml" ||
        fileName === "yarn.lock",
      run: (collector, file) =>
        collector.collectFrameworkFactsFromTokens([basename(file.path)], file.path, 60),
    },
    {
      matches: (fileName) => fileName === "composer.json",
      run: (collector, file) =>
        collector.parseManifestJsonDependencies(
          file.content,
          ["require", "require-dev"],
          file.path
        ),
    },
    {
      matches: (fileName) => fileName === "pom.xml",
      run: (collector, file) => collector.parseManifestMaven(file.content, file.path),
    },
    {
      matches: (fileName) => fileName.endsWith(".csproj"),
      run: (collector, file) => collector.parseManifestDotNet(file.content, file.path),
    },
    {
      matches: (fileName) => fileName === "requirements.txt",
      run: (collector, file) =>
        collector.parseManifestRegex(file.content, /^([\w.-]+)/gim, file.path, 88),
    },
    {
      matches: (fileName) => fileName === "go.mod",
      run: (collector, file) =>
        collector.parseManifestRegex(file.content, /^[\t ]*([\w./-]+)[\t ]+v\d/gim, file.path, 88),
    },
    {
      matches: (fileName) => fileName === "cargo.toml",
      run: (collector, file) =>
        collector.parseManifestRegex(
          file.content,
          /^[\t ]*([\w-]+)[\t ]*=[\t ]*["{]/gim,
          file.path,
          88
        ),
    },
    {
      matches: (fileName) => fileName === "pubspec.yaml",
      run: (collector, file) => collector.parseManifestPubspec(file.content, file.path),
    },
  ];

  private analyzeFile(file: AnalyzedFile, signals?: FileSignals) {
    const fileName = basename(file.path).toLowerCase();
    const pathLower = file.path.toLowerCase();

    this.collectPolicyPathFacts(pathLower, fileName);
    this.collectManifestFacts(fileName, file);
    this.collectSignalDerivedFacts(file.path, signals);
    if (this.isOneC(pathLower)) this.addFact("1C:Enterprise", "Language", 95);
  }

  private collectPolicyPathFacts(pathLower: string, fileName: string) {
    const categories = ProjectPolicy.getCategories(pathLower);

    if (categories.includes("infra")) this.addFact("Infrastructure as Code", "Infrastructure", 84);
    if (categories.includes("tooling")) this.addFact("Build Tooling", "CI/CD", 70);
    if (categories.includes("config"))
      this.addFact("Configuration-Driven Setup", "Infrastructure", 66);

    if (pathLower.includes("/.github/workflows/")) this.addFact("GitHub Actions", "CI/CD", 100);
    if (fileName === ".gitlab-ci.yml") this.addFact("GitLab CI", "CI/CD", 100);
    if (fileName === "dockerfile") this.addFact("Docker", "Infrastructure", 100);
    if (fileName === "docker-compose.yml" || fileName === "docker-compose.yaml") {
      this.addFact("Docker Compose", "Infrastructure", 100);
    }
    if (fileName === "ansible.cfg") this.addFact("Ansible", "Infrastructure", 100);
    if (fileName.endsWith(".tf")) this.addFact("Terraform", "Infrastructure", 100);
    if (fileName.startsWith("capacitor.config.")) this.addFact("Capacitor", "Mobile", 100);
    if (fileName === "expo.json") this.addFact("Expo", "Mobile", 100);
    if (
      pathLower.includes("/k8s/") ||
      fileName === "deployment.yml" ||
      fileName === "deployment.yaml"
    ) {
      this.addFact("Kubernetes", "Infrastructure", 100);
    }
    if (fileName.startsWith("tailwind.config.")) this.addFact("Tailwind CSS", "UI/Styling", 100);
  }

  private collectManifestFacts(fileName: string, file: AnalyzedFile) {
    for (const handler of FactCollector.manifestHandlers) {
      if (!handler.matches(fileName)) continue;
      handler.run(this, file);
    }
  }

  private collectSignalDerivedFacts(filePath: string, signals?: FileSignals) {
    if (signals?.frameworkHints?.length != null) {
      this.frameworkFacts.push(...signals.frameworkHints);
    }
    if (signals?.imports.length != null) {
      this.collectFrameworkFactsFromTokens(signals.imports, filePath, 72);
    }
  }

  private collectFrameworkFactsFromTokens(tokens: string[], filePath: string, confidence: number) {
    this.frameworkFacts.push(...collectFrameworkFactsFromTokens(tokens, filePath, confidence));
  }

  private promoteMergedFrameworkFacts() {
    for (const fact of selectRepositoryFrameworkFacts(this.frameworkFacts)) {
      this.addFact(fact.name, mapFrameworkCategory(fact.category), fact.confidence);
    }
  }

  private addFact(name: string, category: TechCategory, confidence: number) {
    const existing = this.facts.get(name);
    if (!existing || existing.confidence < confidence) {
      this.facts.set(name, { category, confidence, name });
    }
  }

  private parseManifestPackageJson(content: string, filePath: string) {
    this.parseManifestJsonDependencies(
      content,
      ["dependencies", "devDependencies", "peerDependencies"],
      filePath
    );

    try {
      const data = JSON.parse(content);
      const frameworkTokens = [
        data.name,
        ...Object.keys(Boolean(data.scripts) || {}),
        ...Object.keys(Boolean(data.dependencies) || {}),
        ...Object.keys(Boolean(data.devDependencies) || {}),
      ].filter((value): value is string => typeof value === "string");
      this.collectFrameworkFactsFromTokens(frameworkTokens, filePath, 95);
    } catch {
      // Optional signal only.
    }
  }

  private parseManifestJsonDependencies(content: string, keys: string[], filePath: string) {
    try {
      const data = JSON.parse(content) as Record<string, unknown>;
      for (const key of keys) {
        const section = data[key];
        if (section != null && typeof section === "object" && !Array.isArray(section)) {
          const deps = Object.keys(section);
          this.collectFrameworkFactsFromTokens(deps, filePath, 94);
        }
      }
    } catch {
      // Optional signal only.
    }
  }

  private parseManifestMaven(content: string, filePath: string) {
    try {
      const jsonObj = xmlParser.parse(content);
      const deps = jsonObj?.project?.dependencies?.dependency;
      const depArray = Array.isArray(deps) ? deps : [deps];
      const tokens = depArray
        .flatMap((item: any) => [item?.artifactId, item?.groupId])
        .filter((value: unknown): value is string => typeof value === "string");
      this.collectFrameworkFactsFromTokens(tokens, filePath, 92);
    } catch {
      // Optional signal only.
    }
  }

  private parseManifestDotNet(content: string, filePath: string) {
    try {
      const jsonObj = xmlParser.parse(content);
      const itemGroups = jsonObj?.Project?.ItemGroup;
      const groupArray = Array.isArray(itemGroups) ? itemGroups : [itemGroups];
      const pkgArray = groupArray.flatMap((group: unknown) => {
        const refs = (group as { PackageReference?: unknown }).PackageReference;
        return Array.isArray(refs) ? refs : [refs];
      });
      const tokens = pkgArray
        .map((pkg: any) => pkg?.["@_Include"])
        .filter((value: unknown): value is string => typeof value === "string");
      this.collectFrameworkFactsFromTokens(tokens, filePath, 92);
    } catch {
      // Optional signal only.
    }
  }

  private parseManifestRegex(content: string, regex: RegExp, filePath: string, confidence: number) {
    const tokens: string[] = [];
    for (const match of content.matchAll(regex)) {
      if (typeof match[1] === "string" && match[1].length > 0) tokens.push(match[1]);
    }
    this.collectFrameworkFactsFromTokens(tokens, filePath, confidence);
  }

  private parseManifestPubspec(content: string, filePath: string) {
    try {
      const data = YAML.parse(content);
      const deps = data?.dependencies;

      if (deps != null && typeof deps === "object" && !Array.isArray(deps)) {
        const depKeys = Object.keys(deps);
        this.collectFrameworkFactsFromTokens(depKeys, filePath, 88);
      }
    } catch {
      // Optional signal only.
    }
  }

  private isOneC(path: string): boolean {
    return (
      path.endsWith(".bsl") ||
      path.endsWith(".os") ||
      path.includes("/catalogs/") ||
      path.includes("/documents/")
    );
  }
}

import { normalizeLanguageName } from "../../lib/language-metadata";
import { ProjectPolicy } from "./project-policy";
import { FILE_CATEGORY_SCORING } from "./scoring-constants";

export function getFileScore(path: string): number {
  const lower = path.toLowerCase();

  if (ProjectPolicy.isSensitive(lower)) return FILE_CATEGORY_SCORING.sensitive;
  if (ProjectPolicy.isLowSignalConfig(lower)) return FILE_CATEGORY_SCORING.lowSignalConfig;
  if (ProjectPolicy.isGeneratedFile(lower) || ProjectPolicy.isAssetFile(lower)) {
    return FILE_CATEGORY_SCORING.generated;
  }
  if (ProjectPolicy.isDocsFile(lower)) return FILE_CATEGORY_SCORING.docs;
  if (ProjectPolicy.isBenchmarkFile(lower)) return FILE_CATEGORY_SCORING.benchmarks;
  if (ProjectPolicy.isTestFile(lower)) return FILE_CATEGORY_SCORING.tests;
  if (ProjectPolicy.isInfraFile(lower)) return FILE_CATEGORY_SCORING.infrastructure;
  if (ProjectPolicy.isToolingFile(lower)) return FILE_CATEGORY_SCORING.tooling;
  if (ProjectPolicy.isConfigFile(lower)) return FILE_CATEGORY_SCORING.config;
  if (ProjectPolicy.isApiPath(lower)) return FILE_CATEGORY_SCORING.api;
  if (ProjectPolicy.isRuntimeSource(lower)) return FILE_CATEGORY_SCORING.runtimeSource;

  if (ProjectPolicy.isFrontendComponent(lower)) {
    return FILE_CATEGORY_SCORING.runtimeSource;
  }

  const depth = path.split("/").length;
  let score = FILE_CATEGORY_SCORING.defaultBase;
  if (depth < 3) {
    score += FILE_CATEGORY_SCORING.depthBonus;
  }

  return score;
}
export function linguistStyleLabel(filePath: string, fallbackName: string): string {
  const extMatch = /(\.[^./\\]+)$/u.exec(filePath);
  const ext = extMatch?.[1] ?? "";
  return normalizeLanguageName(ext) || fallbackName;
}

import { escapeRegExp, uniq } from "es-toolkit";

import type { FrameworkFact } from "./discovery.types";
import { ProjectPolicy } from "./project-policy";
import { FRAMEWORK_CATALOG } from "./project-policy-rules";

const aliasRegexCache = new Map<string, RegExp>();

function getFrameworkAliasRegex(alias: string): RegExp {
  let cached = aliasRegexCache.get(alias);
  if (cached == null) {
    const escapedAlias = escapeRegExp(alias.toLowerCase());
    cached = RegExp(`(^|[^a-z0-9])${escapedAlias}([^a-z0-9]|$)`, "iu");
    aliasRegexCache.set(alias, cached);
  }
  return cached;
}

function matchesFrameworkAlias(token: string, alias: string): boolean {
  const normalizedAlias = alias.toLowerCase();

  if (/[./@-]/.test(normalizedAlias)) {
    return token.includes(normalizedAlias);
  }

  return getFrameworkAliasRegex(normalizedAlias).test(token);
}

export function collectFrameworkFactsFromTokens(
  tokens: Iterable<string>,
  source: string,
  baseConfidence: number
): FrameworkFact[] {
  const collected = new Map<string, FrameworkFact>();

  for (const rawToken of tokens) {
    const token = rawToken.toLowerCase();
    for (const entry of FRAMEWORK_CATALOG) {
      if (!entry.aliases.some((alias) => matchesFrameworkAlias(token, alias))) continue;

      const existing = collected.get(entry.name);
      const next: FrameworkFact = {
        category: entry.category,
        confidence: baseConfidence,
        name: entry.name,
        sources: existing == null ? [source] : uniq([...existing.sources, source]),
      };

      if (existing == null || existing.confidence < next.confidence) {
        collected.set(entry.name, next);
      } else {
        existing.sources = next.sources;
      }
    }
  }

  return Array.from(collected.values()).sort((left, right) => right.confidence - left.confidence);
}

function mergeFrameworkFacts(facts: FrameworkFact[]): FrameworkFact[] {
  const merged = new Map<string, FrameworkFact>();

  for (const fact of facts) {
    const existing = merged.get(fact.name);
    if (existing == null) {
      merged.set(fact.name, { ...fact, sources: uniq(fact.sources) });
      continue;
    }

    existing.confidence = Math.max(existing.confidence, fact.confidence);
    existing.sources = uniq([...existing.sources, ...fact.sources]);
  }

  return Array.from(merged.values()).sort((left, right) => right.confidence - left.confidence);
}

function countCoreSources(fact: FrameworkFact): number {
  const coreSources = fact.sources.filter((source) => ProjectPolicy.isFrameworkFactSource(source));
  return uniq(coreSources).length;
}

function hasManifestOnlySources(fact: FrameworkFact): boolean {
  return (
    fact.sources.length > 0 &&
    fact.sources.every(
      (source) =>
        ProjectPolicy.isConfigFile(source) ||
        ProjectPolicy.isDocsFile(source) ||
        ProjectPolicy.isInfraFile(source) ||
        ProjectPolicy.isTestFile(source) ||
        ProjectPolicy.isToolingFile(source)
    )
  );
}

function isCoreRepositoryFrameworkFact(fact: FrameworkFact): boolean {
  const coreSourceCount = countCoreSources(fact);
  if (coreSourceCount >= 2) return true;
  if (coreSourceCount >= 1 && (fact.category === "api" || fact.category === "framework")) {
    return true;
  }
  return false;
}

export function selectRepositoryFrameworkFacts(facts: FrameworkFact[]): FrameworkFact[] {
  const mergedFacts = mergeFrameworkFacts(facts);
  const coreFacts = mergedFacts.filter((fact) => isCoreRepositoryFrameworkFact(fact));
  if (coreFacts.length > 0) {
    return coreFacts;
  }

  const filteredFallback = mergedFacts.filter((fact) => !hasManifestOnlySources(fact));
  return filteredFallback.length > 0 ? filteredFallback : mergedFacts;
}

import { analyzeGraph, type Edge, type Graph } from "graph-cycles";
import { DirectedGraph } from "graphology";
import { hasCycle } from "graphology-dag";
import { basename, dirname, join, normalize } from "pathe";
import ts from "typescript";

import { dumpDebug } from "../../lib/debug-logger";
import { getKnownLanguageExtensions } from "../../lib/language-metadata";
import { normalizeRepoPath } from "./common";
import { SCHEMA_LIMITS } from "./scoring-constants";

type AliasRule = {
  prefix: string;
  targets: string[];
};

export function isLikelyInternalImportSpecifier(spec: string): boolean {
  const t = spec.trim();
  if (t.startsWith(".")) return true;
  if (/^[@~]{1,2}\//u.test(t)) return true;
  if (t.startsWith("#")) return true;
  return false;
}

const RELATIVE_IMPORT_SUFFIXES = [
  "",
  ...getKnownLanguageExtensions(),
  "/index.ts",
  "/index.js",
  "/__init__.py",
];

export function resolveRelativeImport(
  fromPath: string,
  importPath: string,
  fileSet: Set<string>
): null | string {
  const normalizedImport = normalizeRepoPath(importPath);
  if (!normalizedImport.startsWith(".")) return null;

  const basePath = normalize(join(dirname(fromPath), normalizedImport));

  for (const suffix of RELATIVE_IMPORT_SUFFIXES) {
    const candidate = normalizeRepoPath(`${basePath}${suffix}`);
    if (fileSet.has(candidate)) return candidate;
  }

  return null;
}

function resolveAliasImport(
  importPath: string,
  fileSet: Set<string>,
  aliasRules: AliasRule[]
): null | string {
  if (aliasRules.length === 0) return null;

  for (const rule of aliasRules) {
    if (!importPath.startsWith(rule.prefix)) continue;
    const suffix = importPath.slice(rule.prefix.length).replace(/^\/+/u, "");

    for (const target of rule.targets) {
      const candidateBase = normalizeRepoPath(join(target, suffix));
      for (const importSuffix of RELATIVE_IMPORT_SUFFIXES) {
        const candidate = normalizeRepoPath(`${candidateBase}${importSuffix}`);
        if (fileSet.has(candidate)) return candidate;
      }
    }
  }

  return null;
}

export function resolveModuleImport(
  importPath: string,
  fileSet: Set<string>,
  filesByBaseName: Map<string, string[]>,
  aliasRules: AliasRule[] = []
): null | string {
  const aliasResolved = resolveAliasImport(importPath, fileSet, aliasRules);
  if (aliasResolved != null) return aliasResolved;

  const normalizedImport = normalize(importPath);

  const candidates = [
    normalizedImport,
    `${normalizedImport}.ts`,
    `${normalizedImport}.js`,
    `${normalizedImport}.py`,
    `${normalizedImport}.go`,
    `${normalizedImport}.java`,
    `${normalizedImport}.kt`,
    `${normalizedImport}.cs`,
    `${normalizedImport}.php`,
    `${normalizedImport}.rb`,
    `${normalizedImport}.rs`,
    `${normalizedImport}.bsl`,
    `${normalizedImport}/__init__.py`,
    `${normalizedImport}/index.ts`,
    `${normalizedImport}/index.js`,
  ].map((path) => normalizeRepoPath(path));

  for (const candidate of candidates) {
    if (fileSet.has(candidate)) return candidate;
  }

  const lastSegment = basename(normalizedImport);

  const fileNameCandidates = [
    lastSegment,
    `${lastSegment}.ts`,
    `${lastSegment}.js`,
    `${lastSegment}.py`,
    `${lastSegment}.go`,
    `${lastSegment}.java`,
    `${lastSegment}.kt`,
    `${lastSegment}.cs`,
    `${lastSegment}.php`,
    `${lastSegment}.rb`,
    `${lastSegment}.rs`,
    `${lastSegment}.bsl`,
  ];

  for (const fileName of fileNameCandidates) {
    const matches = filesByBaseName.get(fileName.toLowerCase());
    if (matches != null && matches.length > 0) {
      if (matches.length === 1) return matches[0]!;
      const tsMatch = matches.find((m) => m.endsWith(".ts"));
      if (tsMatch != null) return tsMatch;
      return matches[0]!;
    }
  }

  return null;
}

export function collectAliasRules(files: Array<{ content: string; path: string }>): AliasRule[] {
  const rules: AliasRule[] = [];

  for (const file of files) {
    const normalizedPath = normalizeRepoPath(file.path);
    if (!/\/tsconfig(?:\.[^/]+)?\.json$/iu.test(normalizedPath)) continue;

    try {
      const parsed = ts.parseConfigFileTextToJson(normalizedPath, file.content);
      if (parsed.error != null) continue;

      const compilerOptions = parsed.config?.compilerOptions;
      if (compilerOptions == null || typeof compilerOptions !== "object") continue;

      const baseUrl = typeof compilerOptions.baseUrl === "string" ? compilerOptions.baseUrl : ".";
      const paths = compilerOptions.paths as Record<string, string[] | undefined> | undefined;
      if (paths == null) continue;

      for (const [rawAlias, rawTargets] of Object.entries(paths)) {
        if (!Array.isArray(rawTargets) || rawTargets.length === 0) continue;
        const prefix = rawAlias.replace(/\*.*$/u, "");
        const targets = rawTargets.map((target) =>
          normalizeRepoPath(join(dirname(normalizedPath), baseUrl, target.replace(/\*.*$/u, "")))
        );
        rules.push({ prefix, targets });
      }
    } catch {
      // Best-effort helper only.
    }
  }

  return rules;
}
export function findDependencyCycles(graphMap: Map<string, Set<string>>): string[][] {
  const graph = new DirectedGraph();

  for (const [node, edges] of graphMap.entries()) {
    if (!graph.hasNode(node)) graph.addNode(node);
    for (const edge of edges) {
      if (!graph.hasNode(edge)) graph.addNode(edge);
      if (!graph.hasEdge(node, edge)) graph.addEdge(node, edge);
    }
  }

  if (!hasCycle(graph)) {
    void dumpDebug("dependency-cycles", { count: 0, cycles: [] });
    return [];
  }

  const mutableGraphData: Array<Edge> = [];

  const allNodes = new Set<string>();
  for (const [node, edges] of graphMap.entries()) {
    allNodes.add(node);
    for (const edge of edges) {
      allNodes.add(edge);
    }
  }

  for (const node of allNodes) {
    const edges = graphMap.get(node);
    mutableGraphData.push([node, edges ? Array.from(edges) : []]);
  }

  const analysis = analyzeGraph(mutableGraphData as Graph);

  const detectedCycles: string[][] = analysis.cycles;

  const result = detectedCycles
    .slice(0, SCHEMA_LIMITS.maxCyclesDetected)
    .sort((left, right) => left.length - right.length);

  void dumpDebug("dependency-cycles", { count: result.length, cycles: result });
  return result;
}

