export type RegexRoutePattern = Pick<RouteRef, "framework"> & {
  confidence?: number;
  methodIndex: number;
  pathIndex: number;
  pattern: RegExp;
};

export type RegexSymbolPattern = {
  exported?: boolean;
  kind: SymbolKind;
  pattern: RegExp;
};

export type RegexSignalSpec = {
  apiSurfacePatterns: RegExp[];
  entrypointHint: (file: RepositoryFile) => boolean;
  exportPatterns: RegExp[];
