  exportPatterns: [
    /^\s*(?:public|export|pub)\s+/gm,
    /^\s*(?:function|class|interface|module|procedure|func|proc)\s+/gim,
  ],
  importPatterns: [
    /^\s*import\s+([\w./-]+)/gm,
    /^\s*from\s+([\w./-]+)\s+import\b/gm,
    /^\s*use\s+([\w./-]+)/gm,
    /^\s*include\s+["']([^"']+)["']/gm,
