export async function initRuntime() {
  if (runtimeInitPromise) return runtimeInitPromise;

  runtimeInitPromise = (async () => {
    //eslint-disable-next-line @typescript-eslint/no-require-imports
    const mod = require("web-tree-sitter");

    let Parser = mod.Parser;

    if (!Parser || typeof Parser.init !== "function") {
      Parser = mod.default;
    }

    if (!Parser || typeof Parser.init !== "function") {
      Parser = mod;
    }

    if (!Parser || typeof Parser.init !== "function") {
      throw new Error(`[TreeSitter] Could not find Parser.init. Module keys: ${Object.keys(mod)}`);
    }

    const runtimeWasmName = "tree-sitter.wasm";
    const pathsToTry = [
      resolve(process.cwd(), runtimeWasmName),
      resolve(process.cwd(), "node_modules/web-tree-sitter", runtimeWasmName),
      join(resolve(require.resolve("web-tree-sitter"), ".."), runtimeWasmName),
    ];

    const finalWasmPath = pathsToTry.find((p) => fs.existsSync(p));
    if (!finalWasmPath) {
      throw new Error(`[TreeSitter] Runtime WASM not found. Checked: ${pathsToTry.join(", ")}`);
    }

    await Parser.init({
      locateFile: (name: string) => {
        if (name === "tree-sitter.wasm") {
          return finalWasmPath;
        }
        return name;
      },
    });

    logger.info({ msg: "Tree-sitter runtime ready", wasm: finalWasmPath });

    return { mod, Parser };
  })();

  return runtimeInitPromise;
}

export async function loadLanguage(ext: string, spec: LanguageSpec) {
  const { mod, Parser } = await initRuntime();

  if (!languageCache.has(ext)) {
    languageCache.set(
      ext,
      (async () => {
        const wasmPath = resolveGrammarWasmPath(spec);

        const Language = Parser.Language || mod.Language || mod.default?.Language;

        if (!Language || typeof Language.load !== "function") {
          throw new Error(`[TreeSitter] Language.load is missing!`);
        }

        const wasmBytes = fs.readFileSync(wasmPath);

        return await Language.load(wasmBytes);
      })().catch((error) => {
        languageCache.delete(ext);
        logger.error({ error, ext, msg: "Failed to load language grammar" });
        throw error;
      })
    );
  }

  return await languageCache.get(ext);
}

function resolveGrammarWasmPath(spec: LanguageSpec): string {
  const candidates = [
    resolve(process.cwd(), spec.wasm),
    resolve(process.cwd(), "node_modules/tree-sitter-wasms/out", spec.wasm),
    resolve(import.meta.dirname ?? "", "../../../vendor/wasms", spec.wasm),
  ];

  for (const path of candidates) {
    if (fs.existsSync(path)) {
      return path;
    }
  }

  const errorContext = {
    checkedPaths: candidates,
    cwd: process.cwd(),
    env: process.env.NODE_ENV,
    specWasm: spec.wasm,
  };

  logger.error({ errorContext, msg: "Tree-sitter grammar not found" });

  throw new Error(
    `[TreeSitter] Grammar WASM not found: ${spec.wasm}. ` +
      `Ensure it is included in trigger.config.ts additionalFiles.`
  );
}

function lineOf(content: string, fragment: string) {
  const index = content.indexOf(fragment);
  if (index < 0) return;
  return content.slice(0, index).split(/\r?\n/u).length;
}

function extractNodeName(nodeText: string) {
  const firstLine = nodeText.split(/\r?\n/u, 1)[0]?.trim() ?? "";
  return /([A-Z_a-z]\w*)/.exec(firstLine)?.[1];
}

function collectRoutes(file: RepositoryFile, spec: LanguageSpec) {
  const routes: RouteRef[] = [];

  for (const routePattern of spec.routePatterns ?? []) {
    for (const match of file.content.matchAll(routePattern.pattern)) {
      const method =
        typeof match[routePattern.methodIndex] === "string"
          ? match[routePattern.methodIndex]?.toUpperCase()
          : undefined;
      const routePath =
        typeof match[routePattern.pathIndex] === "string"
          ? match[routePattern.pathIndex]
          : undefined;
      if (method == null || routePath == null) continue;
      routes.push({
        confidence: routePattern.confidence ?? CONFIDENCE_LEVELS.astRoute,
        framework: routePattern.framework,
        kind: "http",
        line: lineOf(file.content, match[0]),
        method,
        path: routePath,
        sourcePath: file.path,
      });
    }
  }

  return routes;
}

// ============================================================================
// УНИВЕРСАЛЬНЫЙ СЛОВАРЬ УЗЛОВ СЛОЖНОСТИ TREE-SITTER (Branching & Nesting)
// ============================================================================
const AST_COMPLEXITY_NODES = new Set([
  "case_clause",
  "catch_clause",
  "conditional_expression",
  "do_statement",
  "elif_clause",
  "else_if_clause",
  "except_clause",
  "for_in_clause",
  "for_statement",
  "if_statement",
  "switch_statement",
  "while_statement",
]);

const AST_NESTING_NODES = new Set([
  "catch_clause",
  "class_definition",
  "do_statement",
  "except_clause",
  "for_statement",
  "function_definition",
  "if_statement",
  "method_definition",
  "switch_statement",
  "while_statement",
]);

export async function collectTreeSitterSignals(file: RepositoryFile): Promise<FileSignals | null> {
  const ext = getFileExtension(file.path);
  const spec = SPECS[ext];
  if (!spec) return null;

  try {
    // Получаем Parser из промиса
    const { Parser } = await initRuntime();
    const lang = await loadLanguage(ext, spec);

    // Создаем инстанс
    const parser = new Parser();
    let tree: any;

    try {
      parser.setLanguage(lang);
      tree = parser.parse(file.content);
      const root = tree.rootNode;

      let apiSurface = 0;
      let exports = 0;
      const imports = new Set<string>();
      const symbols: SymbolRef[] = [];

      let complexity = 0;
      let maxNesting = 0;
      let currentNesting = 0;

      const declarationTypes = new Set(spec.declarations.flatMap((entry) => entry.types));
      const declarationKindByType = new Map(
        spec.declarations.flatMap((entry) => entry.types.map((type) => [type, entry.kind] as const))
      );

      const cursor = root.walk();
      let reachedRoot = false;

      while (!reachedRoot) {
        const nodeType = cursor.nodeType;
        const nodeText = cursor.nodeText;

        if (AST_COMPLEXITY_NODES.has(nodeType)) {
          complexity += 1 + currentNesting;
          maxNesting = Math.max(maxNesting, currentNesting);
        }

        if (spec.imports.types.includes(nodeType)) {
          spec.imports.patterns.forEach((re) => {
            const match = nodeText.match(re);
            if (match?.[1]) imports.add(match[1]);
          });
        }

        if (declarationTypes.has(nodeType)) {
          exports += 1;
          const kind = declarationKindByType.get(nodeType) ?? "function";
          const name = extractNodeName(nodeText);
          if (name != null) {
            symbols.push({
              confidence: CONFIDENCE_LEVELS.astSymbol,
              exported: true,
              kind,
              line: lineOf(file.content, nodeText),
              name,
              path: file.path,
            });
          }
        }

        if (spec.api?.some((re) => re.test(nodeText))) {
          apiSurface++;
        }

        if (cursor.gotoFirstChild()) {
          if (AST_NESTING_NODES.has(nodeType)) {
            currentNesting++;
          }
          continue;
        }

        if (cursor.gotoNextSibling()) continue;

        let backtrack = true;
        while (backtrack) {
          if (!cursor.gotoParent()) {
            reachedRoot = true;
            backtrack = false;
          } else {
            const parentType = cursor.nodeType;
            if (AST_NESTING_NODES.has(parentType)) {
              currentNesting = Math.max(0, currentNesting - 1);
            }

            if (cursor.gotoNextSibling()) {
              backtrack = false;
            }
          }
        }
      }

      const routes = collectRoutes(file, spec);
      const frameworkHints = collectFrameworkFactsFromTokens(
        [...imports, file.path, ...symbols.map((symbol) => symbol.name)],
        file.path,
        78
      );

      return {
        analysisMode: "tree-sitter",
        apiSurface: Math.max(apiSurface, routes.length),
        complexityMetrics: {
          complexity,
          maxNesting,
        },
        confidence: CONFIDENCE_LEVELS.astStructure,
        entrypointHint: spec.entrypoints.some((re) => re.test(file.content)),
        exports,
        frameworkHints,
        imports: Array.from(imports),
        path: file.path,
        routes,
        source: "extraction" as const,
        symbols,
      };
    } finally {
      tree?.delete?.();
      parser?.delete?.();
    }
  } catch (error) {
    logger.error({
      error,
      ext,
      msg: "Tree-sitter unavailable; falling back to non-AST analysis",
      path: file.path,
    });
    return null;
  }
}

export async function getRuntime() {
  const { Parser } = await initRuntime();
  return Parser;
}

export function getSpecByExt(ext: string) {
  return SPECS[ext];
}

import { extname } from "pathe";
import ts from "typescript";

import type { TsStaticHint } from "../../types";
import { normalizeRepoPath } from "../core/common";
import { COMPLEXITY_SCORING } from "../core/scoring-constants";

const TS_LIKE = new Set([".cjs", ".cts", ".js", ".jsx", ".mjs", ".mts", ".ts", ".tsx"]);

type VisitContext = {
  hints: TsStaticHint[];
  normalizedPath: string;
  sourceFile: ts.SourceFile;
};

const visitNode = (node: ts.Node, context: VisitContext) => {
  const { hints, normalizedPath, sourceFile } = context;

  if (node.kind === ts.SyntaxKind.AnyKeyword) {
    const startPos = node.getStart();
    const { line } = sourceFile.getLineAndCharacterOfPosition(startPos);
    hints.push({
      detail: "Explicit `any` weakens type safety.",
      kind: "explicit-any",
      line: line + 1,
      path: normalizedPath,
    });
    return;
  }

  if (ts.isFunctionDeclaration(node) || ts.isFunctionExpression(node) || ts.isArrowFunction(node)) {
    const nodeStart = node.getStart();
    const nodeEnd = node.getEnd();

    const start = sourceFile.getLineAndCharacterOfPosition(nodeStart);
    const end = sourceFile.getLineAndCharacterOfPosition(nodeEnd);
    const lineSpan = end.line - start.line + 1;

    if (lineSpan >= COMPLEXITY_SCORING.lineCountThreshold) {
      hints.push({
        detail: `Function spans ~${lineSpan} lines (threshold ${COMPLEXITY_SCORING.lineCountThreshold}).`,
        kind: "long-function",
        line: start.line + 1,
        path: normalizedPath,
      });
    }

    const paramCount = node.parameters.length;
    if (paramCount >= COMPLEXITY_SCORING.paramCountThreshold) {
      hints.push({
        detail: `Function has ${paramCount} parameters (threshold ${COMPLEXITY_SCORING.paramCountThreshold}).`,
        kind: "many-params",
        line: start.line + 1,
        path: normalizedPath,
      });
    }
  }

  ts.forEachChild(node, (child) => visitNode(child, context));
};

function scriptKind(filePath: string): ts.ScriptKind {
  const lower = filePath.toLowerCase();
  if (lower.endsWith(".tsx")) return ts.ScriptKind.TSX;
  if (lower.endsWith(".jsx")) return ts.ScriptKind.JSX;
  if (lower.endsWith(".js") || lower.endsWith(".mjs") || lower.endsWith(".cjs")) {
    return ts.ScriptKind.JS;
  }
  if (lower.endsWith(".cts") || lower.endsWith(".mts")) {
    return ts.ScriptKind.TS;
  }
  return ts.ScriptKind.TS;
}

export function collectTypeScriptStaticHints(
  files: { content: string; path: string }[]
): TsStaticHint[] {
  const hints: TsStaticHint[] = [];

  for (const file of files) {
    const normalized = normalizeRepoPath(file.path);
    const ext = extname(normalized).toLowerCase();
    if (!TS_LIKE.has(ext)) continue;

    let sourceFile: ts.SourceFile;
    try {
      sourceFile = ts.createSourceFile(
        normalized,
        file.content,
        ts.ScriptTarget.Latest,
        false,
        scriptKind(normalized)
      );

      visitNode(sourceFile, { hints, normalizedPath: normalized, sourceFile });
    } catch {
      continue;
    }
  }

  return hints;
}

import ts from "typescript";

import type {
  EntrypointRef,
  FileSignals,
  FrameworkFact,
  RepositoryFile,
  RouteRef,
  SymbolKind,
  SymbolRef,
} from "../core/discovery.types";
import { collectFrameworkFactsFromTokens } from "../core/framework-catalog";
import { CONFIDENCE_LEVELS } from "../core/scoring-constants";

const CONTROL_FLOW_KINDS = new Set([
  ts.SyntaxKind.CaseClause,
  ts.SyntaxKind.CatchClause,
  ts.SyntaxKind.ConditionalExpression,
  ts.SyntaxKind.DoStatement,
  ts.SyntaxKind.ForInStatement,
  ts.SyntaxKind.ForOfStatement,
  ts.SyntaxKind.ForStatement,
  ts.SyntaxKind.IfStatement,
  ts.SyntaxKind.SwitchStatement,
  ts.SyntaxKind.WhileStatement,
]);

const INCREASES_NESTING_KINDS = new Set([
  ts.SyntaxKind.CatchClause,
  ts.SyntaxKind.DoStatement,
  ts.SyntaxKind.ForInStatement,
  ts.SyntaxKind.ForOfStatement,
  ts.SyntaxKind.ForStatement,
  ts.SyntaxKind.IfStatement,
  ts.SyntaxKind.SwitchStatement,
  ts.SyntaxKind.WhileStatement,
]);

function getScriptKind(filePath: string): ts.ScriptKind {
  if (filePath.endsWith(".tsx")) return ts.ScriptKind.TSX;
  if (filePath.endsWith(".jsx")) return ts.ScriptKind.JSX;
  if (filePath.endsWith(".js") || filePath.endsWith(".mjs") || filePath.endsWith(".cjs")) {
    return ts.ScriptKind.JS;
  }
  return ts.ScriptKind.TS;
}

function hasExportModifier(modifiers: ts.NodeArray<ts.ModifierLike> | undefined): boolean {
  return modifiers?.some((modifier) => modifier.kind === ts.SyntaxKind.ExportKeyword) ?? false;
}

const HTTP_METHODS = new Set(["delete", "get", "head", "options", "patch", "post", "put"]);

function getNodeLine(sourceFile: ts.SourceFile, node: ts.Node): number {
  return sourceFile.getLineAndCharacterOfPosition(node.getStart(sourceFile)).line + 1;
}

function nodeName(node: ts.Node): string | undefined {
  const namedNode = "name" in node ? (node as ts.Node & { name?: ts.Node }) : undefined;
  return namedNode?.name != null && ts.isIdentifier(namedNode.name)
    ? namedNode.name.text
    : undefined;
}

function pushSymbol(
  symbols: SymbolRef[],
  sourceFile: ts.SourceFile,
  node: ts.Node,
  kind: SymbolKind,
  exported: boolean,
  fallbackName?: string
) {
  const name = fallbackName ?? nodeName(node);
  if (name == null || name.length === 0) return;

  symbols.push({
    confidence: exported ? CONFIDENCE_LEVELS.tsCompiler : 75,
    exported,
    kind,
    line: getNodeLine(sourceFile, node),
    name,
    path: sourceFile.fileName,
  });
}

function literalPath(argument: ts.Expression | undefined): string | undefined {
  return argument != null &&
    (ts.isStringLiteral(argument) || ts.isNoSubstitutionTemplateLiteral(argument))
    ? argument.text
    : undefined;
}

function collectCallRoute(
  node: ts.CallExpression,
  sourceFile: ts.SourceFile,
  routes: RouteRef[],
  frameworkHints: FrameworkFact[]
) {
  if (!ts.isPropertyAccessExpression(node.expression)) return;

  const methodName = node.expression.name.text;
  const normalizedMethod = methodName.toLowerCase();
  const path = literalPath(node.arguments[0]);
  const receiver = node.expression.expression.getText(sourceFile);

  if (HTTP_METHODS.has(normalizedMethod) && path != null) {
    routes.push({
      confidence: CONFIDENCE_LEVELS.tsInferred,
      framework: frameworkHints[0]?.name,
      kind: "http",
      line: getNodeLine(sourceFile, node),
      method: normalizedMethod.toUpperCase(),
      path,
      sourcePath: sourceFile.fileName,
    });
    return;
  }

  if (methodName === "route" && path != null) {
    routes.push({
      confidence: 72,
      framework:
        frameworkHints[0]?.name ?? (receiver.toLowerCase().includes("hono") ? "Hono" : undefined),
      kind: "http",
      line: getNodeLine(sourceFile, node),
      method: "ROUTE",
      path,
      sourcePath: sourceFile.fileName,
    });
  }
}

/**
 * Единый сборщик сигналов и сложности TypeScript файлов.
 * Строит AST-дерево и обходит его строго ОДИН РАЗ, снижая нагрузку на память на 50%.
 */
export function collectTypeScriptSignals(file: RepositoryFile): FileSignals {
  const sourceFile = ts.createSourceFile(
    file.path,
    file.content,
    ts.ScriptTarget.Latest,
    true,
    getScriptKind(file.path)
  );

  // dumpDebug(`ast-ts-${path.basename(file.path)}`, {
  //   path: file.path,
  //   kind: "TypeScript-Native-AST",
  //   nodes: sourceFile.statements.map(s => ({
  //     kind: ts.SyntaxKind[s.kind],
  //     name: (s as any).name?.escapedText || "anonymous",
  //     pos: s.pos,
  //     end: s.end
  //   }))
  // });

  const imports: string[] = [];
  let apiSurface = 0;
  let exports = 0;
  const symbols: SymbolRef[] = [];
  const routes: RouteRef[] = [];
  const frameworkTokens = new Set<string>();

  let complexity = 0;
  let maxNesting = 0;

  const visit = (node: ts.Node, nesting: number = 0) => {
    if (CONTROL_FLOW_KINDS.has(node.kind)) {
      complexity += 1 + nesting;
      maxNesting = Math.max(maxNesting, nesting);
    }
    const nextNesting = nesting + (INCREASES_NESTING_KINDS.has(node.kind) ? 1 : 0);

    if (ts.isImportDeclaration(node) && ts.isStringLiteral(node.moduleSpecifier)) {
      imports.push(node.moduleSpecifier.text);
      frameworkTokens.add(node.moduleSpecifier.text);
    }

    if (
      ts.isExportDeclaration(node) &&
      node.moduleSpecifier &&
      ts.isStringLiteral(node.moduleSpecifier)
    ) {
      imports.push(node.moduleSpecifier.text);
      exports += node.exportClause != null ? 1 : 0;
    }

    if (ts.isExportAssignment(node)) {
      exports += 1;
      pushSymbol(symbols, sourceFile, node, "module", true, "default");
    }

    // 3. ОПРЕДЕЛЕНИЕ СИМВОЛОВ (Классы, методы, функции, типы)
    if (
      (ts.isFunctionDeclaration(node) ||
        ts.isClassDeclaration(node) ||
        ts.isInterfaceDeclaration(node) ||
        ts.isTypeAliasDeclaration(node) ||
        ts.isEnumDeclaration(node)) &&
      hasExportModifier(node.modifiers)
    ) {
      exports += 1;
      const kind = ts.isFunctionDeclaration(node)
        ? "function"
        : ts.isClassDeclaration(node)
          ? "class"
          : ts.isInterfaceDeclaration(node)
            ? "interface"
            : ts.isTypeAliasDeclaration(node)
              ? "type"
              : "enum";
      pushSymbol(symbols, sourceFile, node, kind, true);
    }

    if (ts.isVariableStatement(node) && hasExportModifier(node.modifiers)) {
      exports += node.declarationList.declarations.length;
      for (const declaration of node.declarationList.declarations) {
        if (ts.isIdentifier(declaration.name)) {
          pushSymbol(symbols, sourceFile, declaration, "variable", true, declaration.name.text);
        }
      }
    }

    if (ts.isFunctionDeclaration(node)) {
      pushSymbol(symbols, sourceFile, node, "function", hasExportModifier(node.modifiers));
    }

    if (ts.isClassDeclaration(node)) {
      pushSymbol(symbols, sourceFile, node, "class", hasExportModifier(node.modifiers));
    }

    if (ts.isInterfaceDeclaration(node)) {
      pushSymbol(symbols, sourceFile, node, "interface", hasExportModifier(node.modifiers));
    }

    if (ts.isTypeAliasDeclaration(node)) {
      pushSymbol(symbols, sourceFile, node, "type", hasExportModifier(node.modifiers));
    }

    if (ts.isEnumDeclaration(node)) {
      pushSymbol(symbols, sourceFile, node, "enum", hasExportModifier(node.modifiers));
    }

    if (ts.isMethodDeclaration(node)) {
      pushSymbol(symbols, sourceFile, node, "method", false);
    }

    if (ts.isCallExpression(node)) {
      const frameworkHints = collectFrameworkFactsFromTokens(frameworkTokens, file.path, 90);
      collectCallRoute(node, sourceFile, routes, frameworkHints);
    }

    ts.forEachChild(node, (child) => visit(child, nextNesting));
  };

  visit(sourceFile, 0);

  [
    /\bnew\s+Hono\s*\(/,
    /\bexpress\s*\(/,
    /\bfastify\s*\(/,
    /\bNestFactory\.create\b/,
    /\bcreateTRPCRouter\b/,
    /\brouter\.(get|post|put|patch|delete)\b/gi,
  ].forEach((pattern) => {
    if (pattern.test(file.content)) frameworkTokens.add(pattern.source);
  });

  const frameworkHints = collectFrameworkFactsFromTokens(
    [...imports, ...Array.from(frameworkTokens)],
    file.path,
    90
  );

  apiSurface += (
    file.content.match(/\b(publicProcedure|protectedProcedure|adminProcedure)\b/g) ?? []
  ).length;
  apiSurface += (file.content.match(/\b(GET|POST|PUT|PATCH|DELETE)\b\s*[(:=]/g) ?? []).length;

  const entrypointRefs: EntrypointRef[] = [];
  const entrypointHint =
    /\bcreateServer\b|\bNestFactory\.create\b|\bnew Hono\b|\bexpress\(|\bif\s*\(\s*require\.main\s*===\s*module\s*\)|\bserve\(/.test(
      file.content
    );

  if (entrypointHint) {
    entrypointRefs.push({
      confidence: 78,
      kind: "runtime",
      path: file.path,
      reason: "runtime bootstrap pattern detected in TypeScript/JavaScript source",
    });
  }

  if (exports > 0 && /\/index\.[cm]?[jt]sx?$/i.test(file.path)) {
    entrypointRefs.push({
      confidence: 66,
      kind: "library",
      path: file.path,
      reason: "exporting index file suggests package public surface",
    });
  }

  return {
    analysisMode: "typescript-ast",
    apiSurface,
    complexityMetrics: {
      complexity,
      maxNesting,
    },
    confidence: CONFIDENCE_LEVELS.tsCompiler,
    entrypointHint,
    entrypointRefs,
    exports,
    frameworkHints,
    imports,
    path: file.path,
    routes,
    source: "extraction" as const,
    symbols,
  };
}

import { mean } from "es-toolkit";

import { percentile } from "../../lib/math-utils";
import { clamp } from "../core/common";
import type { RepoMetrics } from "../core/metrics.types";
import { COMPLEXITY_SCORING, TECH_DEBT_SCORING } from "../core/scoring-constants";

export function normalizeComplexityScore(params: {
  cycles: number;
  fileCount: number;
  maxNesting: number;
  scores: number[];
}): number {
  if (params.scores.length === 0 || params.fileCount === 0) {
    return 100;
  }

  const average = mean(params.scores);

  const p85 = percentile(params.scores, COMPLEXITY_SCORING.percentileThreshold);
  const highComplexityThreshold = Math.max(COMPLEXITY_SCORING.minComplexityThreshold, p85);
  const highComplexityFiles = params.scores.filter(
    (score) => score >= highComplexityThreshold
  ).length;

  const hotspotRatio = highComplexityFiles / params.fileCount;

  const averagePenalty = clamp(
    average * COMPLEXITY_SCORING.averageComplexityMultiplier,
    0,
    COMPLEXITY_SCORING.averagePenaltyMax
  );
  const nestingPenalty = clamp(
    params.maxNesting * COMPLEXITY_SCORING.nestingDepthMultiplier,
    0,
    COMPLEXITY_SCORING.maxNestingPenaltyMax
  );
  const cyclePenalty = clamp(
    params.cycles * COMPLEXITY_SCORING.cycleMultiplier,
    0,
    COMPLEXITY_SCORING.cyclePenaltyMax
  );
  const hotspotPenalty = clamp(
    hotspotRatio * COMPLEXITY_SCORING.hotspotRatioMultiplier,
    0,
    COMPLEXITY_SCORING.hotspotRatioPenaltyMax
  );

  return clamp(
    Math.round(100 - averagePenalty - nestingPenalty - cyclePenalty - hotspotPenalty),
    0,
    100
  );
}

export function normalizeTechDebtScore(params: {
  dependencyCycles: number;
  duplicationPercentage: number;
  fileCount: number;
  orphanModules: number;
  todos: number;
}): number {
  if (params.fileCount === 0) {
    return 100;
  }

  const todoDensity = params.todos / params.fileCount;
  const orphanRatio = params.orphanModules / params.fileCount;

  const todoPenalty = clamp(
    todoDensity * TECH_DEBT_SCORING.todoDensityMultiplier,
    0,
    TECH_DEBT_SCORING.todoPenaltyMax
  );
  const duplicationPenalty = clamp(
    params.duplicationPercentage * TECH_DEBT_SCORING.duplicationMultiplier,
    0,
    TECH_DEBT_SCORING.duplicationPenaltyMax
  );
  const cyclePenalty = clamp(
    params.dependencyCycles * TECH_DEBT_SCORING.cycleMultiplier,
    0,
    TECH_DEBT_SCORING.cyclePenaltyMax
  );
  const orphanPenalty = clamp(
    orphanRatio * TECH_DEBT_SCORING.orphanRatioMultiplier,
    0,
    TECH_DEBT_SCORING.orphanPenaltyMax
  );

  return clamp(
    Math.round(100 - todoPenalty - duplicationPenalty - cyclePenalty - orphanPenalty),
    0,
    100
  );
}

export function mergeRouteInventories(
  extracted: RepoMetrics["routeInventory"] | undefined,
  openapiInventory: RepoMetrics["openapiInventory"]
): NonNullable<RepoMetrics["routeInventory"]> {
  const extractedInventory =
    extracted ??
    ({
      estimatedOperations: 0,
      frameworks: [],
      httpRoutes: [],
      rpcProcedures: 0,
      source: "extracted",
      sourceFiles: [],
    } satisfies NonNullable<RepoMetrics["routeInventory"]>);

  if (openapiInventory == null || openapiInventory.sourceFiles.length === 0) {
    return extractedInventory;
  }

  const combinedFrameworks = Array.from(new Set([...extractedInventory.frameworks, "OpenAPI"]));

  let finalSource: "extracted" | "mixed" | "openapi" = "openapi";
  if (extractedInventory.estimatedOperations > 0 && openapiInventory.estimatedOperations > 0) {
    finalSource = "mixed";
  } else if (extractedInventory.estimatedOperations > 0) {
    finalSource = "extracted";
  }

  return {
    estimatedOperations: Math.max(
      extractedInventory.estimatedOperations,
      openapiInventory.estimatedOperations
    ),
    frameworks: combinedFrameworks,
    httpRoutes: extractedInventory.httpRoutes,
    rpcProcedures: extractedInventory.rpcProcedures,
    source: finalSource,
    sourceFiles: Array.from(
      new Set([...extractedInventory.sourceFiles, ...openapiInventory.sourceFiles])
    ).sort((a, b) => a.localeCompare(b)),
  };
}

import { maxBy, sumBy } from "es-toolkit";

import { getLanguageColor } from "../../lib/language-metadata";
import { percentile } from "../../lib/math-utils";
import type { FileSignals, LanguageMetric } from "../core/discovery.types";
import type { RepoMetrics } from "../core/metrics.types";
import { ProjectPolicy } from "../core/project-policy";
import { COMPLEXITY_SCORING, SCHEMA_LIMITS } from "../core/scoring-constants";

export type FileScanResult = {
  comments: number;
  complexity: number;
  maxNesting: number;
  normalizedPath: string;
  prettyName: string;
  securityFindings: RepoMetrics["securityFindings"];
  securityIssues: number;
  securityScanStatus: "ok" | "partial";
  signal: FileSignals;
  size: number;
  source: number;
  todos: number;
};

export type ScanAggregation = {
  analysisCoverage: RepoMetrics["analysisCoverage"];
  fileComplexities: Array<{ path: string; score: number }>;
  fileSignalsByPath: Map<string, FileSignals>;
  languages: LanguageMetric[];
  mostComplexFiles: string[];
  securityFindings: RepoMetrics["securityFindings"];
  securityScanStatus: RepoMetrics["securityScanStatus"];
  totals: {
    comments: number;
    maxNesting: number;
    securityIssues: number;
    size: number;
    source: number;
    todos: number;
  };
};

function buildAnalysisCoverage(
  results: FileScanResult[],
  totalFiles: number
): RepoMetrics["analysisCoverage"] {
  const languagesByMode = {
    heuristic: new Set<string>(),
    treeSitter: new Set<string>(),
    typeScriptAst: new Set<string>(),
  };

  let typeScriptAstFiles = 0;
  let treeSitterFiles = 0;

  for (const result of results) {
    const mode = result.signal.analysisMode;
    if (mode === "typescript-ast") {
      languagesByMode.typeScriptAst.add(result.prettyName);
      typeScriptAstFiles++;
    } else if (mode === "tree-sitter") {
      languagesByMode.treeSitter.add(result.prettyName);
      treeSitterFiles++;
    } else {
      languagesByMode.heuristic.add(result.prettyName);
    }
  }

  const heuristicFiles = Math.max(0, totalFiles - typeScriptAstFiles - treeSitterFiles);

  return {
    heuristicFiles,
    languagesByMode: {
      heuristic: Array.from(languagesByMode.heuristic).sort((left, right) =>
        left.localeCompare(right)
      ),
      treeSitter: Array.from(languagesByMode.treeSitter).sort((left, right) =>
        left.localeCompare(right)
      ),
      typeScriptAst: Array.from(languagesByMode.typeScriptAst).sort((left, right) =>
        left.localeCompare(right)
      ),
    },
    parserCoveragePercent:
      totalFiles === 0
        ? 0
        : Math.round(((typeScriptAstFiles + treeSitterFiles) / totalFiles) * 100),
    totalFiles,
    treeSitterFiles,
    typeScriptAstFiles,
  };
}

export function aggregateScanResults(results: FileScanResult[]): ScanAggregation {
  const fileComplexities = results.map((result) => ({
    path: result.normalizedPath,
    score: result.complexity,
  }));

  const langStats = results.reduce<Record<string, number>>((acc, result) => {
    acc[result.prettyName] = (acc[result.prettyName] ?? 0) + result.source;
    return acc;
  }, {});

  const rankedComplexities = fileComplexities.toSorted((left, right) => right.score - left.score);

  const usefulScores = rankedComplexities
    .filter((item) => ProjectPolicy.isUsefulComplexityCandidate(item.path))
    .map((item) => item.score);

  const rawPercentile = percentile(usefulScores, COMPLEXITY_SCORING.percentileThreshold);
  const focusedThreshold = Math.max(8, rawPercentile);

  const focusedComplexFiles = rankedComplexities
    .filter((item) => item.score >= focusedThreshold)
    .map((item) => item.path)
    .filter((path) => ProjectPolicy.isUsefulComplexityCandidate(path));

  const fallbackComplexFiles = rankedComplexities
    .map((item) => item.path)
    .filter((path) => ProjectPolicy.isUsefulComplexityCandidate(path));

  const mostComplexFiles = (
    focusedComplexFiles.length > 0 ? focusedComplexFiles : fallbackComplexFiles
  ).slice(0, SCHEMA_LIMITS.maxFilesToSkeletonize);

  const totals = {
    comments: sumBy(results, (r) => r.comments),
    maxNesting: maxBy(results, (r) => r.maxNesting)?.maxNesting ?? 0,
    securityIssues: sumBy(results, (r) => r.securityIssues),
    size: sumBy(results, (r) => r.size),
    source: sumBy(results, (r) => r.source),
    todos: sumBy(results, (r) => r.todos),
  };

  return {
    analysisCoverage: buildAnalysisCoverage(results, results.length),
    fileComplexities,
    fileSignalsByPath: new Map(results.map((result) => [result.normalizedPath, result.signal])),
    languages: Object.entries(langStats)
      .map(([name, lines]) => ({
        color: getLanguageColor(name) || "#cccccc",
        lines,
        name,
      }))
      .sort((left, right) => right.lines - left.lines),
    mostComplexFiles,
    securityFindings: results.flatMap((result) => result.securityFindings),
    securityScanStatus: results.some((result) => result.securityScanStatus === "partial")
      ? "partial"
      : "ok",
    totals,
  };
}

