import { AsyncLocalStorage } from "node:async_hooks";
import type { NextRequest } from "next/server";
import ipaddr from "ipaddr.js";

import { IS_PROD } from "@/shared/constants/env.flags";

type RequestStore = {
  appVersion?: string;
  ip: null | string;
  method: string;

  origin?: string;
  path: string;
  referer?: string;
  requestId: string;

  userAgent: string;
  userId?: number;

  userRole?: string;
};

export const requestContext = new AsyncLocalStorage<RequestStore>();

/**
 * Анонимизирует IP-адрес для соответствия GDPR и записи в тип INET PostgreSQL.
 * IPv4: зануляет последний октет (1.2.3.4 -> 1.2.3.0)
 * IPv6: зануляет последние 64 бита (2001:db8:85a3:0:0:8a2e:370:7334 -> 2001:db8:85a3:0::)
 */
export function anonymizeIp(ip: null | string | undefined): null | string {
  if (ip == null || ip === "unknown" || ip.trim() === "") return null;

  if (ip === "127.0.0.1" || ip === "::1") return ip;

  try {
    const addr = ipaddr.process(ip);
    const kind = addr.kind();

    if (kind === "ipv4") {
      const ipv4 = addr as ipaddr.IPv4;
      const octets = ipv4.toByteArray();
      octets[3] = 0;
      return ipaddr.fromByteArray(octets).toString();
    }

    const ipv6 = addr as ipaddr.IPv6;
    const parts = [...ipv6.parts];

    parts[4] = 0;
    parts[5] = 0;
    parts[6] = 0;
    parts[7] = 0;

    return new ipaddr.IPv6(parts).toNormalizedString();
  } catch {
    return null;
  }
}

type VercelNextRequest = NextRequest & {
  geo?: {
    city?: string;
    country?: string;
    region?: string;
  };
  ip?: string;
};

export function getIp(request: NextRequest): string {
  return (
    (request as VercelNextRequest).ip ??
    request.headers.get("x-forwarded-for")?.split(",")[0] ??
    "127.0.0.1"
  );
}

export function getUa(request: NextRequest): string {
  return request.headers.get("user-agent") ?? "unknown";
}

export function getCountry(request: NextRequest): string {
  const geoCountry = (request as VercelNextRequest).geo?.country;
  if (geoCountry != null) return geoCountry;

  const vercelHeader = request.headers.get("x-vercel-ip-country");
  if (vercelHeader != null) return vercelHeader.toUpperCase();

  if (!IS_PROD) return "LOCAL";

  return "UNKNOWN";
}

type RequestContextInput = {
  method: string;
  path: string;
  req: NextRequest;
  requestId?: string;
  userId?: number;
  userRole?: string;
};

function getRequestIdFromHeaders(request: NextRequest): string | undefined {
  return sanitizeRequestId(request.headers.get("x-request-id"));
}

export function generateRequestId(): string {
  if (typeof globalThis.crypto.randomUUID === "function") {
    return globalThis.crypto.randomUUID();
  }
  throw new Error("crypto.randomUUID is not available in this runtime");
}

export function sanitizeRequestId(value?: null | string): string | undefined {
  if (value == null) return undefined;
  const trimmed = value.trim();
  if (trimmed.length === 0 || trimmed.length > 64) return undefined;
  if (!/^[\w-]+$/.test(trimmed)) return undefined;
  return trimmed;
}

export function resolveRequestId(request?: NextRequest, existing?: string): string | undefined {
  if (existing != null) return sanitizeRequestId(existing);
  if (request == null) return undefined;
  return getRequestIdFromHeaders(request);
}

function ensureRequestId(request: NextRequest, existing?: string): string {
  return sanitizeRequestId(existing) ?? getRequestIdFromHeaders(request) ?? generateRequestId();
}

export function buildRequestStore(input: RequestContextInput): RequestStore {
  const requestId = ensureRequestId(input.req, input.requestId);
  return {
    ip: anonymizeIp(getIp(input.req)),
    method: input.method,
    origin: input.req.headers.get("origin") ?? undefined,
    path: input.path,
    referer: input.req.headers.get("referer") ?? undefined,
    requestId,
    userAgent: getUa(input.req),
    userId: input.userId,
    userRole: input.userRole,
  };
}

/**
 * SafetyContext
 * Unified safety settings and data handling rules for LLM interactions.
 * Centralizes escaping, sanitization, and validation logic.
 */

import { logger } from "../infrastructure/logger";
import { escapePromptXmlAttr, escapePromptXmlText } from "./string-utils";

/**
 * Safety level for handling user input
 */
type SafetyLevel = "moderate" | "permissive" | "strict";

/**
 * Data handling strategy
 */
type DataHandlingStrategy = "escape-json" | "escape-xml" | "no-escape" | "sanitize-html";

/**
 * SafetyContext manages all data safety and escaping across LLM prompts
 */
export class SafetyContext {
  private level: SafetyLevel = "strict";
  private strategies: Map<string, DataHandlingStrategy> = new Map();

  constructor(level: SafetyLevel = "strict") {
    this.level = level;
    this.setupDefaultStrategies();
  }

  /**
   * Setup default escaping strategies per data type
   */
  private setupDefaultStrategies(): void {
    this.strategies.set("xml", "escape-xml");
    this.strategies.set("json", "escape-json");
    this.strategies.set("html", "sanitize-html");
    this.strategies.set("code", "no-escape");
  }

  /**
   * Set safety level
   */
  setSafetyLevel(level: SafetyLevel): this {
    this.level = level;
    return this;
  }

  /**
   * Register custom handling strategy for a data type
   */
  registerStrategy(dataType: string, strategy: DataHandlingStrategy): this {
    this.strategies.set(dataType, strategy);
    return this;
  }

  /**
   * Escape data based on context type
   */
  escape(data: string, context: "json" | "xml-attr" | "xml-text" = "xml-text"): string {
    if (this.level === "permissive") {
      return data;
    }

    switch (context) {
      case "xml-text": {
        return escapePromptXmlText(data);
      }
      case "xml-attr": {
        return escapePromptXmlAttr(data);
      }
      case "json": {
        return JSON.stringify(data);
      }
      default: {
        return data;
      }
    }
  }

  /**
   * Sanitize user input that will be embedded in prompts
   */
  sanitizeUserInput(input: string): string {
    if (this.level === "strict") {
      // Remove or reject potentially dangerous patterns
      const dangerous = [
        /prompt\s*injection/i,
        /system\s*prompt/i,
        /ignore.*instructions/i,
        /bypass/i,
        /jailbreak/i,
      ];

      for (const pattern of dangerous) {
        if (pattern.test(input)) {
          logger.warn({
            msg: "Potentially dangerous input pattern detected",
            pattern: pattern.toString(),
          });
          // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
          if (this.level === "strict") {
            throw new Error("Input contains potentially dangerous patterns");
          }
        }
      }
    }

    return this.escape(input, "xml-text");
  }

  /**
   * Prepare JSON for embedding in prompts
   */
  prepareJsonForPrompt(data: object, escape = true): string {
    const json = JSON.stringify(data, null, 2);
    return escape ? this.escape(json, "xml-text") : json;
  }

  /**
   * Prepare file content for embedding in prompts
   */
  prepareFileContent(
    filePath: string,
    content: string,
    maxLength = 50_000,
    escapeContext: "xml-attr" | "xml-text" = "xml-text"
  ): { content: string; path: string; truncated: boolean } {
    let truncated = false;
    let processedContent = content;

    if (content.length > maxLength) {
      processedContent = content.slice(0, maxLength) + "\n// [CONTENT TRUNCATED]";
      truncated = true;
    }

    return {
      content: this.escape(processedContent, escapeContext),
      path: this.escape(filePath, "xml-attr"),
      truncated,
    };
  }

  /**
   * Validate repository paths
   */
  validatePaths(
    paths: string[],
    allowedPaths?: Set<string>
  ): { invalid: string[]; valid: string[] } {
    if (!allowedPaths || allowedPaths.size === 0) {
      // If no restrictions, all paths are valid
      return { invalid: [], valid: paths };
    }

    const valid: string[] = [];
    const invalid: string[] = [];

    for (const path of paths) {
      if (allowedPaths.has(path)) {
        valid.push(path);
      } else {
        invalid.push(path);
      }
    }

    return { invalid, valid };
  }

  /**
   * Prepare allowed paths list for inclusion in prompts
   */
  prepareAllowedPaths(paths: string[]): string {
    const safe = paths.map((p) => this.escape(p, "xml-text"));
    return safe.join("\n");
  }

  /**
   * Create a safety-checked evidence block
   */
  createEvidenceBlock(
    tag: string,
    data: object,
    {
      allowedPaths,
      maxSize = 100_000,
      validatePaths = false,
    }: { allowedPaths?: Set<string>; maxSize?: number; validatePaths?: boolean } = {}
  ): { invalidPaths: string[]; truncated: boolean; xml: string } {
    const json = JSON.stringify(data, null, 2);
    let truncated = false;
    let content = json;
    let invalidPaths: string[] = [];

    // Check size
    if (content.length > maxSize) {
      content = content.slice(0, maxSize) + "\n// [DATA TRUNCATED]";
      truncated = true;
    }

    // Validate paths if requested
    if (validatePaths && "paths" in data && Array.isArray((data as { paths: unknown }).paths)) {
      const pathsData = (data as { paths: string[] }).paths;
      const validation = this.validatePaths(pathsData, allowedPaths);
      invalidPaths = validation.invalid;
    }

    const escaped = this.escape(content, "xml-text");
    return {
      invalidPaths,
      truncated,
      xml: `<${tag}>\n${escaped}\n</${tag}>`,
    };
  }

  /**
   * Get a safety report for an evidence block
   */
  generateSafetyReport(data: {
    maxDataSize?: number;
    pathsValidated?: number;
    userInputPresent?: boolean;
    xmlTags?: number;
  }): string {
    const report: string[] = [];
    if (data.xmlTags != null) report.push(`✓ XML tags properly escaped: ${data.xmlTags}`);
    if (data.maxDataSize != null)
      report.push(`✓ Max data size enforced: ${data.maxDataSize} bytes`);
    if (data.userInputPresent === true) report.push(`⚠ User input present (sanitized)`);
    if (data.pathsValidated != null) report.push(`✓ Paths validated: ${data.pathsValidated}`);
    return report.join("\n");
  }
}

/**
 * Global safety context singleton
 */
let globalSafetyContext: null | SafetyContext = null;

/**
 * Get or create global safety context
 */
export function getGlobalSafetyContext(level: SafetyLevel = "strict"): SafetyContext {
  if (!globalSafetyContext) {
    globalSafetyContext = new SafetyContext(level);
  }
  return globalSafetyContext;
}

/**
 * Reset global safety context (for testing)
 */
export function resetGlobalSafetyContext(): void {
  globalSafetyContext = null;
}

import "server-only";

import safeStringify from "fast-safe-stringify";

const SENSITIVE_KEYS = new Set([
  "access_token",
  "apikey",
  "authorization",
  "cardnumber",
  "clientsecret",
  "cookie",
  "creditcard",
  "cvv",
  "cvv2",
  "gh_token",
  "hash",
  "hashedkey",
  "iban",
  "id_token",
  "identifier",
  "imagekey",
  "newpassword",
  "passphrase",
  "password",
  "passwordhash",
  "privatekey",
  "proxy-authorization",
  "refresh_token",
  "salt",
  "secret",
  "session_id",
  "session_state",
  "sessiontoken",
  "set-cookie",
  "sid",
  "signingkey",
  "state",
  "token",
  "verificationtoken",
  "x-github-token",
]);

const GITHUB_TOKEN_REGEX = /(github_pat_\w+|gh[oprsu]_\w{36,})/g;
const BEARER_TOKEN_REGEX = /(\bbearer\s+)[^\s,;]+/gi;

function redactValue(key: string, value: unknown): unknown {
  const lowerKey = key.toLowerCase();
  const normalizedKey = lowerKey.replaceAll(/[_-]/g, "");

  if (SENSITIVE_KEYS.has(lowerKey) || SENSITIVE_KEYS.has(normalizedKey)) {
    return "[REDACTED]";
  }

  if (typeof value === "bigint") {
    return value.toString();
  }

  if (typeof value === "string") {
    let safeString = value;
    if (safeString.includes("gh") || safeString.includes("github_pat_")) {
      safeString = safeString.replaceAll(GITHUB_TOKEN_REGEX, "[REDACTED_GH_TOKEN]");
    }
    if (/bearer\s+/i.test(safeString)) {
      safeString = safeString.replaceAll(BEARER_TOKEN_REGEX, "$1[REDACTED]");
    }
    return safeString;
  }

  return value;
}

export function sanitizePayload(obj: unknown): unknown {
  if (typeof obj === "string") return redactValue("", obj);
  if (typeof obj === "bigint") return obj.toString();
  if (obj == null || typeof obj !== "object") return obj;

  try {
    return JSON.parse(safeStringify(obj, redactValue));
  } catch (error) {
    return {
      _sanitization_error: true,
      error_name: error instanceof Error ? error.name : "UnknownError",
      reason: "Sanitization failed",
      type_was: typeof obj,
    };
  }
}

const SEARCH_TOKEN_PATTERN = /[\p{L}\p{N}\p{M}]+/gu;
const MAX_SEARCH_TERMS = 8;
const MIN_SEARCH_TERM_LENGTH = 2;

export function normalizeSearchInput(search?: string): string | undefined {
  const normalized = search?.trim().normalize("NFC").toLowerCase();
  return normalized != null && normalized.length > 0 ? normalized : undefined;
}

export function tokenizeSearchInput(search?: string): string[] {
  const normalizedSearch = normalizeSearchInput(search);
  if (normalizedSearch == null) return [];

  const matches = normalizedSearch.match(SEARCH_TOKEN_PATTERN) ?? [];
  const uniqueTerms = new Set<string>();

  for (const match of matches) {
    if (match.length < MIN_SEARCH_TERM_LENGTH) continue;

    uniqueTerms.add(match);
    if (uniqueTerms.size >= MAX_SEARCH_TERMS) break;
  }

  return [...uniqueTerms];
}

import { compact, escape, uniq } from "es-toolkit";
import { basename, extname, normalize } from "pathe";
import validator from "validator";

import { normalizeRepoPath } from "../engine/core/common";

/**
 * Type-safe guard for non-empty strings.
 */
export const hasText = (value: unknown): value is string =>
  typeof value === "string" && !validator.isEmpty(value, { ignore_whitespace: true });

/**
 * Check if empty/whitespace.
 */
export const isEmpty = (value: unknown): boolean =>
  typeof value !== "string" || validator.isEmpty(value, { ignore_whitespace: true });

/**
 * Escape XML text.
 */
export function escapePromptXmlText(value: string): string {
  return escape(value);
}

/**
 * Escape XML attr.
 */
export function escapePromptXmlAttr(value: string): string {
  return escape(value);
}

export function getFileExtension(filePath: string): string {
  const normalized = normalize(normalizeRepoPath(filePath));
  return extname(normalized);
}

export function getFileName(filePath: string): string {
  const normalized = normalize(normalizeRepoPath(filePath));
  return basename(normalized);
}

function uniqueNormalizedPaths(paths: Iterable<string>, limit?: number): string[] {
  const list = compact(Array.from(paths).map((p) => normalize(normalizeRepoPath(p))));
  const result = uniq(list);

  return limit != null ? result.slice(0, limit) : result;
}

export function uniqueObjectPaths<T extends { path: string }>(
  items: Iterable<T>,
  limit?: number
): string[] {
  return uniqueNormalizedPaths(
    Array.from(items).map((i) => i.path),
    limit
  );
}

export function uniqueStringPaths(
  paths: Iterable<false | null | string | undefined>,
  limit?: number
): string[] {
  const list = compact(Array.from(paths)).map((p) => normalize(p as string));
  const result = uniq(list);

  return limit != null ? result.slice(0, limit) : result;
}

export function excludePath(
  paths: Iterable<string>,
  excludedPath: string,
  limit?: number
): string[] {
  const normalizedExcluded = normalize(normalizeRepoPath(excludedPath));

  const filtered = Array.from(paths).filter(
    (p) => normalize(normalizeRepoPath(p)) !== normalizedExcluded
  );

  return uniqueNormalizedPaths(filtered, limit);
}

import { Status } from "@prisma/client";
import { metadata } from "@trigger.dev/sdk/v3";

import { prisma } from "../infrastructure/db";
import { logger as internalLogger } from "../infrastructure/logger";
import { TRIGGER_CONFIG } from "./trigger";

export type LogLevel = "info" | "warn" | "error" | "success";

/**
 * Утилита для управления прогрессом и логами таска.
 * Разделяет real-time поток (metadata) и вечное хранение (DB).
 */
export const taskLogger = {
  /**
   * Хелперы для разных уровней логов
   */
  info(msg: string) { this.log(msg, "info"); },
  warn(msg: string) { this.log(msg, "warn"); },
  error(msg: string) { this.log(msg, "error"); },
  success(msg: string) { this.log(msg, "success"); },

  /**
   * Финальный синк. Вызывается один раз в конце.
   * Собирает ВСЕ логи из метаданных и кладет в БД на вечное хранение.
   */
  async finalize(analysisId: string, status: Status = Status.DONE) {
    const currentMetadata = metadata.current();

    const rawLogs = currentMetadata?.[TRIGGER_CONFIG.metadataKeys.taskLogs];
    const allLogs = Array.isArray(rawLogs) ? rawLogs.join("\n") : "";

    await prisma.analysis.update({
      data: {
        logs: allLogs,
        progress: 100,
        status,
      },
      where: { publicId: analysisId },
    });

    if (status === Status.DONE) {
      this.success(`Analysis finalized with status: ${status}`);
    } else {
      this.error(`Analysis finalized with status: ${status}`);
    }
  },

  /**
   * Гранулярный лог. Только для real-time отображения.
   * Формат строки: "level:::timestamp:::message"
   */
  log(msg: string, level: LogLevel = "info") {
    const timestamp = new Date().toLocaleTimeString();
    const line = `${level}:::${timestamp}:::${msg}`;

    internalLogger.info({ msg: `[${level.toUpperCase()}] [${timestamp}] ${msg}` });

    metadata.append(TRIGGER_CONFIG.metadataKeys.taskLogs, line);
  },

  /**
   * Обновление статуса этапа.
   * Пишет в метаданные И в базу данных (так как это важная точка).
   */
  async milestone(params: { analysisId: string; msg: string; percent: number; status?: Status }) {
    const { analysisId, msg, percent, status = Status.PENDING } = params;

    this.info(`STAGE: ${msg} (${percent}%)`);

    metadata.set(TRIGGER_CONFIG.metadataKeys.statusMessage, msg);
    metadata.set(TRIGGER_CONFIG.metadataKeys.progress, percent);

    await prisma.analysis.update({
      data: {
        message: msg,
        progress: percent,
        status,
      },
      where: { publicId: analysisId },
    });
  },
};

import { getEncoding } from "js-tiktoken";

import { logger } from "../infrastructure/logger";
import { hasText } from "./string-utils";

const encoding = getEncoding("o200k_base");

export async function countTokens(text: string): Promise<number> {
  if (!hasText(text)) return 0;

  try {
    const baseCount = encoding.encode(text).length;

    const safetyFactor = 1.2;

    return Math.ceil(baseCount * safetyFactor);
  } catch (error) {
    logger.error({ error, msg: "Tokenization failed, using fallback:" });
    return Math.ceil(text.length / 3);
  }
}

/**
 * Централизованный конфиг для Trigger.dev.
 */
export const TRIGGER_CONFIG = {
  metadataKeys: {
    progress: "progress",
    statusMessage: "status_message",
    taskLogs: "task_logs",
  },

} as const;

export type TriggerMetadataKey = typeof TRIGGER_CONFIG.metadataKeys[keyof typeof TRIGGER_CONFIG.metadataKeys];

import { UAParser } from "ua-parser-js";

export const formatUserAgent = (uaString: null | string): string => {
  if (uaString == null || uaString === "internal") return "System";

  const parser = new UAParser(uaString);
  const { browser, cpu, device, os } = parser.getResult();

  const browserPart =
    browser.name != null ? `${browser.name} ${browser.major ?? ""}`.trim() : "Unknown Browser";

  const osPart = os.name != null ? `${os.name} ${os.version ?? ""}`.trim() : "Unknown OS";

  const deviceInfo = [];
  if (device.vendor != null) deviceInfo.push(device.vendor);
  if (device.model != null) deviceInfo.push(device.model);
  if (cpu.architecture != null) deviceInfo.push(cpu.architecture);

  const hardware = deviceInfo.length > 0 ? ` [${deviceInfo.join(" ")}]` : "";

  return `${browserPart} on ${osPart}${hardware}`;
};

import fs from "node:fs/promises";
import { compact } from "es-toolkit";
import fg from "fast-glob";
import { isBinaryFile } from "isbinaryfile";
import { join, normalize } from "pathe";

import { REALTIME_CONFIG } from "@/shared/constants/realtime";

import { ProjectPolicy } from "../engine/core/project-policy";
import { prisma } from "../infrastructure/db";
import { logger } from "../infrastructure/logger";
import { realtimeServer } from "../infrastructure/realtime";
import { taskLogger } from "./task-logger";

export async function handleError(
  error: unknown,
  analysisId: string,
  channelName: string,
  tempPath: string
) {
  const message = error instanceof Error ? error.message : "Unknown error";
  logger.error({
    analysisId,
    error: error instanceof Error ? { message: error.message, stack: error.stack } : String(error),
    msg: "TASK_ERROR",
  });

  await cleanup(tempPath);

  await prisma.analysis.update({
    data: {
      error: message,
      message: "Analysis failed",
      status: "FAILED",
    },
    where: { publicId: analysisId },
  });

  await realtimeServer.channels
    .get(channelName)
    .publish(REALTIME_CONFIG.events.user.analysisProgress, {
      analysisId,
      message,
      status: "FAILED",
    });
}

export async function cleanup(dirPath: string) {
  const path = normalize(dirPath);
  await fs.rm(path, { force: true, recursive: true });
}

export async function readAndFilterFiles(basePath: string, selectedFiles: string[]) {
  taskLogger.log(`Scanning directory for ${selectedFiles.length} patterns...`);

  const resolvedBase = await fs.realpath(basePath);

  const entries = await fg(selectedFiles, {
    absolute: false,
    cwd: resolvedBase,
    dot: true,
    followSymbolicLinks: false,
    onlyFiles: true,
  });

  if (entries.length === 0) {
    throw new Error("No valid files found to analyze in the specified path");
  }

  const filePromises = entries.map(async (filePath) => {
    taskLogger.log(`Reading: ${filePath}`);

    if (ProjectPolicy.isSensitive(filePath)) {
      taskLogger.log(`Skipping sensitive file: ${filePath}`);

      logger.warn({
        filePath,
        msg: "Skipping sensitive file from analysis context",
      });
      return null;
    }

    const fullPath = join(resolvedBase, filePath);
    const realFullPath = await fs.realpath(fullPath).catch(() => null);

    if (realFullPath == null || !realFullPath.startsWith(resolvedBase)) {
      logger.warn({
        filePath,
        msg: "Security: rejected path outside base directory",
      });
      return null;
    }

    try {
      const buffer = await fs.readFile(realFullPath);
      const isBinary = await isBinaryFile(buffer);

      if (isBinary) return null;

      return { content: buffer.toString("utf-8"), path: filePath };
    } catch (error) {
      logger.warn({
        error:
          error instanceof Error ? { message: error.message, stack: error.stack } : String(error),
        filePath,
        msg: "Failed to read file",
      });
      return null;
    }
  });

  const settledFiles = await Promise.all(filePromises);
  const validFiles = compact(settledFiles);

  if (validFiles.length === 0) throw new Error("No valid text files found to analyze");
  return validFiles;
}
